-- Poems batch 124
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('19022ca9-906d-44f4-aa0d-3a9f993a85a5','出遊歸鞍上口占','陸游','宋','宋诗','song-poetry','','[]','渺渺烟波飛槳去，迢迢桑野策驢還。',64,'全唐诗/poet.song.134000.json','["渺渺烟波飛槳去，迢迢桑野策驢還。", "寄懷楚水吳山外，得意唐詩晉帖間。", "每惜好春如我老，誰能長日伴人閑。", "世間自是無兼得，勛業元非造物慳。"]'),
('dabdffc9-1ff2-4616-9335-e2a43939fcf1','閑詠','陸游','宋','宋诗','song-poetry','','[]','本志常思退，前緣剩得閑。',48,'全唐诗/poet.song.134000.json','["本志常思退，前緣剩得閑。", "聽猿來剡縣，采藥上稽山。", "超絕風塵表，瑩然冰雪顔。", "向來香火地，五綴羽衣班。"]'),
('fc983b60-d1d8-4145-8d5b-2b389be84d38','雨','陸游','宋','宋诗','song-poetry','','[]','曉望橫斜映水亭，暮看飄灑溼簾旌。',64,'全唐诗/poet.song.134000.json','["曉望橫斜映水亭，暮看飄灑溼簾旌。", "不嫌平野蒼茫色，實厭空階點滴聲。", "上策莫如常熟睡，少安毋躁會當晴。", "且將穡事傳童稚，未插秧時正好耕。"]'),
('078c7d1c-4021-4059-a4c7-367b73ce893e','立夏','陸游','宋','宋诗','song-poetry','','[]','赤幟插城扉，東君整駕歸。',48,'全唐诗/poet.song.134000.json','["赤幟插城扉，東君整駕歸。", "泥新巢燕鬧，花盡蜜蜂稀。", "槐柳陰初密，簾櫳暑尚微。", "日斜湯沐罷，熟練試單衣。"]'),
('3be9a6e7-87f2-482b-bbba-3ca1912e5bd4','孤寂','陸游','宋','宋诗','song-poetry','','[]','晚境諸兒少在傍，書堂孤寂似僧房。',64,'全唐诗/poet.song.134000.json','["晚境諸兒少在傍，書堂孤寂似僧房。", "家居不減旅懷惡，夏夜尚如寒漏長。", "數筯筍虀甘淡薄，半盂麥飯喜豐穰。", "愚儒幸自元無事，日課朱黄自作忙。"]'),
('a869ff2e-d05f-449a-9add-3027f7158bba','明日觀孤寂詩不覺大笑作長句自解','陸游','宋','宋诗','song-poetry','','[]','獨處將如長夜何，直將寂默養天和。',64,'全唐诗/poet.song.134000.json','["獨處將如長夜何，直將寂默養天和。", "愛身不惰如懷璧，守氣無虧似塞河。", "塵篋空存獲麟筆，烟陂懶和飯牛歌。", "年來勛業君知否，纛下新降百萬魔。"]'),
('8c3b8f0a-733c-4bf0-9381-45f584e6a153','初夏出遊三首  其一','陸游','宋','宋诗','song-poetry','','[]','早緣疏拙遂歸耕，晚爲沉綿得養生。',64,'全唐诗/poet.song.134000.json','["早緣疏拙遂歸耕，晚爲沉綿得養生。", "藥鑱釣竿緣已熟，海村山市眼偏明。", "安西萬里人何在，廣武千年恨未平。", "但使蓮峰歸路穩，亦無閑手揖公卿。"]'),
('89b88b61-b95d-4875-bb49-7dc191660ae7','初夏出遊三首  其二','陸游','宋','宋诗','song-poetry','','[]','平生與世曠周旋，惟有清遊意獨便。',64,'全唐诗/poet.song.134000.json','["平生與世曠周旋，惟有清遊意獨便。", "小竈炊菰山市口，束芻秣蹇海雲邊。", "春融恨欠舒長日，秋爽已悲摇落天。", "首夏清和真妙語，爲君誦此一欣然。"]'),
('7e14b6af-9ee9-44b2-905e-f515ef12222b','初夏出遊三首  其三','陸游','宋','宋诗','song-poetry','','[]','泥黦{糭米=木}鞋雨墊巾，閑遊又送一年春。',69,'全唐诗/poet.song.134000.json','["泥黦{糭米=木}鞋雨墊巾，閑遊又送一年春。", "長歌聊對聖賢酒，羸病極知朝暮人。", "廢堞荒郊閑吊古，朱櫻青杏正嘗新。", "桃源自愛山川美，未必當時是避秦。"]'),
('2704059b-1c3c-4315-9fea-651fb96cc512','自詠','陸游','宋','宋诗','song-poetry','','[]','龜屋裁小冠，鹿皮製短裘。',96,'全唐诗/poet.song.134000.json','["龜屋裁小冠，鹿皮製短裘。", "陸駕少游車，水泛淵明舟。", "山澤與城市，有路即可遊。", "或時一飯去，間亦旬日留。", "方見莫木萌，忽已天地秋。", "淘丹雲澗冷，采藥乳穴幽。", "逢人亦欣然，有問乃不酬。", "摩挲金銅人，千載寄悠悠。"]'),
('7f40394c-250f-4373-9801-76caf394b9c0','五更聞雨思季長','陸游','宋','宋诗','song-poetry','','[]','幽叢鳴姑惡，高樹號杜宇。',48,'全唐诗/poet.song.134000.json','["幽叢鳴姑惡，高樹號杜宇。", "驚回千里夢，聽此五更雨。", "展轉窗未明，更覺心獨苦。", "天涯懷故人，安得插兩羽。"]'),
('319a6c8b-5118-4317-9488-2e5a87cb6e8d','醉中作','陸游','宋','宋诗','song-poetry','','[]','小市鐘聲斷，高樓月色新。',48,'全唐诗/poet.song.134000.json','["小市鐘聲斷，高樓月色新。", "醉眠當大路，狂舞屬行人。", "有客要元亮，無妻諫伯倫。", "山花信手插，不復惜烏巾。"]'),
('e2f35059-ccf7-473a-9394-14d206582be6','溪園','陸游','宋','宋诗','song-poetry','','[]','跌宕欲忘形，溪園半醉醒。',48,'全唐诗/poet.song.134000.json','["跌宕欲忘形，溪園半醉醒。", "靜看猿哺果，閑愛鶴梳翎。", "矮榻水紋簟，虛齋山字屏。", "更須新月夜，風露對青冥。"]'),
('5ce8bcb0-0a9b-4dfd-99aa-fdc8ed9c230d','初夏閑居八首  其一','陸游','宋','宋诗','song-poetry','','[]','雲液初篘小甕香，風漪乍展北窗凉。',64,'全唐诗/poet.song.134000.json','["雲液初篘小甕香，風漪乍展北窗凉。", "巢乾燕乳蟲供哺，花過蜂閑蜜滿房。", "閉戶不知春已去，鈔書但覺日方長。", "所嗟詩思年來減，虛負奚奴古錦囊。"]'),
('9c5d88bb-2fd0-4bd0-86f3-0c79842c4606','初夏閑居八首  其二','陸游','宋','宋诗','song-poetry','','[]','川雲漠漠雨冥冥，濁酒閑傾不滿瓶。',64,'全唐诗/poet.song.134000.json','["川雲漠漠雨冥冥，濁酒閑傾不滿瓶。", "蠶簇尚寒憂繭薄，稻陂初滿喜秧青。", "王師護塞方屯甲，親詔憂民已放丁。", "病起自憐猶健在，不須求應少微星。"]'),
('e278956a-e47b-4f3b-9370-4bb7fe06eac8','初夏閑居八首  其三','陸游','宋','宋诗','song-poetry','','[]','松棚黯黯接虛堂，掃地燒香旋置床。',64,'全唐诗/poet.song.134000.json','["松棚黯黯接虛堂，掃地燒香旋置床。", "密葉留花供淺酌，斷雲障日作微凉。", "高城薄暮聞吹角，小市豐年有戲埸。", "白首史官閑盡歲，祇將搜句答流光。"]'),
('3bd33820-3f2f-43bd-855b-54e5996c25b9','初夏閑居八首  其四','陸游','宋','宋诗','song-poetry','','[]','城上朱旗夏令初，溪頭綠水蘸菰蒲。',64,'全唐诗/poet.song.134000.json','["城上朱旗夏令初，溪頭綠水蘸菰蒲。", "花貪結子無遺萼，燕接飛蟲正哺雛。", "簫鼓賽蠶人盡醉，陂塘移稻客相呼。", "長安青蓋金羈馬，也有農家此樂無。"]'),
('6c6d6a0a-3809-48bb-9354-a5224548f60d','初夏閑居八首  其五','陸游','宋','宋诗','song-poetry','','[]','啜茗清風兩腋生，西齋雅具愜幽情。',64,'全唐诗/poet.song.134000.json','["啜茗清風兩腋生，西齋雅具愜幽情。", "熏衣過後篝爐冷，展卷終時懶架橫。", "巢燕何曾擇貧富，鳴鳩元不爲陰晴。", "但能與物俱無著，小草新詩取次成。"]'),
('1156ec73-a9f7-473b-82fa-7940d05e073d','初夏閑居八首  其六','陸游','宋','宋诗','song-poetry','','[]','野水楓林久寄家，慣將枯淡作生涯。',64,'全唐诗/poet.song.134000.json','["野水楓林久寄家，慣將枯淡作生涯。", "小樓有月聽吹笛，深院無風看磑茶。", "靜岸葛巾穿薈蔚，閑拖筇杖入谽谺。", "平居每與兒孫說，切勿人前一語誇。"]'),
('9e90e08c-0b7a-49a2-b94d-db8004538146','初夏閑居八首  其七','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','水邊茆屋兩三間，野叟幽人日往還。',64,'全唐诗/poet.song.134000.json','["水邊茆屋兩三間，野叟幽人日往還。", "兩卷硬黄書老子，數峰破墨畫廬山。", "功名會上元須福，生死津頭正要頑。", "試說龜堂得力處，向來何啻半生閑。"]'),
('a1bb4517-d042-4559-bdfc-e5a590c3692e','初夏閑居八首  其八','陸游','宋','宋诗','song-poetry','','[]','煮酒青梅次第嘗，啼鶯乳燕占年光。',64,'全唐诗/poet.song.134000.json','["煮酒青梅次第嘗，啼鶯乳燕占年光。", "蠶收戶戶繅絲白，麥熟村村搗麨香。", "民有袴襦知歲樂，亭無桴鼓喜時康。", "未嘗一事橫胸次，但曲吾肱夢自長。"]'),
('1c117433-b47e-4651-abb8-841797e27349','子坦今秋鹽官市征當滿作絕句寄之','陸游','宋','宋诗','song-poetry','','[]','八十老翁頭似雪，柯橋送汝泪頻揮。',32,'全唐诗/poet.song.134000.json','["八十老翁頭似雪，柯橋送汝泪頻揮。", "殘年豈料猶强健，却向柯橋接汝歸。"]'),
('50d12208-aa72-4afd-b9e3-b0572a63e071','子遹調官得永平錢監待次甚遠寄詩寬其意蓋將與之偕行也','陸游','宋','宋诗','song-poetry','','[]','黄紙起家陞仕籍，青衫遡闕拜恩光。',64,'全唐诗/poet.song.134000.json','["黄紙起家陞仕籍，青衫遡闕拜恩光。", "署銜汝勿憎銅臭，就養吾方喜飯香。", "世事極知多倚伏，人生正要小回翔。", "但令父子常相守，斂版扶犁味總長。"]'),
('9eac78f1-16fb-4cda-bd43-4347335b50a9','送韓立道守池州','陸游','宋','宋诗','song-poetry','','[]','千里江山控上流，省郎懷綬去爲州。',64,'全唐诗/poet.song.134000.json','["千里江山控上流，省郎懷綬去爲州。", "才華故在諸公右，談笑遥分聖主憂。", "月墮麗譙喧鼓角，雨餘綠野遍鋤耰。", "萬家歌舞春風裏，秋浦如今不似秋。"]'),
('e2a946e0-ec12-4ba6-8435-cfa5baf9087b','野興四首  其一','陸游','宋','宋诗','song-poetry','','[]','寓館無常地，輕裝不宿謀。',48,'全唐诗/poet.song.134000.json','["寓館無常地，輕裝不宿謀。", "迷途問耕叟，過渡上漁舟。", "野飯香炊玉，村醪滑瀉油。", "還家亦無事，隨處送悠悠。"]'),
('c2d2027b-e55c-44a8-80d1-0c189005fa48','野興四首  其二','陸游','宋','宋诗','song-poetry','','[]','小雨迎藜杖，微風入葛巾。',48,'全唐诗/poet.song.134000.json','["小雨迎藜杖，微風入葛巾。", "寧甘結襪系，不作拜車塵。", "施藥鄉鄰喜，忘機鳥雀馴。", "家山又初夏，好在不貲身。"]'),
('baa18e59-e878-485a-86c7-532f3783e2ae','野興四首  其三','陸游','宋','宋诗','song-poetry','','[]','山豁逢孤寺，林窮渡小溝。',48,'全唐诗/poet.song.134000.json','["山豁逢孤寺，林窮渡小溝。", "松聲亂僧梵，雨點雜魚遊。", "皂纛三軍帥，金章萬戶侯。", "人生各有願，未肯換扁舟。"]'),
('cd4465fb-621a-411c-9c25-c8a3ee14725d','野興四首  其四','陸游','宋','宋诗','song-poetry','','[]','去去歷山村，行行並廟垣。',48,'全唐诗/poet.song.134000.json','["去去歷山村，行行並廟垣。", "湍流鱠魚小，仄徑鮓花繁。", "白鷺飛如導，青蘿險可捫。", "歸途不寂寞，迎笑有諸孫。"]'),
('5aaa1f5f-cbe6-4dfa-8c60-259bb8bdd334','東齋雜書十二首  其一','陸游','宋','宋诗','song-poetry','','[]','吾廬雖甚陋，窗扉亦疏明。',48,'全唐诗/poet.song.134000.json','["吾廬雖甚陋，窗扉亦疏明。", "開卷冬日暖，曲肱暑風清。", "昨日一鳥鳴，今日一木榮。", "欣然與之接，悲慨何由生。"]'),
('90055594-a753-46f2-bf42-c85ac88a58e3','東齋雜書十二首  其二','陸游','宋','宋诗','song-poetry','','[]','吾貧無時醒，日月忽遄邁。',48,'全唐诗/poet.song.134000.json','["吾貧無時醒，日月忽遄邁。", "空林春采葚，荒壟秋種稗。", "孤學有自來，饑死奚足怪。", "著書充棟宇，一字不肯賣。"]'),
('f16da407-28b0-43d9-941a-97c6b89aa3fc','東齋雜書十二首  其三','陸游','宋','宋诗','song-poetry','','[]','負負無可言，上上不須說。',48,'全唐诗/poet.song.134000.json','["負負無可言，上上不須說。", "天壤大如許，我獨身孑孑。", "苟合不可爲，萬事聽瓦裂。", "年登麥飯足，得酒且勤啜。"]'),
('4c2a2e6c-a067-4caf-9354-ed7e61abc22b','東齋雜書十二首  其四','陸游','宋','宋诗','song-poetry','','[]','有客可劇談，有酒可盡醉。',48,'全唐诗/poet.song.134000.json','["有客可劇談，有酒可盡醉。", "老夫老更窮，終日惟坐睡。", "既無客款門，酒亦未易致。", "頹然北窗下，兀兀有餘味。"]'),
('f0b31b51-e444-4031-a065-f9e263e6de55','東齋雜書十二首  其五','陸游','宋','宋诗','song-poetry','','[]','下帷聽雨聲，開戶延月色。',48,'全唐诗/poet.song.134000.json','["下帷聽雨聲，開戶延月色。", "霏霏半篆香，湛湛一池墨。", "徐行舒血脈，危坐學踵息。", "吾聞諸先賢，養生莫如嗇。"]'),
('7ed106dc-3b5f-4535-b260-713420d94702','東齋雜書十二首  其六','陸游','宋','宋诗','song-poetry','','[]','門低不通車，室隘劣容膝。',48,'全唐诗/poet.song.134000.json','["門低不通車，室隘劣容膝。", "掩脛無全衣，作字用挫筆。", "親朋孰可望，門內自相恤。", "一笑語吾兒，汝馭未須叱。"]'),
('6b8e154b-8c50-473e-abb8-fe4d71beef50','東齋雜書十二首  其七','陸游','宋','宋诗','song-poetry','','[]','區芋常願雨，秧菜常願晴。',48,'全唐诗/poet.song.134000.json','["區芋常願雨，秧菜常願晴。", "吾兒行渡江，晨起愁風生。", "人生各徇私，夫豈造物情。", "孰能均此意，萬里皆春耕。"]'),
('5bebba84-60d4-4426-ad3b-5c83abb9eae0','東齋雜書十二首  其八','陸游','宋','宋诗','song-poetry','','[]','吾居魚鱉鄉，戒食兼鮮薧。',48,'全唐诗/poet.song.134000.json','["吾居魚鱉鄉，戒食兼鮮薧。", "雞鶩以御客，乃者亦一掃。", "區區仁愛心，殆可質蒼昊。", "物情豈遠哉，我亦吝肝腦。"]'),
('430b67f1-9366-427a-914a-65b832741851','東齋雜書十二首  其九','陸游','宋','宋诗','song-poetry','','[]','藝花恨不茂，薙草欲其盡。',48,'全唐诗/poet.song.134000.json','["藝花恨不茂，薙草欲其盡。", "心常墮貪愛，否則近殘忍。", "蝶網猶翩翾，蚓斷更菌蠢。", "君其等觀之，何者非可閔。"]'),
('25a6a6f4-e2b2-49d5-abaa-e2621313c430','東齋雜書十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','藥與疾相當，何恙不能已。',48,'全唐诗/poet.song.134000.json','["藥與疾相當，何恙不能已。", "良醫善用藥，疾去藥亦止。", "晨晡節飲食，勞佚時卧起。", "藉臼米長生，耄期直易爾。"]'),
('2fe550c3-5891-4cd7-a32b-4f02d9cfe71d','東齋雜書十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','養生有妙理，省事與寡言。',48,'全唐诗/poet.song.134000.json','["養生有妙理，省事與寡言。", "于此能力守，眾說皆其藩。", "擾擾斲汝本，譊譊傷汝魂。", "要當俱置之，息深踵自溫。"]'),
('d6ebc088-0a21-4583-ad40-2ef013f96cdf','東齋雜書十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','學者學聖人，斯須不容苟。',48,'全唐诗/poet.song.134000.json','["學者學聖人，斯須不容苟。", "百年樂簞瓢，千載仰山斗。", "家庭盛弦誦，父子相師友。", "但令書種存，勿愧耕壟畝。"]'),
('d6c8f99e-6479-4187-8289-edbc636fd95d','梅市','陸游','宋','宋诗','song-poetry','','[]','沙際人家半掩扉，借炊小住不相違。',64,'全唐诗/poet.song.134000.json','["沙際人家半掩扉，借炊小住不相違。", "水生溪面大魚躍，風定草頭雙蝶飛。", "竹院遊僧聞鼓集，烟畦老圃荷鋤歸。", "浩然物外真堪樂，回首浮生萬事非。"]'),
('bd2ac145-e74a-4e36-a9e9-5526f8dfca80','初夏幽居四首  其一','陸游','宋','宋诗','song-poetry','','[]','日長巷陌曬絲香，雨霽郊原割麥忙。',64,'全唐诗/poet.song.134000.json','["日長巷陌曬絲香，雨霽郊原割麥忙。", "小擔過門嘗冷粉，微風解籜看新篁。", "傍籬鄰婦收魚笱，叩戶村醫送藥方。", "欲到湖邊還懶動，悠然扶杖立斜陽。"]'),
('b5723ce5-6b61-432e-98aa-a1f425bc8fcc','初夏幽居四首  其二','陸游','宋','宋诗','song-poetry','','[]','虛堂一幅接䍦巾，竹樹森疏夏令新。',64,'全唐诗/poet.song.134000.json','["虛堂一幅接䍦巾，竹樹森疏夏令新。", "瓶竭重招麴道士，床空新聘竹夫人。", "寒龜不食猶能壽，弊帚何施亦自珍。", "枕簟北窗寧有厭，小山終日對嶙峋。"]'),
('cf4d654a-1f22-4aaa-a29c-0cace29f7976','初夏幽居四首  其三','陸游','宋','宋诗','song-poetry','','[]','野草幽花無歇時，一窗終日對東籬。',64,'全唐诗/poet.song.134000.json','["野草幽花無歇時，一窗終日對東籬。", "病猶獨醉雖堪笑，老未全衰亦自奇。", "古紙硬黄臨晉帖，矮箋勻碧錄唐詩。", "箇中疑是忘憂處，問著山翁却不知。"]'),
('691589aa-37e0-419a-89e6-c9748a5065c8','初夏幽居四首  其四','陸游','宋','宋诗','song-poetry','','[]','東園梅熟杏初丹，老子披襟每不冠。',64,'全唐诗/poet.song.134000.json','["東園梅熟杏初丹，老子披襟每不冠。", "古硯坡陀麝煤綠，小山葱蒨石盆寒。", "移床剩欲眠松塢，鼓枻還思泊蓼灘。", "未用絲毫辨差等，黄塵終勝客長安。"]'),
('7911e10c-1d14-4d2d-ab8e-4ab5a66e147f','泛舟至近村茅徐兩舍勞以尊酒','陸游','宋','宋诗','song-poetry','','[]','小舸悠颺亦樂哉，迢迢故取北村回。',64,'全唐诗/poet.song.134000.json','["小舸悠颺亦樂哉，迢迢故取北村回。", "山從樹外參差出，水自城陰曲折來。", "樂歲共忘東作苦，殘租不待急符催。", "舊鄰父老睽離久，喚取開顔把一杯。"]'),
('8a05822c-e0b0-441e-a6a8-6cdb27f2194a','再次前韵','陸游','宋','宋诗','song-poetry','','[]','少壯即今安在哉，輕舟訪舊莫輕回。',64,'全唐诗/poet.song.134000.json','["少壯即今安在哉，輕舟訪舊莫輕回。", "兒童擁岸迎舟入，婦女窺籬喜客來。", "多難只成雙鬢改，流年更著暮笳催。", "放懷魚鳥平生事，少住茅簷盡此杯。"]'),
('45ff724b-3b39-4eb5-81e9-5d880a493e99','題陳伯予主簿所藏秦少遊像','陸游','宋','宋诗','song-poetry','','[]','晚生常恨不從公，忽拜英姿繪畫中。',32,'全唐诗/poet.song.134000.json','["晚生常恨不從公，忽拜英姿繪畫中。", "妄欲步趨端有意，我名公字正相同。"]'),
('738d1328-bb9c-4302-99b4-c71d39adc97c','入梅','陸游','宋','宋诗','song-poetry','','[]','今年入梅日，雲脚垂到地。',72,'全唐诗/poet.song.134000.json','["今年入梅日，雲脚垂到地。", "芬香小麥麨，展轉北窗睡。", "甲夜聞雨聲，起拜造物賜。", "三登于此卜，一飽可坐致。", "語兒高爾囷，戒婦豐爾饋。", "擊壤歌太平，門無督租吏。"]'),
('32db63d8-e085-4603-aa45-aaa4ecd3a4a6','北窗雨中作','陸游','宋','宋诗','song-poetry','','[]','鬰蒸作不解，風雨來有信。',72,'全唐诗/poet.song.134000.json','["鬰蒸作不解，風雨來有信。", "豈惟窗戶清，更喜草木潤。", "簡編既陳前，燈火亦可近。", "跂予望聖賢，傾河洗驕吝。", "扶衰幸未死，吾道其少進。", "安得平生歡，懷抱爲君盡。"]'),
('302e9b4a-7212-491e-9cd5-e8337bb86ff9','戲書觸目','陸游','宋','宋诗','song-poetry','','[]','狸奴閑占熏籠卧，燕子橫穿翠徑飛。',32,'全唐诗/poet.song.134000.json','["狸奴閑占熏籠卧，燕子橫穿翠徑飛。", "我亦人間好事者，憑闌小立試單衣。"]'),
('b057c400-6f6c-4b26-83a9-d32a143f4874','四月二十八日作二首  其一','陸游','宋','宋诗','song-poetry','','[]','四月欲盡五月初，九十未及八十餘。',32,'全唐诗/poet.song.134000.json','["四月欲盡五月初，九十未及八十餘。", "開口何曾談世事，收身且復愛吾廬。"]'),
('22a2388b-0b44-41f2-84e4-32572345ccf2','四月二十八日作二首  其二','陸游','宋','宋诗','song-poetry','','[]','行遍人間病不禁，鬢毛飽受雪霜侵。',32,'全唐诗/poet.song.134000.json','["行遍人間病不禁，鬢毛飽受雪霜侵。", "茅簷一夜蕭蕭雨，洗盡平生幻妄心。"]'),
('dd1782aa-4332-421c-bcb3-8fd8c706b4e6','倚筇','陸游','宋','宋诗','song-poetry','','[]','老翁愈老欲安歸，歸卧稽山飽蕨薇。',64,'全唐诗/poet.song.134000.json','["老翁愈老欲安歸，歸卧稽山飽蕨薇。", "未免解牛逢肯綮，豈能相馬造精微。", "靈山有士拈花笑，闕里何人鼓瑟希。", "我亦倚筇桑竹下，白髯蕭颯滿斜暉。"]'),
('2aa705c6-a87b-4e1b-96f8-b10ab742cd85','薄暑','陸游','宋','宋诗','song-poetry','','[]','仲夏暑尚薄，孤村日尤長。',96,'全唐诗/poet.song.134000.json','["仲夏暑尚薄，孤村日尤長。", "僧坊初施浴，行路亦饋漿。", "老我絕人事，終日坐虛堂。", "南北兩松棚，細細吹清香。", "堂中無長物，獨置湘竹床。", "我睡僕亦休，睡覺誰在傍。", "起坐拭兩眥，小山鬰蒼蒼。", "安得烏有生，俱老無何鄉。"]'),
('cd7da580-451d-45bd-ad47-1104fe2fe93c','晝寢二首  其一','陸游','宋','宋诗','song-poetry','','[]','倦腕擎書忽墮前，心清無夢腹便便。',32,'全唐诗/poet.song.134000.json','["倦腕擎書忽墮前，心清無夢腹便便。", "丹成未要排雲去，且住人間作睡仙。"]'),
('5887e281-5923-4d7a-8af1-2a570055188f','晝寢二首  其二','陸游','宋','宋诗','song-poetry','','[]','困睫芒羊一欠伸，頹然忽已墮紗巾。',32,'全唐诗/poet.song.134000.json','["困睫芒羊一欠伸，頹然忽已墮紗巾。", "鼻端雷動君無怪，路熟華胥不問津。"]'),
('3c83c071-95a2-4adf-8898-306790baf50f','睡起二首  其一','陸游','宋','宋诗','song-poetry','','[]','睡起倀倀扇懶摇，枕痕著面未全消。',32,'全唐诗/poet.song.134000.json','["睡起倀倀扇懶摇，枕痕著面未全消。", "山丹石竹俱零落，孤蝶飛來伴寂寥。"]'),
('56a65017-32dc-4431-a692-a09c70dbdf62','睡起二首  其二','陸游','宋','宋诗','song-poetry','','[]','蒲萄換葉欲成陰，歲月催人感慨深。',32,'全唐诗/poet.song.134000.json','["蒲萄換葉欲成陰，歲月催人感慨深。", "安得門前無俗客，岸巾臨水聽蟬吟。"]'),
('dfc38386-bd98-463f-a313-0b7e1ca21c46','林間書意二首  其一','陸游','宋','宋诗','song-poetry','','[]','三三兩兩市船回，水際柴門尚未開。',64,'全唐诗/poet.song.134000.json','["三三兩兩市船回，水際柴門尚未開。", "垂綠筍梢風正惡，弄黄梅子雨初來。", "紅螺杯小傾花露，紫玉池深貯麝煤。", "領取林間閑富貴，向來誤計伴鄒枚。"]'),
('6ccb5a5f-8099-41e6-9bb9-9ce3d7c746d3','林間書意二首  其二','陸游','宋','宋诗','song-poetry','','[]','小山草木一窗秋，團扇江山萬里愁。',64,'全唐诗/poet.song.134000.json','["小山草木一窗秋，團扇江山萬里愁。", "不讀狐書真僻學，未登鬼籙且閑遊。", "少隨官牒嗟無策，晚脫朝衫喜自由。", "半嶺嘯聲驚阮籍，要知天下有高流。"]'),
('bcda8498-85c3-4f92-b615-0a919d286e1a','示子遹','陸游','宋','宋诗','song-poetry','','[]','吾家太傅後，衿佩盛青青。',48,'全唐诗/poet.song.134000.json','["吾家太傅後，衿佩盛青青。", "我忝殿諸老，汝能通一經。", "學先嚴詁訓，書要講聲形。", "夙夜常相勉，諸孫待典刑。"]'),
('c977ec06-54a8-4e67-a4aa-5e17746bd684','追凉小酌','陸游','宋','宋诗','song-poetry','','[]','綠樹暗魚梁，臨流追晚凉。',48,'全唐诗/poet.song.134000.json','["綠樹暗魚梁，臨流追晚凉。", "持杯屬江月，散髮據胡床。", "苦荬腌虀美，菖蒲漬蜜香。", "醉來呼稚子，扶我上南塘。"]'),
('9d2264ac-342c-4942-8bff-3f8a8ed687eb','暑夜泛舟二首  其一','陸游','宋','宋诗','song-poetry','','[]','暑氣方然一鼎湯，聊呼艇子夜追凉。',64,'全唐诗/poet.song.134000.json','["暑氣方然一鼎湯，聊呼艇子夜追凉。", "微風忽起髮根冷，闕月初升林影長。", "漸近場中聞笑語，却從堤外看帆檣。", "超然自適君知否，身世從來付兩忘。"]'),
('2d3964ce-bf59-4890-a119-9f21cc66a521','暑夜泛舟二首  其二','陸游','宋','宋诗','song-poetry','','[]','烈暑元知不可逃，天將清夜付吾曹。',64,'全唐诗/poet.song.134000.json','["烈暑元知不可逃，天將清夜付吾曹。", "小舟行處浦風急，健鶻歸時山月高。", "愚智極知均腐骨，利名何啻一秋毫。", "等閑分得吳松水，安用并州快翦刀。"]'),
('689ecfc1-4e9d-435f-bcc8-f7f18f37e7e7','短歌行','陸游','宋','宋诗','song-poetry','','[]','冠一免不可以復冠，門一杜不可以復開。',116,'全唐诗/poet.song.134000.json','["冠一免不可以復冠，門一杜不可以復開。", "山林兀兀但俟死，臺省衮衮吁可哀。", "巨材倒壑亦已矣，萬牛欲挽真難哉。", "阿房銅人其重各千石，回首變化爲風埃。", "吾曹浮脆不自悟，乃欲冠劍常崔嵬。", "勸君飲勿用杯酌，但當手提北斗魁。", "挹乾東海見蓬萊，安用俯首爲低摧。"]'),
('a16cc6c8-d55f-406c-bdb2-431609be251c','小江','陸游','宋','宋诗','song-poetry','','[]','細靄斜陽一片秋，數家茅屋小江頭。',64,'全唐诗/poet.song.134000.json','["細靄斜陽一片秋，數家茅屋小江頭。", "櫓聲遠入菰蘆夾，鳥陣斜飛蘭杜洲。", "暫住便成閑嘯詠，欲歸更復小遲留。", "老翁脚力猶能健，明日重來倚寺樓。"]'),
('7c9ea78a-ba09-4842-aff6-ab144417f3a9','歸興二首  其一','陸游','宋','宋诗','song-poetry','','[]','輕雷轣轆斷梅初，殘籜縱橫過筍餘。',64,'全唐诗/poet.song.134000.json','["輕雷轣轆斷梅初，殘籜縱橫過筍餘。", "飽有期程新買犢，睡無厭足久捐書。", "白蘋滿渚閑揮榜，綠樹連村獨跨驢。", "夏日儘長歸亦暮，水邊燈火已疏疏。"]'),
('8dcdc02b-76b3-4bf3-ace4-b68e25117502','歸興二首  其二','陸游','宋','宋诗','song-poetry','','[]','古道迢迢人迹稀，羸驂欹帽遠村歸。',64,'全唐诗/poet.song.134000.json','["古道迢迢人迹稀，羸驂欹帽遠村歸。", "正看日暮羊牛下，又見月明烏鵲飛。", "僧院疏鐘出林岫，漁家微火耿窗扉。", "閑遊要是幽人事，草露從教濕短衣。"]'),
('fd9af6bf-0e6c-4a4d-9221-cd63afbe42fb','自春來數夢至閬中蒼溪驛五月十四日又夢作兩絕句記之  其一','陸游','宋','宋诗','song-poetry','','[]','騎驢夜到蒼溪驛，正是猿啼月落時。',32,'全唐诗/poet.song.134000.json','["騎驢夜到蒼溪驛，正是猿啼月落時。", "三十五年如電掣，敗牆誰護舊題詩。"]'),
('ec7a45c3-fc4d-439b-8bb3-f2a69e66d3d7','自春來數夢至閬中蒼溪驛五月十四日又夢作兩絕句記之  其二','陸游','宋','宋诗','song-poetry','','[]','亭皋敗葉先秋霣，城上驚烏半夜啼。',32,'全唐诗/poet.song.134000.json','["亭皋敗葉先秋霣，城上驚烏半夜啼。", "自笑遠遊心未已，年來頻夢到蒼溪。"]'),
('5f5f6580-5c66-4f81-b71e-0d814f18579c','自嘲二首  其一','陸游','宋','宋诗','song-poetry','','[]','長日淡無事，虛堂來遠風。',48,'全唐诗/poet.song.134000.json','["長日淡無事，虛堂來遠風。", "愛眠從病蹇，厭事懶治聾。", "貓健翻憐鼠，庭荒不責童。", "爾來添目暗，又免送歸鴻。"]'),
('ae53f10c-c140-4d92-9d0b-01ec557589a5','自嘲二首  其二','陸游','宋','宋诗','song-poetry','','[]','身卧孤村日，年當大耋時。',48,'全唐诗/poet.song.134000.json','["身卧孤村日，年當大耋時。", "貧憂償酒券，懶悔許僧碑。", "輸稅質耕犢，飯醫烹伏雌。", "勞生不須嘆，隨事且支持。"]'),
('d8a4200e-d44c-405e-96c2-8d4925ec7480','雨霽','陸游','宋','宋诗','song-poetry','','[]','一雨洗炎蒸，危闌偶獨憑。',48,'全唐诗/poet.song.134000.json','["一雨洗炎蒸，危闌偶獨憑。", "凉颸生萃蔡，爽氣入鬅鬙。", "庭下宵遊燐，盤中晝掃蠅。", "絕勝塵土裏，馬上嚼寒冰。"]'),
('211aaf39-4410-42a4-a7d1-bcf8c5b1bbba','大雨','陸游','宋','宋诗','song-poetry','','[]','萬壑風聲遠，千林雨脚長。',48,'全唐诗/poet.song.134000.json','["萬壑風聲遠，千林雨脚長。", "溝盈懸爨竈，屋漏徙衣囊。", "未說豐年喜，先便永夜凉。", "清秋病小愈，起柁上瀟湘。"]'),
('94d656b7-4640-4926-acfd-17c37938dde1','社飲','陸游','宋','宋诗','song-poetry','','[]','世上升沉一轆轤，古來成敗幾樗蒱。',64,'全唐诗/poet.song.134000.json','["世上升沉一轆轤，古來成敗幾樗蒱。", "試看大醉稱賢相，始信常醒是鄙夫。", "起舞非無垂白伴，暮歸仍有髧髦扶。", "即今不乏丹青手，誰畫三山社飲圖。"]'),
('613ac4b9-fd36-4797-be81-30d20459f264','采藥有感','陸游','宋','宋诗','song-poetry','','[]','蒹葭記霜露，蟋蟀謹歲月。',96,'全唐诗/poet.song.134000.json','["蒹葭記霜露，蟋蟀謹歲月。", "古人于物理，瑣細不敢忽。", "我少讀蒼雅，衰眊今白髮。", "中間嬰疢疾，過日常卒卒。", "澗毛春可求，山藥秋可掘。", "雖云力探討，疑義未免闕。", "屏居朋友散，奧妙誰敢發。", "窮理已矣夫，置觵當自罰。"]'),
('05ea88f0-ca65-492b-a66b-e2562d0f1c12','觀邸報感懷','陸游','宋','宋诗','song-poetry','','[]','六聖涵濡壽域民，耄年肝膽尚輪囷。',64,'全唐诗/poet.song.134000.json','["六聖涵濡壽域民，耄年肝膽尚輪囷。", "難求壯士白羽箭，且岸先生烏角巾。", "幽谷主盟猿鶴社，扁舟自適水雲身。", "却看長劍空三嘆，上蔡臨淮奏捷頻。"]'),
('d7b6d414-1ccd-4951-b5c6-c43838348d34','送子遹至梅市而歸','陸游','宋','宋诗','song-poetry','','[]','梅市長堤愴別情，魯墟歸路當閑行。',64,'全唐诗/poet.song.134000.json','["梅市長堤愴別情，魯墟歸路當閑行。", "日沉菱浦看魚躍，烟合菰叢聞獺鳴。", "蘸水門扉初半掩，擁橋炬火已先迎。", "停橈不奈清愁得，獨倚闌干待月明。"]'),
('4ce7fab5-438a-4bd3-9656-2943387a7c63','述閑','陸游','宋','宋诗','song-poetry','','[]','披衣按摩罷，據榻欠伸餘。',48,'全唐诗/poet.song.134000.json','["披衣按摩罷，據榻欠伸餘。", "香暖翻心字，茶凝出草書。", "客稀門每閉，意悶髮重梳。", "賴有盆山樹，幽情得少攄。"]'),
('9b48c6f9-e084-4a97-aaf3-4561915b5e1e','幽居','陸游','宋','宋诗','song-poetry','','[]','謝病言歸一鹿車，短籬數掩護幽居。',64,'全唐诗/poet.song.134000.json','["謝病言歸一鹿車，短籬數掩護幽居。", "樹枝南畔有飛鵲，蓮葉東邊多戲魚。", "倦枕續成驚斷夢，斜風吹落讀殘書。", "興來偶曳枯筇出，父老逢迎却未疏。"]'),
('28b0c380-7c1b-4ba6-b1ea-e848ab2715c7','午暑','陸游','宋','宋诗','song-poetry','','[]','笛材織簟凉如水，霧縠縫幮薄若空。',32,'全唐诗/poet.song.134000.json','["笛材織簟凉如水，霧縠縫幮薄若空。", "更著高安竹根枕，不妨專享北窗風。"]'),
('b3df4907-1e92-4a5d-83b4-ea33156d21eb','舟過道士莊','陸游','宋','宋诗','song-poetry','','[]','江蘺芳杜滿沙汀，道士莊前酒半醒。',64,'全唐诗/poet.song.134000.json','["江蘺芳杜滿沙汀，道士莊前酒半醒。", "上下風烟還竟日，往來魚鳥各忘形。", "歸人薄晚常爭渡，病葉先秋亦自零。", "興欲盡時猶小住，北村漁火看青熒。"]'),
('88d594cc-8ca0-469e-ac3f-4328503f0d28','晨興','陸游','宋','宋诗','song-poetry','','[]','晨興未櫛盥，扶杖並簷立。',72,'全唐诗/poet.song.134000.json','["晨興未櫛盥，扶杖並簷立。", "斷雲方東行，庭草露猶溼。", "朝饑神益爽，清虛自來入。", "可憐數雞雛，隨母啄遺粒。", "蝶殘蚍蜉喜，鼠腐鴟鴉集。", "吾當一洗之，漱泉開玉笈。"]'),
('2082e469-4f07-4683-b413-d9dab339cda9','對酒','陸游','宋','宋诗','song-poetry','','[]','斷簡殘編不策勛，東皋猶得肆微勤。',64,'全唐诗/poet.song.134000.json','["斷簡殘編不策勛，東皋猶得肆微勤。", "榮枯一枕春來夢，聚散千山雨後雲。", "烟水幸堪供眼界，世緣何得累心君。", "床頭小甕今朝熟，撥置閑愁且一欣。"]'),
('3079296b-124f-40a8-acc5-02458dee3112','泛舟','陸游','宋','宋诗','song-poetry','','[]','水長芳洲沒，風生釣艇橫。',48,'全唐诗/poet.song.134000.json','["水長芳洲沒，風生釣艇橫。", "偶尋東埭去，却作北村行。", "宿鳥昏方定，流螢雨更明。", "歸來未覺晚，傳漏下重城。"]'),
('1f5f0fcb-670b-421a-84d7-acadab12224c','地僻','陸游','宋','宋诗','song-poetry','','[]','地僻臨湍瀨，門幽長綠苔。',48,'全唐诗/poet.song.134000.json','["地僻臨湍瀨，門幽長綠苔。", "客書疑誤達，僧刺愧虛來。", "清露蘋花坼，斜陽燕子回。", "自憐猶有恨，佳日對空罍。"]'),
('b1109752-a6a3-45eb-8302-a44e84efd682','東軒','陸游','宋','宋诗','song-poetry','','[]','終日在東廂，閑消百刻香。',48,'全唐诗/poet.song.134000.json','["終日在東廂，閑消百刻香。", "一枰分黑白，雙硯列朱黄。", "荷氣侵簾馥，桐陰覆井凉。", "前知今夕夢，孤榜上瀟湘。"]'),
('3f3513fd-d4fd-48b1-a11a-dcbf5e036f42','季夏雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','蟻鬭知將雨，蟲鳴覺近秋。',24,'全唐诗/poet.song.134000.json','["蟻鬭知將雨，蟲鳴覺近秋。", "衰翁非愛酒，無計奈孤愁。"]'),
('608130ae-6202-4000-ab14-9e487fc0cc02','季夏雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','巉巉瘦驢嶺，莽莽老牛陂。',24,'全唐诗/poet.song.134000.json','["巉巉瘦驢嶺，莽莽老牛陂。", "四海均羈旅，何人感此詩。"]'),
('3b1334da-5fa0-4c5c-8c62-246e90709128','季夏雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','熟睡一炊頃，清談數刻間。',24,'全唐诗/poet.song.134000.json','["熟睡一炊頃，清談數刻間。", "未言能近道，要得暫身閑。"]'),
('f8100910-4d0a-46bf-af5a-538b2685854e','季夏雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','疏泉澆藥壟，枕石聽松風。',24,'全唐诗/poet.song.134000.json','["疏泉澆藥壟，枕石聽松風。", "此樂慚專享，無因與客同。"]'),
('5c90e15d-1523-41ba-801a-987c2fa9392e','夏夜暑毒不少解起坐庭中二首  其一','陸游','宋','宋诗','song-poetry','','[]','窗間有螢過，枕上見星流。',24,'全唐诗/poet.song.134000.json','["窗間有螢過，枕上見星流。", "欲睡不堪熱，長歌起飯牛。"]'),
('448f4bc4-43cb-41a7-80c5-c195b60475bd','夏夜暑毒不少解起坐庭中二首  其二','陸游','宋','宋诗','song-poetry','','[]','風從高樹下，蟲抱短莎鳴。',24,'全唐诗/poet.song.134000.json','["風從高樹下，蟲抱短莎鳴。", "小據胡床坐，還扶拄杖行。"]'),
('d3eab343-cf0c-4d1a-9706-2b22915ad96b','素飯','陸游','宋','宋诗','song-poetry','','[]','放翁年來不肉食，盤箸未免猶豪奢。',64,'全唐诗/poet.song.134000.json','["放翁年來不肉食，盤箸未免猶豪奢。", "松桂軟炊玉粒飯，醯醬自調銀色茄。", "時招林下二三子，氣壓城中千百家。", "緩步橫摩五經笥，風爐更試茶山茶。"]'),
('2954f329-68cd-48f8-a213-6c7a49f2d205','老態自遣','陸游','宋','宋诗','song-poetry','','[]','似見不見目愈衰，欲墮不墮齒更危。',96,'全唐诗/poet.song.134000.json','["似見不見目愈衰，欲墮不墮齒更危。", "誰令汝年八九十，常欲强健寧非癡。", "目昏大字亦可讀，齒摇猶能决濡肉。", "若知用短百無憂，此理正如夔一足。", "矇矓臲卼俱有味，笑侮莫聽傍人喙。", "但令孫曾能力耕，一飽不妨還美睡。"]'),
('3d90dde9-ea57-46a2-b752-a571b32aac00','耒陽令曾君寄禾譜農器譜二書求詩','陸游','宋','宋诗','song-poetry','','[]','歐陽公譜西都花，蔡公亦記北苑茶。',112,'全唐诗/poet.song.134000.json','["歐陽公譜西都花，蔡公亦記北苑茶。", "農功最大置不錄，如棄六藝崇百家。", "曾侯奮筆譜多稼，儋州讀罷深咨嗟。", "一篇秧馬傳海內，農器名數方萌芽。", "令君繼之筆何健，古今一一辨等差。", "我今八十歸抱耒，兩編入手喜莫涯。", "神農之學未可廢，坐使末俗慚浮華。"]'),
('2bf5971c-aa45-46cd-a0b9-8cc4a7895371','雨夜','陸游','宋','宋诗','song-poetry','','[]','羸軀對影愴餘齡，追念平時只自驚。',64,'全唐诗/poet.song.134000.json','["羸軀對影愴餘齡，追念平時只自驚。", "夏木正濃桐葉墜，秋風未起草蟲鳴。", "蠹魚似是三生業，汗馬難希百世名。", "小雨迎凉何所作，北窗還對短燈檠。"]'),
('632f15be-e495-40cb-b64b-476252a7de01','柴門','陸游','宋','宋诗','song-poetry','','[]','寂寞柴門不徹扃，槐花細細糝空庭。',64,'全唐诗/poet.song.134000.json','["寂寞柴門不徹扃，槐花細細糝空庭。", "晚梅摘得鹽供飣，濁酒沽來草塞瓶。", "病已廢耕拋襏襫，閑猶持釣愛笭箵。", "經旬莫恨無來客，交舊疏如欲旦星。"]'),
('b58738e1-989e-4fc4-ac57-b1a3b588de27','賽神','陸游','宋','宋诗','song-poetry','','[]','落日林間簫鼓聲，村村倒社祝西成。',64,'全唐诗/poet.song.134000.json','["落日林間簫鼓聲，村村倒社祝西成。", "扶翁兒大兩髦髧，溉水渠成千耦耕。", "家受一廛修本業，鄉推三老主齊盟。", "日聞淮潁歸王化，要使新民識太平。"]'),
('addbe59f-99ec-4cd5-a5d0-f0f1104154ac','菖蒲二首  其一','陸游','宋','宋诗','song-poetry','','[]','古磵生菖蒲，根瘦節蹙密。',48,'全唐诗/poet.song.134000.json','["古磵生菖蒲，根瘦節蹙密。", "仙人教我服，刀匕蠲百疾。", "陽狂華陰市，顔朱髮如漆。", "歲久功當成，壽與天地畢。"]'),
('fd69ed7e-0a58-4ae0-8bcc-be34302865f1','菖蒲二首  其二','陸游','宋','宋诗','song-poetry','','[]','菖蒲古上藥，結根已千年。',48,'全唐诗/poet.song.134000.json','["菖蒲古上藥，結根已千年。", "聞之安期生，采服可以仙。", "斯人非世人，兩耳長垂肩。", "松下語未終，竦身上青天。"]'),
('ba164190-9b89-46b9-9084-c7c23958b5a1','迂拙','陸游','宋','宋诗','song-poetry','','[]','迂拙宜歸早，乘除得死遲。',48,'全唐诗/poet.song.134000.json','["迂拙宜歸早，乘除得死遲。", "老稀朝市夢，窮足道途詩。", "譁世無它技，忘懷自一奇。", "故溪幽絕處，惟許白鷗知。"]'),
('6ad35a77-c51d-4c79-a9ca-ca8dd6fad562','夏夜','陸游','宋','宋诗','song-poetry','','[]','六尺筇枝膝上橫，中庭岸幘聽鼉更。',64,'全唐诗/poet.song.134000.json','["六尺筇枝膝上橫，中庭岸幘聽鼉更。", "露零金掌漢宮曉，月度銀河秦塞明。", "菡萏晚花香未減，梧桐病葉墮無聲。", "關河又見新秋近，屈指流年一嘆驚。"]'),
('e30fc58f-29cf-479b-91b1-e2ae0f634ed5','夏末野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','半世天涯倦遠遊，還鄉不減旅人愁。',64,'全唐诗/poet.song.134000.json','["半世天涯倦遠遊，還鄉不減旅人愁。", "數聲相應鳩呼雨，一片初飛葉報秋。", "山塢風烟僧院路，河梁燈火酒家樓。", "絕知雪鬢宜蓑笠，分付貂蟬與黑頭。"]'),
('f7b0a84b-8894-4714-9a22-26996367a952','夏末野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','漠漠川雲闔復開，天公試手挽秋回。',64,'全唐诗/poet.song.134000.json','["漠漠川雲闔復開，天公試手挽秋回。", "參差小市林邊出，縹緲疏鐘雨外來。", "土挼飯香供晚餉，布帘字大賣新醅。", "歸舟自逐輕鷗去，不用城笳抵死催。"]'),
('10b206d4-f6e9-4353-9333-44d1f9633118','示子孫','陸游','宋','宋诗','song-poetry','','[]','茆屋惟須補漏穿，家人衣食亦隨緣。',32,'全唐诗/poet.song.134000.json','["茆屋惟須補漏穿，家人衣食亦隨緣。", "豈容一事相關白，已過傳家十二年。"]'),
('5d489993-5a57-4163-b7bb-03174751f888','夜雨','陸游','宋','宋诗','song-poetry','','[]','藩籬處處蔓牽牛，薏苡叢深稗穗抽。',32,'全唐诗/poet.song.134000.json','["藩籬處處蔓牽牛，薏苡叢深稗穗抽。", "只道物生常茂遂，一宵風雨又成秋。"]'),
('ee632e1e-f839-4e77-bfd5-ede2ac490532','劇暑','陸游','宋','宋诗','song-poetry','','[]','六月暑方劇，喘汗不支持。',216,'全唐诗/poet.song.134000.json','["六月暑方劇，喘汗不支持。", "逃之顧無術，惟望樹影移。", "或謂當讀書，或勸把酒卮。", "或誇作字好，蕭然却炎曦。", "或欲溪上釣，或思竹間棋。", "亦有出下策，買簟傾家貲。", "赤脚蹋增冰，此計又絕癡。", "我獨謂不然，願子少置思。", "方今詔書下，淮汴方出師。", "黄旗立轅門，羽檄晝夜馳。", "大將先擐甲，三軍隨指揮。", "行伍未盡食，大將不言饑。", "渴不先飲水，驟不先告疲。", "吾儕獨安居，茂林蔭茅茨。", "脫巾濯寒泉，卧起從其私。", "于此尚畏熱，鬼神其可欺。", "坐客皆謂然，索紙遂成詩。", "便覺窗几間，颯颯清風吹。"]'),
('ba7518eb-c1b2-4518-ae45-d8de8a049d28','六月十夜風月佳甚起坐中庭有作','陸游','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','曼膚汗雨不勝揮，夜景泠然暫解圍。',64,'全唐诗/poet.song.134000.json','["曼膚汗雨不勝揮，夜景泠然暫解圍。", "漱罷寒泉甘齒頰，夢回斜月入窗扉。", "荷翻小浦孤螢度，露溼危巢倦鶴歸。", "我亦馭風思遠適，岳陽樓上酹湘妃。"]'),
('fa77e0df-7412-4e28-bc91-e4dd4b83b777','古井','陸游','宋','宋诗','song-poetry','','[]','道傍有古井，久廢無與汲。',48,'全唐诗/poet.song.134000.json','["道傍有古井，久廢無與汲。", "鄰里共浚之，寒泉稍來集。", "駕言欲漱濯，冀遠塵土襲。", "躊躇復棄去，綆短安能及。"]'),
('8697a01f-e451-4d93-8552-39a29d3a0067','庵中紀事用前輩韵','陸游','宋','宋诗','song-poetry','','[]','掃灑一庵躬瑣細，蓬戶朝昏手開閉。',96,'全唐诗/poet.song.134000.json','["掃灑一庵躬瑣細，蓬戶朝昏手開閉。", "荒山斸藥須長鑱，小竈煎茶便短袂。", "空中咄咄安用書，身外悠悠固難計。", "山僧野叟到即留，麥飯葵羹貴能繼。", "久貧奴婢多散去，豈有跣足並椎髻。", "負薪長歌過此生，直疑身在鴻荒世。"]'),
('445fb539-47c1-4793-8e49-04d40e14f762','急雨','陸游','宋','宋诗','song-poetry','','[]','觸熱支離老病增，忽看東北片雲興。',64,'全唐诗/poet.song.134000.json','["觸熱支離老病增，忽看東北片雲興。", "疾雷載雨輸膏澤，茂樹生風洗鬰蒸。", "采藥喜逢岷下客，說詩曾對剡中僧。", "坐令身在羲皇上，繞坐何煩更設冰。"]'),
('498443aa-f6e3-482a-9ff7-1b2a5332eb2e','舍東追凉','陸游','宋','宋诗','song-poetry','','[]','驕陽收火傘，清露貯冰壺。',48,'全唐诗/poet.song.134000.json','["驕陽收火傘，清露貯冰壺。", "海湧四更月，風生千頃蒲。", "歌狂忘老境，意豁失窮途。", "所恨朋儕盡，無人爲攬鬚。"]'),
('217788c6-44c9-4eeb-a89c-cfe6df7afd36','酒藥','陸游','宋','宋诗','song-poetry','','[]','愁憑酒破除，病藉藥枝梧。',48,'全唐诗/poet.song.134000.json','["愁憑酒破除，病藉藥枝梧。", "焦革死已久，宋清今亦無。", "幽情寄魚鳥，小艇雜菰蒲。", "海上秋風早，懸知肺渴蘇。"]'),
('7eb9ad5d-a7c0-4dfe-b17d-2a38a28d5e45','六月十七日大暑殆不可過然去伏盡秋初皆不過數日作此自遣','陸游','宋','宋诗','song-poetry','','[]','赫日炎威豈易摧，火雲壓屋正崔嵬。',64,'全唐诗/poet.song.134000.json','["赫日炎威豈易摧，火雲壓屋正崔嵬。", "嗜眠但喜蘄州簟，畏酒不禁河朔杯。", "人望息肩亭午過，天方悔禍素秋來。", "細思殘暑能多少，夜夜常占斗柄回。"]'),
('81c87756-1f7a-4035-954a-aaffbe12ad88','急雨遽凉','陸游','宋','宋诗','song-poetry','','[]','急雨消殘暑，曠然天地秋。',48,'全唐诗/poet.song.134000.json','["急雨消殘暑，曠然天地秋。", "露螢矜熠熠，風葉送颼颼。", "凉簟惟添睡，明河不洗愁。", "流年又如此，隨處怯登樓。"]'),
('3c1528fe-b188-4964-a948-f26ad06badd7','縱遊深山隨所遇記之四首  其一','陸游','宋','宋诗','song-poetry','','[]','行穿犖确度谽谺，路跨清溪一木斜。',32,'全唐诗/poet.song.134000.json','["行穿犖确度谽谺，路跨清溪一木斜。", "歷盡艱危到平地，壞垣欹屋兩三家。"]'),
('aeb0b635-40df-4572-bb0b-c217534940d9','縱遊深山隨所遇記之四首  其二','陸游','宋','宋诗','song-poetry','','[]','山徑欹危細棧通，孤村小店夕陽紅。',32,'全唐诗/poet.song.134000.json','["山徑欹危細棧通，孤村小店夕陽紅。", "竹郎有廟臨江際，木客無家住箐中。"]'),
('9139bea3-98f2-4e51-8e2c-8331d67ab72e','縱遊深山隨所遇記之四首  其三','陸游','宋','宋诗','song-poetry','','[]','道逢山客束荆薪，口眼睢盱略似人。',32,'全唐诗/poet.song.134000.json','["道逢山客束荆薪，口眼睢盱略似人。", "試問村名瞠不語，剨然長嘯上嶙峋。"]'),
('df6b1204-ce4a-41b0-ba03-02fdb3c16ff1','縱遊深山隨所遇記之四首  其四','陸游','宋','宋诗','song-poetry','','[]','古寺蕭蕭不見僧，飛鼪滿屋老梟鳴。',32,'全唐诗/poet.song.134000.json','["古寺蕭蕭不見僧，飛鼪滿屋老梟鳴。", "空房終夜無燈火，斷木支門睡到明。"]'),
('6ee8cacb-37eb-44ba-aacc-f69ed553ba41','感中原舊事戲作','陸游','宋','宋诗','song-poetry','','[]','蜂兒園裏香塵細，燕子樓中寶瑟斜。',32,'全唐诗/poet.song.134000.json','["蜂兒園裏香塵細，燕子樓中寶瑟斜。", "惟有天知太平事，乞傾東海洗胡沙。"]'),
('7ee7a5e3-bcf3-4608-9c84-ef8056f355ab','小凉','陸游','宋','宋诗','song-poetry','','[]','羸軀一夏困沉綿，不在林間即水邊。',64,'全唐诗/poet.song.134000.json','["羸軀一夏困沉綿，不在林間即水邊。", "高卧已忘浮世事，小凉漸近早秋天。", "桔槔軋軋鳴幽圃，舴艋遥遥入暮烟。", "餘日無多那諱得，逢人自笑說明年。"]'),
('0ee9abb2-fe66-4be4-a40a-08731f8c6687','村居','陸游','宋','宋诗','song-poetry','','[]','人笑無才自笑狂，槿籬竹塢得深藏。',64,'全唐诗/poet.song.134000.json','["人笑無才自笑狂，槿籬竹塢得深藏。", "自從病後辜風月，未免愁中讀老莊。", "行圃數畦秋菜長，泛溪十里晚荷香。", "叢書坐懶無由續，且補忠州手錄方。"]'),
('2c66441d-3fc1-47b1-ba48-d7bd405c944f','城東','陸游','宋','宋诗','song-poetry','','[]','出郭溶溶細縠波，平生此地幾經過。',64,'全唐诗/poet.song.134000.json','["出郭溶溶細縠波，平生此地幾經過。", "祭餘野廟啼烏樂，酒賤村墟醉叟多。", "亭午疏鐘離石佛，斂昏微雨泊曹娥。", "采蓮艇子愁衣溼，不爲人家惜綠荷。"]'),
('18855b5a-2ff7-4796-8202-6331a2b45211','初秋露坐作短歌','陸游','宋','宋诗','song-poetry','','[]','房星縱，心星橫，斗牛闌干河漢明。',64,'全唐诗/poet.song.134000.json','["房星縱，心星橫，斗牛闌干河漢明。", "青天露坐性所樂，不覺庭樹秋風生。", "秋風摇落君勿悲，明年花開還滿枝。", "人生衰謝則已矣，寧復鬒髮童顔時。"]'),
('804c7f16-b50d-434f-afdd-1196b3ee6db7','池上','陸游','宋','宋诗','song-poetry','','[]','旋移吟榻並池橫，欲出柴門復懶行。',64,'全唐诗/poet.song.134000.json','["旋移吟榻並池橫，欲出柴門復懶行。", "樹罅忽明知月上，竹梢微動覺風生。", "貧無醉日惟堅忍，疾遇凉秋亦漸平。", "二尺燈檠元好在，便思相伴聽蛩聲。"]'),
('ff0e8f07-ce8f-4113-afad-4114f968767e','秋稼漸登識喜','陸游','宋','宋诗','song-poetry','','[]','門外新場滑似油，早禾已慶十分收。',64,'全唐诗/poet.song.134000.json','["門外新場滑似油，早禾已慶十分收。", "虹霓不隔郊原雨，蜩蚻爭催巷陌秋。", "人樂風傳迎社鼓，路長水濺采蓮舟。", "老翁自笑無它事，欲隱牆東學儈牛。"]'),
('08a3d095-6702-4937-9627-fd0f9f16bca2','野渡用前韵','陸游','宋','宋诗','song-poetry','','[]','十里平沙到渡頭，溪山合向畫圖收。',64,'全唐诗/poet.song.134000.json','["十里平沙到渡頭，溪山合向畫圖收。", "老僧赴供袈黎古，醉叟行歌䆉䅉秋。", "斷岸烟迷耕處草，孤村雨送釣時舟。", "龍泉不斸元無恨，莫放神光上斗牛。"]'),
('ac84585d-5a58-473b-8fe2-845937cd5ed6','秋後一日風雨','陸游','宋','宋诗','song-poetry','','[]','炎歊數日劇，蕩滌及秋初。',48,'全唐诗/poet.song.134000.json','["炎歊數日劇，蕩滌及秋初。", "病葉風吹盡，鳴蟬雨打疏。", "趁凉謀社酒，乘潤理園蔬。", "分喜寧無處，蒲中鱍鱍魚。"]'),
('5e3bc8b8-a34b-42ab-ab0a-0cca0708246e','感事','陸游','宋','宋诗','song-poetry','','[]','曾事高皇接雋遊，君恩天地若爲酬。',64,'全唐诗/poet.song.134000.json','["曾事高皇接雋遊，君恩天地若爲酬。", "濟時已負終身愧，謀己常從一笑休。", "在昔風塵馳廄置，即今烟雨暗耕疇。", "孤愁欲豁寧無地，野店逢僧每小留。"]'),
('c0db3328-a36e-42c8-8b87-8323e63b261c','久無客至戲作','陸游','宋','宋诗','song-poetry','','[]','瘦影支離雪鬢繁，頻年老病卧孤村。',64,'全唐诗/poet.song.134000.json','["瘦影支離雪鬢繁，頻年老病卧孤村。", "雍容那有客聯騎，剝啄尚無僧扣門。", "濁酒香浮新社甕，晚瓜味敵故侯園。", "茅簷蓬戶風烟晚，小酌欣然對子孫。"]'),
('0a20bf99-2a1d-48fe-8593-2711e13b9e63','乍凉','陸游','宋','宋诗','song-poetry','','[]','凉風蘇病骨，摇落起詩情。',48,'全唐诗/poet.song.134000.json','["凉風蘇病骨，摇落起詩情。", "一病輒數日，幾詩終此生。", "招呼丹竈客，結束玉霄行。", "預想溪橋路，三更待月明。"]'),
('25bfa594-23cd-4c87-8676-ac1142c03728','閑趣','陸游','宋','宋诗','song-poetry','','[]','絕迹市朝外，結廬雲水間。',48,'全唐诗/poet.song.134000.json','["絕迹市朝外，結廬雲水間。", "心平詩淡泊，身退夢安閑。", "有酒旋尋伴，無門那說關。", "桐江故不遠，日暮趁潮還。"]'),
('d5e3d1d1-cae5-40da-9972-dfd1eb224003','溪上','陸游','宋','宋诗','song-poetry','','[]','溪上秋來風露清，蕭然浴罷葛衣輕。',64,'全唐诗/poet.song.134000.json','["溪上秋來風露清，蕭然浴罷葛衣輕。", "看雲舒卷了窮達，見月虧盈知死生。", "老去關心惟藥裹，閑中消日付棋枰。", "故人書札頻相問，何日芒鞋上赤城。"]'),
('71d2fc1b-7569-40b0-88c7-3f8e8c56cf97','秋詞三首  其一','陸游','宋','宋诗','song-poetry','','[]','東吳七月暑未艾，川雲忽興天晝晦。',64,'全唐诗/poet.song.134000.json','["東吳七月暑未艾，川雲忽興天晝晦。", "蔽空雨點弩發機，平地成渠屋穿背。", "早禾玉粒自天瀉，村北村南喧地碓。", "大牲如阜酒如江，相喚龍祠作秋賽。"]'),
('0d44b725-ae6a-4305-b895-dbf2cb3824c1','秋詞三首  其二','陸游','宋','宋诗','song-poetry','','[]','八月暑退凉風生，家家場中打稻聲。',64,'全唐诗/poet.song.134000.json','["八月暑退凉風生，家家場中打稻聲。", "穗多粒飽三倍熟，車軸壓折人肩頳。", "常年縣符鬧如雨，道上即今無吏行。", "鄉閭老稚迭歌舞，竈釜日饜豬羊烹。"]'),
('86b65768-2b88-4e41-a01c-8e66dbd103eb','秋詞三首  其三','陸游','宋','宋诗','song-poetry','','[]','蓐收功成將整駕，萬頃黄雲收晚稼。',64,'全唐诗/poet.song.134000.json','["蓐收功成將整駕，萬頃黄雲收晚稼。", "公私逋負一洗空，懷抱喜看兒婭姹。", "從來婚聘不出鄉，長自東家適西舍。", "年豐人樂我作詩，朝耕夜織誰能畫。"]'),
('f4c471f1-a40c-4b87-8fbb-68c9c478c920','秋思','陸游','宋','宋诗','song-poetry','','[]','詩人本自易悲傷，何况身更憂患場。',64,'全唐诗/poet.song.134000.json','["詩人本自易悲傷，何况身更憂患場。", "烏鵲成橋秋又到，梧桐滴雨夜初凉。", "江南江北堠雙隻，燈暗燈明更短長。", "安得平生會心侶，一尊相屬送年光。"]'),
('8c500602-746a-486c-92fd-1aac317bc64c','老學庵北窗雜書七首  其一','陸游','宋','宋诗','song-poetry','','[]','本慕修真謝俗塵，中年蹭蹬作詩人。',32,'全唐诗/poet.song.134000.json','["本慕修真謝俗塵，中年蹭蹬作詩人。", "即今恨養金丹晚，且向江湖作釣緡。"]'),
('2bcfc624-7f03-426b-95ad-18a6962e3886','老學庵北窗雜書七首  其二','陸游','宋','宋诗','song-poetry','','[]','偶住人間遂許時，殘骸自笑尚支持。',32,'全唐诗/poet.song.134000.json','["偶住人間遂許時，殘骸自笑尚支持。", "直須消破黄齏盡，始是浮生結局時。"]'),
('86cde569-febc-4a47-a7dd-35ac5c37c9b3','老學庵北窗雜書七首  其三','陸游','宋','宋诗','song-poetry','','[]','茅齋遥夜養心君，靜處工夫自策勛。',32,'全唐诗/poet.song.134000.json','["茅齋遥夜養心君，靜處工夫自策勛。", "正喜殘香伴幽獨，鴉鳴窗白又紛紛。"]'),
('4419eb00-41a2-4c85-8798-e50f36991313','老學庵北窗雜書七首  其四','陸游','宋','宋诗','song-poetry','','[]','小龍團與長鷹爪，桑苧玉川俱未知。',32,'全唐诗/poet.song.134000.json','["小龍團與長鷹爪，桑苧玉川俱未知。", "自置風爐北窗下，勒回睡思賦新詩。"]'),
('d7c08f16-a72a-47aa-8525-188d1ec4cc8e','老學庵北窗雜書七首  其五','陸游','宋','宋诗','song-poetry','','[]','定交魚鳥欲忘形，獨岸綸巾坐草亭。',32,'全唐诗/poet.song.134000.json','["定交魚鳥欲忘形，獨岸綸巾坐草亭。", "不恨囊中無赤仄，且欣案上有黄庭。"]'),
('3b09113c-6e4f-49cb-ba32-c00ded3d9e2e','老學庵北窗雜書七首  其六','陸游','宋','宋诗','song-poetry','','[]','松棚接屋得陰多，石徑生苔奈滑何。',32,'全唐诗/poet.song.134000.json','["松棚接屋得陰多，石徑生苔奈滑何。", "盡道疏籬宜細雨，晴時最好晒漁蓑。"]'),
('5c02a881-65b3-4036-8949-3b0a3894edfd','老學庵北窗雜書七首  其七','陸游','宋','宋诗','song-poetry','','[]','龜常曳尾豈非樂，鶴已鎩翎徒自傷。',32,'全唐诗/poet.song.134000.json','["龜常曳尾豈非樂，鶴已鎩翎徒自傷。", "造物今知不負汝，北窗夜雨默焚香。"]'),
('9f08d16c-cda9-4b4a-94ef-a0e434b5bb8b','親舊見過多見賀强健戲作此篇','陸游','宋','宋诗','song-poetry','','[]','偶向人間脫駭機，玉池中夜自生肥。',64,'全唐诗/poet.song.134000.json','["偶向人間脫駭機，玉池中夜自生肥。", "據鞍馬援雖堪笑，强飯廉頗亦未非。", "道貌安能希睟盎，世緣但可付猗違。", "它年不死君須記，會在天津看落暉。"]'),
('f5654257-3354-49cc-8245-9380ca5af374','小病兩日而愈','陸游','宋','宋诗','song-poetry','','[]','病骨羸然山澤臞，故應行路笑形模。',64,'全唐诗/poet.song.134000.json','["病骨羸然山澤臞，故應行路笑形模。", "記書身大似椰子，忍事癭生如瓠壺。", "美酒得錢猶可致，高人折簡孰能呼。", "不如凈掃茅齋地，卧看微香起瓦爐。"]'),
('63ebf94e-4761-43d0-a08b-10e94e13d611','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','修蔓叢篁步步迷，山村東下近魚陂。',64,'全唐诗/poet.song.134000.json','["修蔓叢篁步步迷，山村東下近魚陂。", "釣歸恰值秋風起，棋罷常驚日景移。", "病葉辭枝應有恨，候蟲吟壁故知時。", "殘年我亦悲摇落，薄暮空囊又有詩。"]'),
('1430dbc7-6c1f-43f5-912e-88e59c4f5e50','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','八十仍當過二時，加餐安寢豈前知。',64,'全唐诗/poet.song.134000.json','["八十仍當過二時，加餐安寢豈前知。", "晨梳脫髮雖無數，社甕新醅已有期。", "偶爲買花經廢圃，時因蹋藕下清池。", "尚餘一事終關念，安得兒孫少別離。"]'),
('744a2747-bfc5-4e98-85a0-d7d389c09813','日用四首  其一','陸游','宋','宋诗','song-poetry','','[]','舊好疏毛穎，新知得麴生。',24,'全唐诗/poet.song.134000.json','["舊好疏毛穎，新知得麴生。", "幽居無一事，枕臂聽松聲。"]'),
('4d2abe85-be4e-44a3-a082-d33329fc709e','日用四首  其二','陸游','宋','宋诗','song-poetry','','[]','舂穀灌園蔬，日長閑有餘。',24,'全唐诗/poet.song.134000.json','["舂穀灌園蔬，日長閑有餘。", "何妨忍揮汗，合藥施鄉閭。"]'),
('4f59a6ea-a277-48f4-988e-35646ebcc6a5','日用四首  其三','陸游','宋','宋诗','song-poetry','','[]','貧知藜糝美，渴愛粟漿酸。',24,'全唐诗/poet.song.134000.json','["貧知藜糝美，渴愛粟漿酸。", "食少從奴去，人稀苦屋寬。"]'),
('3496fd0c-ad01-497d-a532-77363bb89aac','日用四首  其四','陸游','宋','宋诗','song-poetry','','[]','空舍封書篋，多年飽蠹魚。',24,'全唐诗/poet.song.134000.json','["空舍封書篋，多年飽蠹魚。", "還家貧不死，讀盡舊藏書。"]'),
('49545b7b-ca4e-4887-81b9-620ce14e1226','七月十一日見落葉','陸游','宋','宋诗','song-poetry','','[]','葉雕非一日，盛夏則已然。',96,'全唐诗/poet.song.134000.json','["葉雕非一日，盛夏則已然。", "一葉復一葉，及此摇落天。", "晨起坐堂上，散若飛鳥翩。", "昔時可藏鴉，今欲不庇蟬。", "顧視庭中草，亦復非阡眠。", "百穀秋皆成，是謂造化權。", "豈爲草木計，而欲求兩全。", "物理貴見微，勇退差爲賢。"]'),
('492d51d3-4603-4931-913b-72014728c910','龜堂一隅開窗設榻爲小憩之地','陸游','宋','宋诗','song-poetry','','[]','栟櫚薝蔔障斜陽，旋置臨階八尺床。',64,'全唐诗/poet.song.134000.json','["栟櫚薝蔔障斜陽，旋置臨階八尺床。", "小展窗扉無大費，略加苫蓋有餘凉。", "老來愈覺歲時速，夢裏不知途路長。", "試問神遊向何處，月明揮榜上瀟湘。"]'),
('b821ff8e-4260-437f-8a3e-2c2bcd547ab0','南門晚眺','陸游','宋','宋诗','song-poetry','','[]','奚奴前負一胡床，門巷楸梧已漸黄。',64,'全唐诗/poet.song.134000.json','["奚奴前負一胡床，門巷楸梧已漸黄。", "不歷塵埃三伏熱，孰知風露九秋凉。", "蕭蕭浦溆漁歌晚，漠漠陂塘稻穗香。", "勿恨行雲吞素月，夢回正愛雨淋浪。"]'),
('2ce5c91b-57c8-4dc8-a6e2-ae502cea80c9','進德','陸游','宋','宋诗','song-poetry','','[]','進德工夫在日新，正如更歷自知津。',64,'全唐诗/poet.song.134000.json','["進德工夫在日新，正如更歷自知津。", "迷時誤認毒爲藥，定後始知天勝人。", "四壁不妨身落魄，萬夫誰敵膽輪囷。", "遺經在匵君毋厭，燈火青熒漸可親。"]'),
('4054ba46-e1af-466b-8bc5-6e70bbdd6c00','次韵邢德允見贈','陸游','宋','宋诗','song-poetry','','[]','人間榮瘁固難窮，歲月推遷即老翁。',64,'全唐诗/poet.song.134000.json','["人間榮瘁固難窮，歲月推遷即老翁。", "馬駿初非凡眼識，源深終與大川通。", "細思渭北希高價，終勝淮南誚發蒙。", "莫學三山頑鈍叟，一生空耗太倉紅。"]'),
('fb2bf09c-3a07-4e02-b808-2c0bcdb5ac3d','秋懷十首  其一','陸游','宋','宋诗','song-poetry','','[]','居在三家聚，門纔一木橫。',48,'全唐诗/poet.song.134000.json','["居在三家聚，門纔一木橫。", "用寬緣歲樂，斂薄爲時平。", "疏樹葉遲落，遠村燈更明。", "題詩雖草草，亦足寫幽情。"]'),
('ba813212-5ba0-4288-8db4-b39618a5a7e2','秋懷十首  其二','陸游','宋','宋诗','song-poetry','','[]','村晚歸牛下，林昏宿鳥喧。',48,'全唐诗/poet.song.134000.json','["村晚歸牛下，林昏宿鳥喧。", "微升天際月，半掩水邊門。", "衣杵悲邊信，漁歌斷客魂。", "老人交舊盡，此意與誰論。"]'),
('57ba3d65-10e3-47ec-9976-df4c1f7bcc12','秋懷十首  其三','陸游','宋','宋诗','song-poetry','','[]','客思殘荷外，農功晚稻前。',48,'全唐诗/poet.song.134000.json','["客思殘荷外，農功晚稻前。", "祭多巫得職，稅足吏無權。", "浦溆家家釣，村墟點點烟。", "歸舟葛衣薄，始覺是秋天。"]'),
('77cd20e2-05b4-45bc-a284-c921d181e238','秋懷十首  其四','陸游','宋','宋诗','song-poetry','','[]','典琴沽市釀，賣劍買吳牛。',48,'全唐诗/poet.song.134000.json','["典琴沽市釀，賣劍買吳牛。", "雞黍隨時具，江山到處留。", "隨僧日一浴，笑吏月三休。", "安得沅湘客，相從賦遠遊。"]'),
('68f8bf03-2c30-45e6-8482-00cec4b8b4cb','秋懷十首  其五','陸游','宋','宋诗','song-poetry','','[]','心常凝不動，形要小勞之。',48,'全唐诗/poet.song.134000.json','["心常凝不動，形要小勞之。", "活火閑煎茗，殘枰靜拾棋。", "曬書朝日出，丸藥晝陰移。", "意適還休去，悠然到睡時。"]'),
('c00aa3eb-bdba-44c1-b1eb-0b8b5a9b5dc8','秋懷十首  其六','陸游','宋','宋诗','song-poetry','','[]','曩得治中俸，湖山偶卜居。',48,'全唐诗/poet.song.134000.json','["曩得治中俸，湖山偶卜居。", "身嘗著禾譜，兒解讀農書。", "遇事絕欣厭，接人均戚疏。", "乾坤雖浩浩，等付一蘧廬。"]'),
('5b177bad-8dc5-4983-aa64-1ff83421196a','秋懷十首  其七','陸游','宋','宋诗','song-poetry','','[]','秋暑雖猶在，晨興氣已清。',48,'全唐诗/poet.song.134000.json','["秋暑雖猶在，晨興氣已清。", "蠻童掃荒徑，獠婢滌空鐺。", "病樹有凋葉，殘蟬無壯聲。", "書生守故態，已復理燈檠。"]'),
('0c71ef8e-5b62-43e0-be1a-ff1a49231179','秋懷十首  其八','陸游','宋','宋诗','song-poetry','','[]','種樹清陰滿，鈔書蠹字穿。',48,'全唐诗/poet.song.134000.json','["種樹清陰滿，鈔書蠹字穿。", "老身猶在世，屈指不知年。", "棄紙儲詩稿，長筒聚藥錢。", "一生如一日，正可付之天。"]'),
('7256e621-285a-4407-84eb-989808b9bdb5','秋懷十首  其九','陸游','宋','宋诗','song-poetry','','[]','望遠目猶明，登高脚更輕。',48,'全唐诗/poet.song.134000.json','["望遠目猶明，登高脚更輕。", "每思遊赤壁，時夢上青城。", "燈下書如蟻，花前飲似鯨。", "古仙曾歷考，强半出儒生。"]'),
('8674ee28-cceb-4036-8556-71f7ce620f0d','秋懷十首  其一○','陸游','宋','宋诗','song-poetry','','[]','昨者風雨過，浩然天地秋。',48,'全唐诗/poet.song.134000.json','["昨者風雨過，浩然天地秋。", "年光雙雪鬢，生計一漁舟。", "賣藥來查浦，聽猿到沃洲。", "平生畏暑毒，八月記初遊。"]'),
('1ddc3b7d-cd86-4cab-a82c-a2bce9551eef','出遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','來往人間不計年，一枝筇竹雪垂肩。',64,'全唐诗/poet.song.134000.json','["來往人間不計年，一枝筇竹雪垂肩。", "掃除身外閑名利，師友書中古聖賢。", "支遁山前饒石水，葛洪井畔慘風烟。", "小癡大黠君無笑，買斷秋光不用錢。"]'),
('ec307b2a-89c8-42f3-b340-96f68598eb67','出遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','行路迢迢入谷斜，繫驢來憩野人家。',64,'全唐诗/poet.song.134000.json','["行路迢迢入谷斜，繫驢來憩野人家。", "山童負擔賣紅果，村女緣籬采碧花。", "篝火就炊朝甑飯，汲泉自煮午甌茶。", "閑遊本自無程數，邂逅何妨一笑譁。"]'),
('824f1719-ddd0-4f4a-8cf3-4ca2da670b05','東窗獨坐書懷','陸游','宋','宋诗','song-poetry','','[]','秋豪外物不關心，竹塢梅村惜未深。',64,'全唐诗/poet.song.134000.json','["秋豪外物不關心，竹塢梅村惜未深。", "蓬戶夜凉燈煜爚，盆山雨潤木蕭森。", "潔齋入靜三熏沐，宴坐降魔七縱擒。", "但恨圖書闕調護，不勝鼠嚙與蟲侵。"]'),
('137b66e7-ff77-42f1-a380-44423b82375e','書嘆','陸游','宋','宋诗','song-poetry','','[]','齊民困衣食，如疲馬思秣。',96,'全唐诗/poet.song.134000.json','["齊民困衣食，如疲馬思秣。", "我欲達其情，疏遠畏强聒。", "有司或苛取，兼并亦豪奪。", "正如橫江網，一舉孰能脫。", "政本在養民，此論豈迂闊。", "我今雖退休，嘗綴廷議末。", "明恩殊未報，敢自同衣褐。", "吾君不可負，願治甚饑渴。"]'),
('b61f4b20-5ffc-470f-9df1-e9600fa158de','荷鋤','陸游','宋','宋诗','song-poetry','','[]','五畝畦蔬地，秋來日荷鋤。',48,'全唐诗/poet.song.134000.json','["五畝畦蔬地，秋來日荷鋤。", "何曾笑爾輩，但覺愛吾廬。", "膽怯沽官釀，瞳昏讀監書。", "區區尚多事，未解雜樵漁。"]'),
('ddfe317f-5867-4be6-9fbc-96c87afd250b','病卧','陸游','宋','宋诗','song-poetry','','[]','老境偏饒卧，秋天不肯晴。',48,'全唐诗/poet.song.134000.json','["老境偏饒卧，秋天不肯晴。", "愁憑書解散，病仗藥支撐。", "果熟鳥烏樂，村深雞犬聲。", "邊頭定何似，頗說募新兵。"]'),
('35cceef5-ec74-40d0-a53a-e6f533925255','秋夜獨坐聞里中鼓吹聲','陸游','宋','宋诗','song-poetry','','[]','收盡浮雲見素娥，青天脈脈映明河。',64,'全唐诗/poet.song.134000.json','["收盡浮雲見素娥，青天脈脈映明河。", "時平里巷吹彈鬧，歲熟人家嫁娶多。", "高會不知清夜永，散歸想見醉顔酡。", "小窗燈火晶熒處，也有人賡七月歌。"]'),
('890aa24f-1b75-4a30-b82b-359d7ee30889','老嘆','陸游','宋','宋诗','song-poetry','','[]','老翁終日飽還嬉，常拾兒童竹馬騎。',64,'全唐诗/poet.song.134000.json','["老翁終日飽還嬉，常拾兒童竹馬騎。", "食爲齒摇艱咀嚼，冠因髮少易傾欹。", "烏烏歌罷人誰問，咄咄書成自不知。", "堪笑殘生似蒲柳，秋風未到已先衰。"]'),
('324e092e-6545-4348-9536-43db769a1a8a','草堂','陸游','宋','宋诗','song-poetry','','[]','南出湖壖有廢堤，草堂只在鸛巢西。',64,'全唐诗/poet.song.134000.json','["南出湖壖有廢堤，草堂只在鸛巢西。", "清風滿榻眠初起，落葉平溝路欲迷。", "新酒已知迎社熟，秋鶯猶作傍簷啼。", "鄰翁相遇饒言笑，共喜年豐米價低。"]'),
('c61eb8af-2e3e-4dbe-bb5b-6877fe629553','齋中讀書罷有感','陸游','宋','宋诗','song-poetry','','[]','少時學問苦匆匆，弦誦光陰轉手空。',64,'全唐诗/poet.song.134000.json','["少時學問苦匆匆，弦誦光陰轉手空。", "聖域淵源雖自力，故交零落與誰同。", "荒村莫恨身垂老，後世元知論自公。", "但掩齋扉憑曲几，忘憂正在寂寥中。"]'),
('537e5c6d-157b-483d-9e30-b20afbeb6112','雨欲作步至浦口','陸游','宋','宋诗','song-poetry','','[]','雨作千山暗，風來萬木號。',96,'全唐诗/poet.song.134000.json','["雨作千山暗，風來萬木號。", "放懷忘世事，徐步出亭皋。", "野處惟知遯，心期不復豪。", "宋清捐善藥，須賈遺綈袍。", "寧乞陶翁食，難餔楚客糟。", "精心窮易老，餘力及莊騷。", "杖屨時行樂，鋤耰慣作勞。", "正令朝夕死，猶足遂吾高。"]'),
('19e0ab53-cb2e-4073-a377-5f860c4a34a5','鏡湖有鳥名水鳧鳴於春夏間若曰打麥作飯偶有所感而作','陸游','宋','宋诗','song-poetry','','[]','人生天地中，賦予各有限。',96,'全唐诗/poet.song.134000.json','["人生天地中，賦予各有限。", "所享過所賦，鮮不貽後患。", "玉食害而家，此語禹所難。", "麥飯勿謂薄，耕時泥及骭。", "土塯竹爲挾，鹽酪調藜莧。", "吾愧人豈知，尚以陋見訕。", "恨亦見事遲，失脚墮名宦。", "千載梁伯鸞，巍然吾無間。"]'),
('102f7b0c-067d-4b28-a3c9-eca8aded9266','自述','陸游','宋','宋诗','song-poetry','','[]','早畏危機避巧丸，長安未到意先闌。',64,'全唐诗/poet.song.134000.json','["早畏危機避巧丸，長安未到意先闌。", "心如老馬雖知路，身似鳴蛙不屬官。", "閑駕柴車無遠近，旋沽村酒半甜酸。", "群兒何足勞情恕，胸次從初抵海寬。"]'),
('c12dd4ad-57f9-42fe-9ee6-9fbaf19d5a40','秋興十二首  其一','陸游','宋','宋诗','song-poetry','','[]','晨興秋色已凄凄，咿喔猶聞隔浦雞。',32,'全唐诗/poet.song.134000.json','["晨興秋色已凄凄，咿喔猶聞隔浦雞。", "說與譍門謝來客，要乘微雨理蔬畦。"]'),
('38f18282-3d4c-4071-b6bd-8e1730cccbd4','秋興十二首  其二','陸游','宋','宋诗','song-poetry','','[]','村酒甜酸市酒渾，猶勝終日對空樽。',32,'全唐诗/poet.song.134000.json','["村酒甜酸市酒渾，猶勝終日對空樽。", "茅齋不奈秋蕭瑟，蹋雨來敲野店門。"]'),
('b4e972f0-b0ac-40a6-9439-0659296f507e','秋興十二首  其三','陸游','宋','宋诗','song-poetry','','[]','囷儲赤米枝梧飯，篋有青氈準擬寒。',32,'全唐诗/poet.song.134000.json','["囷儲赤米枝梧飯，篋有青氈準擬寒。", "政使堆金無處用，不須常貯一錢看。"]'),
('c8cea8cc-c487-456a-9db6-4f79a29793f4','秋興十二首  其四','陸游','宋','宋诗','song-poetry','','[]','病起殘骸不自支，旋烹藜粥解饑羸。',32,'全唐诗/poet.song.134000.json','["病起殘骸不自支，旋烹藜粥解饑羸。", "一編蠹簡青燈下，恰似吳僧夜講時。"]'),
('7b8cac3b-2460-42b6-b1bf-fdc8847648cb','秋興十二首  其五','陸游','宋','宋诗','song-poetry','','[]','莫笑門庭草棘荒，也能隨事答年光。',32,'全唐诗/poet.song.134000.json','["莫笑門庭草棘荒，也能隨事答年光。", "半瓶野店沽醇碧，一畚鄰園餉矮黄。"]'),
('5210f12d-430a-45d2-ade8-b54249738609','秋興十二首  其六','陸游','宋','宋诗','song-poetry','','[]','白頭韭美腌齏熟，頳尾魚鮮斫鱠成。',32,'全唐诗/poet.song.134000.json','["白頭韭美腌齏熟，頳尾魚鮮斫鱠成。", "却對盤餐三太息，老年一飽費經營。"]'),
('fc537b04-8115-427c-ab3d-e509b234f2d4','秋興十二首  其七','陸游','宋','宋诗','song-poetry','','[]','淹速從來但信緣，襟懷無日不超然。',32,'全唐诗/poet.song.134000.json','["淹速從來但信緣，襟懷無日不超然。", "喚船渡口因閑立，待飯僧床得暫眠。"]'),
('113c310d-1181-481f-b83a-33590bac3f44','秋興十二首  其八','陸游','宋','宋诗','song-poetry','','[]','懲羹吹齏豈其非，亡羊補牢理所宜。',32,'全唐诗/poet.song.134000.json','["懲羹吹齏豈其非，亡羊補牢理所宜。", "白頭始訪金丹術，莫笑龜堂見事遲。"]'),
('b123be0d-44bb-46d8-a50f-8d09512483af','秋興十二首  其九','陸游','宋','宋诗','song-poetry','','[]','赫赫能令京兆死，沾沾正坐魏其愚。',32,'全唐诗/poet.song.134000.json','["赫赫能令京兆死，沾沾正坐魏其愚。", "何如陸子山行樂，臚膊常懸酒一壺。"]'),
('40ee058e-dddf-49b5-a160-f9fd8ad11f36','秋興十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','放翁老矣欲何之，采藥名山更不疑。',32,'全唐诗/poet.song.134000.json','["放翁老矣欲何之，采藥名山更不疑。", "但入剡中行百里，姓名顔狀有誰知。"]'),
('80202596-7735-43b7-997a-f7a29f9ceac1','秋興十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','樵客高僧兩斷蓬，偶同烟榜泛秋風。',32,'全唐诗/poet.song.134000.json','["樵客高僧兩斷蓬，偶同烟榜泛秋風。", "栖賢雪夜匆匆別，豈意相逢在剡中。"]'),
('17f20fec-abe8-4723-95e5-8e5bc254b0f8','秋興十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','鼉鼓華鯨響寺廊，殘蕪落葉弄秋光。',32,'全唐诗/poet.song.134000.json','["鼉鼓華鯨響寺廊，殘蕪落葉弄秋光。", "蹇驢繫著門前柳，閑覓題名拂敗牆。"]'),
('883aa53d-b7bb-4e31-92d8-e8b1ed9ca29c','秋夕書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','秋夕初多露，漁家半掩扉。',48,'全唐诗/poet.song.134000.json','["秋夕初多露，漁家半掩扉。", "鵲飛山月出，犬吠市船歸。", "影瘦悲形瘁，冠偏感髮稀。", "眼中無宿士，老我欲疇依。"]'),
('f10f60da-eb15-4fba-b16b-8f8a58376c09','秋夕書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','寂寂青楓岸，蕭蕭白版扉。',48,'全唐诗/poet.song.134000.json','["寂寂青楓岸，蕭蕭白版扉。", "端居常懶動，偶出却忘歸。", "時泰徵科簡，師還驛置稀。", "江村日無事，烟火自相依。"]'),
('cba586b5-9034-4e8f-9b8a-6624c0239c48','薄粥','陸游','宋','宋诗','song-poetry','','[]','薄粥枝梧未死身，饑腸且免轉車輪。',32,'全唐诗/poet.song.134000.json','["薄粥枝梧未死身，饑腸且免轉車輪。", "從來不解周家意，養老常須祝骾人。"]'),
('2879c628-d1ed-4070-a367-4aae51cf8d6e','拄杖','陸游','宋','宋诗','song-poetry','','[]','吾嘗評拄杖，妙處在輕堅。',24,'全唐诗/poet.song.134000.json','["吾嘗評拄杖，妙處在輕堅。", "何日提携汝，同登入峽船。"]'),
('2186000a-8455-49b5-9422-5c05a519d318','小筑二首  其一','陸游','宋','宋诗','song-poetry','','[]','小筑清溪尾，蕭森萬竹蟠。',48,'全唐诗/poet.song.134000.json','["小筑清溪尾，蕭森萬竹蟠。", "庵廬雖偪仄，庭戶亦平寬。", "摘果觀猿哺，開籠放鶴盤。", "澹然還過日，無處著悲歡。"]'),
('b2c48846-209c-44d9-8910-6f8f884143ad','小筑二首  其二','陸游','宋','宋诗','song-poetry','','[]','小筑隨高下，園池皆自然。',48,'全唐诗/poet.song.134000.json','["小筑隨高下，園池皆自然。", "鋤山得靈藥，斸坎遇寒泉。", "幽檻花房斂，深林果蒂駢。", "鄰翁亦好事，相伴送流年。"]'),
('9c292de4-43d0-4c10-b306-13e8cb2f664d','一編','陸游','宋','宋诗','song-poetry','','[]','一編垂首北窗前，皎皎寧當逐物遷。',64,'全唐诗/poet.song.134000.json','["一編垂首北窗前，皎皎寧當逐物遷。", "道有廢興何與我，心無愧怍始知天。", "昔嘗西戍八千里，今復東歸三十年。", "死去雖無勳業事，九原猶可見先賢。"]'),
('ba3beddc-74d2-4ba3-9cdb-e99da8a6e4fe','埭北','陸游','宋','宋诗','song-poetry','','[]','烟村湖埭北，魚市廟壖東。',48,'全唐诗/poet.song.134000.json','["烟村湖埭北，魚市廟壖東。", "急雨時時作，輕舟浦浦通。", "薪芻聚津口，簫鼓鬧林中。", "烏桕禁愁得，來朝數葉紅。"]'),
('d6125c68-e434-45b0-a0b9-077999aa8e5e','風雨','陸游','宋','宋诗','song-poetry','','[]','殘暑時當盡，清風勢自回。',48,'全唐诗/poet.song.134000.json','["殘暑時當盡，清風勢自回。", "重雲韞日月，大雨挾風雷。", "老樹不自保，毀巢吁可哀。", "却愁新雁到，暮境更禁催。"]'),
('00ff7696-1d08-4f66-ad11-53add8e52d3f','解嘲','陸游','宋','宋诗','song-poetry','','[]','心如頑石忘榮辱，身似孤雲任去留。',32,'全唐诗/poet.song.134000.json','["心如頑石忘榮辱，身似孤雲任去留。", "酒甕飯囊君勿誚，也勝滿腹貯閑愁。"]'),
('4e77e6df-2bee-4272-b8f3-3e50748ade58','識喜','陸游','宋','宋诗','song-poetry','','[]','本自怕沾京洛塵，固應不吐相君茵。',64,'全唐诗/poet.song.135000.json','["本自怕沾京洛塵，固應不吐相君茵。", "偶逃鼉作鯨吞地，幸保詩狂酒病身。", "傲世曾歌楚人鳳，著書久絕魯郊麟。", "山村且試筇枝興，風月秋來正一新。"]'),
('5dae32f0-271f-4b54-b282-52416789192f','寓興','陸游','宋','宋诗','song-poetry','','[]','窮巷無來客，秋風獨浩歌。',48,'全唐诗/poet.song.135000.json','["窮巷無來客，秋風獨浩歌。", "壯年閑處老，佳日病中過。", "甚欲携長鑱，仍思擁短蓑。", "逢山皆可隱，不必上三峨。"]'),
('c1f5590f-9bad-4e81-864d-6e740405d52e','老馬行','陸游','宋','宋诗','song-poetry','','[]','老馬虺隤依晚照，自計豈堪三品料。',64,'全唐诗/poet.song.135000.json','["老馬虺隤依晚照，自計豈堪三品料。", "玉鞭金絡付夢想，瘦稗枯萁空咀噍。", "中原蝗旱胡運衰，王師北伐方傳詔。", "一聞戰鼓意氣生，猶能爲國平燕趙。"]'),
('31890abe-a1c9-49da-a2d5-8234c0943a39','農家','陸游','宋','宋诗','song-poetry','','[]','吳農耕澤澤，吳牛耳溼溼。',120,'全唐诗/poet.song.135000.json','["吳農耕澤澤，吳牛耳溼溼。", "農功何崇崇，農事常汲汲。", "冬休筑陂防，丁壯皆雲集。", "春耕人在野，農具已山立。", "房櫳鳴機杼，烟雨暗蓑笠。", "尺薪仰有取，斷履俯有拾。", "洪水昔滔天，得禹民乃粒。", "食不知所從，汝悔將何及。", "孩提同一初，勤惰在所習。", "周公有遺訓，請視七月什。"]'),
('53150aea-3a7e-4463-aada-cd54c5d218bb','對酒作','陸游','宋','宋诗','song-poetry','','[]','齒落不廢嚼，足跛尚能履。',72,'全唐诗/poet.song.135000.json','["齒落不廢嚼，足跛尚能履。", "書生之所遭，僥倖有如此。", "自知窮事業，元不直杯水。", "徒行若車安，蔬食如肉美。", "或時得斗酒，亦復招鄰里。", "不肯歌烏烏，行矣呼起起。"]'),
('00bbd6e4-544d-40b3-b759-61f6c7066893','秋分後頓凄冷有感','陸游','宋','宋诗','song-poetry','','[]','今年秋氣早，木落不待黄。',72,'全唐诗/poet.song.135000.json','["今年秋氣早，木落不待黄。", "蟋蟀當在宇，遽已近我床。", "况我老當逝，且復小彷徉。", "豈無一樽酒，亦有書在傍。", "飲酒讀古書，慨然想黄唐。", "耄矣狂未除，誰能藥膏肓。"]'),
('067492ef-5967-4690-ba13-44c96ce4578f','即事示子遹','陸游','宋','宋诗','song-poetry','','[]','四十已悲非少年，耄期何事每歡然。',64,'全唐诗/poet.song.135000.json','["四十已悲非少年，耄期何事每歡然。", "遊山夜雨眠僧院，沽酒秋風上釣船。", "諸友詩章來亹亹，小兒筆勢亦翩翩。", "眼邊不是常蕭索，終憶巢居訪老仙。"]'),
('b9642253-1143-4ee3-a092-32c3c732f04c','醉中絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','有山有水登臨地，無病無愁嘯傲身。',32,'全唐诗/poet.song.135000.json','["有山有水登臨地，無病無愁嘯傲身。", "世念秋毫除未盡，麴生應恨白頭新。"]'),
('d1bff258-9baa-4e88-96da-6a2b25c1f75d','醉中絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','左餐右粥年年飽，南陌東阡處處閑。',32,'全唐诗/poet.song.135000.json','["左餐右粥年年飽，南陌東阡處處閑。", "幸免催租敗幽興，豈容對酒惜酡顔。"]'),
('f5d2b8b8-d659-4eef-a5fd-85f757addaff','種麥','陸游','宋','宋诗','song-poetry','','[]','墾地播宿麥，飯牛臨野池。',48,'全唐诗/poet.song.135000.json','["墾地播宿麥，飯牛臨野池。", "未能貪佛日，正恐失農時。", "矻矻鋤耰力，勤勤祝史辭。", "嘉平得三白，吾飽豈無期。"]'),
('84358543-f854-486b-ab36-79f5da121cd5','秋晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','梧桐落井床，蟋蟀在書堂。',48,'全唐诗/poet.song.135000.json','["梧桐落井床，蟋蟀在書堂。", "徂歲聿云暮，攬衣慨以慷。", "一生常蹭蹬，萬事略更嘗。", "賴有銘心語，南華論坐忘。"]'),
('43135a49-34be-4a75-9ace-7d8d6ce779aa','秋晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','身世呻吟裏，園廬寂寞中。',48,'全唐诗/poet.song.135000.json','["身世呻吟裏，園廬寂寞中。", "家貧憂酒券，才盡畏詩筒。", "陂水潴猶滿，山苗穫欲空。", "兒孫更力作，勿愧禹遺風。"]'),
('0ca1ecde-01cd-4daf-93ce-ebae3d5170ac','秋穫後即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','多稼如雲接百城，村村鼓樂賽西成。',64,'全唐诗/poet.song.135000.json','["多稼如雲接百城，村村鼓樂賽西成。", "頓寬公賦私逋責，一洗兒啼婦嘆聲。", "社酒粥醲供晚酌，秋菰玉潔芼晨烹。", "放翁醉飽摩便腹，自炙毫甌試雪坑。"]'),
('652660cf-78d0-46b5-98b3-a107e09b5496','秋穫後即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','秋穫春耕力尚餘，雨中襏襫種寒蔬。',64,'全唐诗/poet.song.135000.json','["秋穫春耕力尚餘，雨中襏襫種寒蔬。", "筑居正可茨生草，出市何妨借蹇驢。", "老境朝晡數匙飯，腐儒生死一編書。", "敲門忽有岷山使，慚愧交情未作疏。"]'),
('7569d8c1-1a4c-411b-b0bd-d48f381c46b0','行飯至湖上','陸游','宋','宋诗','song-poetry','','[]','行飯消摇日有常，青鞋又到古祠傍。',64,'全唐诗/poet.song.135000.json','["行飯消摇日有常，青鞋又到古祠傍。", "殘蕪滿路無多綠，落葉投空不待黄。", "只道詩書能發冢，豈知博簺亦亡羊。", "此身只合都無事，時向湖橋看戲場。"]'),
('2bb20c70-4a5e-490b-b424-8241f6d652d1','晨出','陸游','宋','宋诗','song-poetry','','[]','昧爽睡饜足，起扶藜杖行。',48,'全唐诗/poet.song.135000.json','["昧爽睡饜足，起扶藜杖行。", "關山開曉色，草木度秋聲。", "市晚船初發，奴勤地已耕。", "道邊多野菜，小摘助晨烹。"]'),
('472e1f9e-8758-4ca1-b1c5-0290d828fd53','老境','陸游','宋','宋诗','song-poetry','','[]','一生幸免踐危機，老境還山飽蕨薇。',64,'全唐诗/poet.song.135000.json','["一生幸免踐危機，老境還山飽蕨薇。", "智士固知窮有命，達人元謂死爲歸。", "臨窗蜀紙謄詩草，出戶郿縧繫褐衣。", "堪笑街頭小兒女，問予君是伯休非。"]'),
('3f19a611-f1c7-4dbc-9079-6fc7bf384b77','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔梁州夜枕戈，東歸如此壯心何。',64,'全唐诗/poet.song.135000.json','["憶昔梁州夜枕戈，東歸如此壯心何。", "蹉跎已失邯鄲步，悲壯空傳敕勒歌。", "今日扁舟釣烟水，當時重鎧渡冰河。", "自憐一覺寒窗夢，尚想浯溪石可磨。"]'),
('6cce35f0-9c60-468d-a93f-f6c199fcdb74','自嘲','陸游','宋','宋诗','song-poetry','','[]','清心不醉猩猩酒，省事那營燕燕巢。',32,'全唐诗/poet.song.135000.json','["清心不醉猩猩酒，省事那營燕燕巢。", "惟有著書殊未厭，暮年鐵硯亦成凹。"]'),
('5afff98d-f665-4634-8040-d55a5dd52866','解嘲','陸游','宋','宋诗','song-poetry','','[]','我生學語即耽書，萬卷縱橫眼欲枯。',32,'全唐诗/poet.song.135000.json','["我生學語即耽書，萬卷縱橫眼欲枯。", "莫道終身作魚蠹，爾來書外有工夫。"]'),
('f05133da-f399-4fb9-8468-d2bee4ef9c51','新寒','陸游','宋','宋诗','song-poetry','','[]','小雨戒新寒，衡茆已怯寬。',48,'全唐诗/poet.song.135000.json','["小雨戒新寒，衡茆已怯寬。", "甑香炊紫角，門靜挂黄團。", "扶杖穿茶塢，移舟傍釣灘。", "欲知秋有信，霜鬢不勝繁。"]'),
('42d9ef79-7fe1-42e4-9af0-42366eca3509','夜歸','陸游','宋','宋诗','song-poetry','','[]','野店晡炊飯，溪橋夜據鞍。',48,'全唐诗/poet.song.135000.json','["野店晡炊飯，溪橋夜據鞍。", "天回河絡角，海闊斗闌干。", "牧舍牛生犢，蔬園犬逐獾。", "今年時序早，九月已清寒。"]'),
('2753ef99-64e9-48b6-b42e-1cc768c3151f','夢中作','陸游','宋','宋诗','song-poetry','','[]','萬里行求藥，三生誓棄官。',48,'全唐诗/poet.song.135000.json','["萬里行求藥，三生誓棄官。", "鶴巢投暮宿，松麨續朝餐。", "進火金丹熟，凌風玉宇寒。", "人間日月速，歲曆又將殘。"]'),
('b133cabd-c4d5-404f-8af7-09486364d77d','自勵','陸游','宋','宋诗','song-poetry','','[]','中年已懼小人歸，况是駸駸耄及時。',64,'全唐诗/poet.song.135000.json','["中年已懼小人歸，况是駸駸耄及時。", "氣惰欲歸思友助，學衰不進賴兒規。", "無功追愧清時祿，有命何憂晚節饑。", "羸病今年能未死，潜心更下董生帷。"]'),
('059720c0-9996-469c-b5c7-61f98adb5df4','九月一日未明起坐','陸游','宋','宋诗','song-poetry','','[]','病骨清羸八十餘，空齋凄冷五更初。',64,'全唐诗/poet.song.135000.json','["病骨清羸八十餘，空齋凄冷五更初。", "忽聞雲表新來雁，起讀燈前未竟書。", "坐久屢傳雞喔喔，夢殘猶化蝶蘧蘧。", "農功漸畢身無事，約束家童種晚蔬。"]'),
('a916c587-1a30-4cbd-8f66-f6c9f1227b62','小疾偶書','陸游','宋','宋诗','song-poetry','','[]','書生本願致時康，自怪秋來疾在床。',64,'全唐诗/poet.song.135000.json','["書生本願致時康，自怪秋來疾在床。", "胸次豈無醫國策，囊中幸有活人方。", "但知元氣爲根本，正使長生亦粃糠。", "豎子何勞一除掃，區區猶欲恃膏肓。"]'),
('3556fa1a-5835-4d68-9849-ead93cfe4dc6','初寒晨起','陸游','宋','宋诗','song-poetry','','[]','推枕悠然起，寒燈誰與同。',48,'全唐诗/poet.song.135000.json','["推枕悠然起，寒燈誰與同。", "曉窗俄已白，宿火尚能紅。", "老境呻吟外，年華寂寞中。", "長饑亦可恨，聊復固吾窮。"]'),
('0e2445fd-9c8f-4d1a-81e8-e5506a8604a8','霜降前四日頗寒','陸游','宋','宋诗','song-poetry','','[]','草木初黄落，風雲屢闔開。',48,'全唐诗/poet.song.135000.json','["草木初黄落，風雲屢闔開。", "兒童鋤麥罷，鄰里賽神回。", "鷹擊喜霜近，鸛鳴知雨來。", "盛衰君勿嘆，已有復然灰。"]'),
('efd96a10-390b-450a-a890-d67f1849c39e','題驛壁','陸游','宋','宋诗','song-poetry','','[]','輪囷古柳驛門前，糴米歸遲突未烟。',32,'全唐诗/poet.song.135000.json','["輪囷古柳驛門前，糴米歸遲突未烟。", "隨計入都今四紀，驢寒僕瘦只依然。"]'),
('3ab2deaf-24d1-4f7c-b169-1afe074dc08d','閑遊','陸游','宋','宋诗','song-poetry','','[]','大冠長劍已焉哉，短褐禿巾歸去來。',64,'全唐诗/poet.song.135000.json','["大冠長劍已焉哉，短褐禿巾歸去來。", "五世業儒書有種，一生任運仕無媒。", "麥經小雨家家下，菊著新霜處處開。", "自笑閑遊心未歇，青鞋蹋碎白雲堆。"]'),
('036400ff-e7b1-49f9-a1b2-c205bb6c6667','貧舍寫興二首  其一','陸游','宋','宋诗','song-poetry','','[]','深山木食猶堪飽，上古巢居亦自安。',32,'全唐诗/poet.song.135000.json','["深山木食猶堪飽，上古巢居亦自安。", "麥飯草廬吾已過，故應高卧有餘歡。"]'),
('9c4eaf5f-ec51-48dc-ac3a-738b1ff6ac69','貧舍寫興二首  其二','陸游','宋','宋诗','song-poetry','','[]','粲粲新霜縞瓦溝，離離寒菜入盤羞。',32,'全唐诗/poet.song.135000.json','["粲粲新霜縞瓦溝，離離寒菜入盤羞。", "贅童擁篲掃枯葉，聵婢挑燈縫破裘。"]'),
('ad9c17de-01af-4dc1-8632-b45913ba8e1c','秋晚雨中作','陸游','宋','宋诗','song-poetry','','[]','新雁南來歲又殘，蕭蕭風雨暗江干。',64,'全唐诗/poet.song.135000.json','["新雁南來歲又殘，蕭蕭風雨暗江干。", "客疏似悉爾來病，酒薄不禁如許寒。", "草絡籬頭花尚碧，樹當浦口葉初丹。", "醉來且擁黄紬睡，莫問何時后土乾。"]'),
('e08a71e2-6cd3-460f-b84c-3b27fb196d25','待旦','陸游','宋','宋诗','song-poetry','','[]','晨光殘淡月，急點殺寒更。',48,'全唐诗/poet.song.135000.json','["晨光殘淡月，急點殺寒更。", "歷歷記孤夢，悠悠带宿酲。", "攬衣推枕起，亂髮繞床行。", "嘆息人間事，還隨初日生。"]'),
('2d5a4ed2-1df0-4b30-b5f0-8510032eef3d','夜意','陸游','宋','宋诗','song-poetry','','[]','浮雲掃盡天如水，十里疏鐘到野堂。',64,'全唐诗/poet.song.135000.json','["浮雲掃盡天如水，十里疏鐘到野堂。", "窗紙月明人不睡，屋茅霜冷夜初長。", "歸休固已師沮溺，承學猶能陋漢唐。", "安得子孫常念此，不妨世世業耕桑。"]'),
('4aeb5f2d-7a27-420d-88ee-0c8084a65566','湖村','陸游','宋','宋诗','song-poetry','','[]','四十來居湖上村，翩翩七見改初元。',64,'全唐诗/poet.song.135000.json','["四十來居湖上村，翩翩七見改初元。", "風梢解籜竹過母，露葉成陰桐有孫。", "渴鹿出林窺藥井，馴鷗掠水傍棋軒。", "老人不用誇頑健，時看孫曾浴畫盆。"]'),
('175b7481-33f9-46d7-b5f8-5b86076fc45b','連夕熟睡戲書','陸游','宋','宋诗','song-poetry','','[]','投幘塵機息，捐書困味長。',48,'全唐诗/poet.song.135000.json','["投幘塵機息，捐書困味長。", "早眠猶有日，晚起已無霜。", "蝶入三更枕，龜搘八尺床。", "昏昏君莫笑，差勝醉爲鄉。"]'),
('e00e4600-9727-4871-a559-945c680b1617','小軒','陸游','宋','宋诗','song-poetry','','[]','碪杵聲中去日遒，小軒風露一簾秋。',32,'全唐诗/poet.song.135000.json','["碪杵聲中去日遒，小軒風露一簾秋。", "人間走遍心如石，分付寒螿替說愁。"]'),
('538a8819-9f09-437a-b7a2-32d6c3cd8d15','曉寒','陸游','宋','宋诗','song-poetry','','[]','悠悠殘夢伴殘更，萬木風號曉氣清。',64,'全唐诗/poet.song.135000.json','["悠悠殘夢伴殘更，萬木風號曉氣清。", "雞唱欲闌聞井汲，月痕漸淺覺窗明。", "突烟騰碧炊初動，衣焙堆紅火已生。", "小閤翻書裘褐暖，早朝霜滑愧公卿。"]'),
('815d2e44-64c1-4bc9-9208-7547490cf83b','次韵朝陵葉院察見寄','陸游','宋','宋诗','song-poetry','','[]','憶昨翩然別眾仙，秋風吹鬢感凋年。',64,'全唐诗/poet.song.135000.json','["憶昨翩然別眾仙，秋風吹鬢感凋年。", "虛齋無復客滿座，敗橐空餘詩百篇。", "高誼未忘林下約，清吟重結社中緣。", "不教落在塵埃地，萬頃烟波一釣船。"]'),
('816c0544-a4e3-4d09-bd08-bd475c0d664d','書意','陸游','宋','宋诗','song-poetry','','[]','巢山遠下溼，止酒謝中乾。',48,'全唐诗/poet.song.135000.json','["巢山遠下溼，止酒謝中乾。", "粗得養生妙，孰能非意干。", "挂冠身始貴，屏藥疾方安。", "自笑猶多事，時時把釣竿。"]'),
('1b00d458-dcd2-4deb-90e7-44a43b4f7ad5','九月下旬即事','陸游','宋','宋诗','song-poetry','','[]','霜晚知蕎熟，山寒喜酒醲。',48,'全唐诗/poet.song.135000.json','["霜晚知蕎熟，山寒喜酒醲。", "黄絲聽夜織，赤米看晨舂。", "儲藥扶持老，收薪準備冬。", "兒扶還客拜，顧影嘆龍鍾。"]'),
('2e40d4a3-e25d-481e-a782-f98ad83185e2','城南','陸游','宋','宋诗','song-poetry','','[]','城南亭榭鎖閑坊，孤鶴歸飛只自傷。',32,'全唐诗/poet.song.135000.json','["城南亭榭鎖閑坊，孤鶴歸飛只自傷。", "塵漬苔侵數行墨，爾來誰爲拂頹牆。"]'),
('bda75017-39f5-4b10-beb7-a381646f0205','舟中記夢','陸游','宋','宋诗','song-poetry','','[]','石帆山下一漁翁，風雨蕭蕭卧短篷。',32,'全唐诗/poet.song.135000.json','["石帆山下一漁翁，風雨蕭蕭卧短篷。", "幽夢覺時還自笑，閬州城北看蠶叢。"]'),
('f1b5ab19-9ac0-44fb-a9e9-c84492629c88','送周郎','陸游','宋','宋诗','song-poetry','','[]','我居山陰古大澤，四顧茫茫烟水白。',128,'全唐诗/poet.song.135000.json','["我居山陰古大澤，四顧茫茫烟水白。", "平時轍迹所不到，玉樹郎君肯來客。", "衡門僅可俯首過，陋室真成容膝迮。", "木盤設食菜數箸，共飽知君不予責。", "期年相從無夜旦，一日復有千里隔。", "送君津頭泪如綆，老身恨不生羽翮。", "江湖道嶮非一二，觸處兢畏真良策。", "從今日望平安書，我欲燈前手親拆。"]'),
('ce05b8f6-1fcf-41e2-a9eb-d3bfc8635761','村舍得近報有感','陸游','宋','宋诗','song-poetry','','[]','莫謂山村僻，時聞詔令傳。',48,'全唐诗/poet.song.135000.json','["莫謂山村僻，時聞詔令傳。", "寬民除宿負，募士戍新邊。", "霜重瓦欲裂，月明人少眠。", "殘年抱遺恨，終愧祖生鞭。"]'),
('7138b8e1-dbd5-4471-9d2a-9057c14dd6bb','貧嘆','陸游','宋','宋诗','song-poetry','','[]','老叟年年病，書生世世貧。',48,'全唐诗/poet.song.135000.json','["老叟年年病，書生世世貧。", "盜寧窺破橐，雀亦棄空囷。", "屋壞須撐拄，衣穿厭補紉。", "今朝風日美，且復過比鄰。"]'),
('92db0bd8-3c37-4995-b255-a387b7036544','明日復作一首自解','陸游','宋','宋诗','song-poetry','','[]','霜寒衣絮薄，日暮爨烟微。',48,'全唐诗/poet.song.135000.json','["霜寒衣絮薄，日暮爨烟微。", "冀北馬空老，遼東鶴幸歸。", "飄零舊交少，衰疾壯心違。", "每顧兒童笑，吾貧未解圍。"]'),
('285c8df5-6764-4968-aaf4-08382fc6d9b5','子虡調官行在寓{飠茲}團巷初冬遽寒甚作兩絕句寄之  其一','陸游','宋','宋诗','song-poetry','','[]','歲晚江湖行路難，一樽何日共開顔。',35,'全唐诗/poet.song.135000.json','["歲晚江湖行路難，一樽何日共開顔。", "汝方僵卧{飠茲}團巷，我亦饑吟飯顆山。"]'),
('03a37732-4125-4a0d-9763-69d09ecc590e','子虡調官行在寓{飠茲}團巷初冬遽寒甚作兩絕句寄之  其二','陸游','宋','宋诗','song-poetry','','[]','知汝彈冠意易闌，苦貧未免覓微官。',35,'全唐诗/poet.song.135000.json','["知汝彈冠意易闌，苦貧未免覓微官。", "{飠茲}團巷口殘燈火，愁絕霜風十月寒。"]'),
('352bd543-9d53-4125-bc9d-4f3e5ac2fc1f','初冬步至東村','陸游','宋','宋诗','song-poetry','','[]','八月風吹粳稻香，九月蕎熟天始霜。',64,'全唐诗/poet.song.135000.json','["八月風吹粳稻香，九月蕎熟天始霜。", "男耕女饁常滿野，宿麥覆塊皆蒼蒼。", "豐年比屋喜迎客，花底何曾酒杯迮。", "家人但覓浩歌聲，不在東阡在南陌。"]'),
('7411d09d-4b58-4d9c-a997-e645a3aec3f9','南門散策二首  其一','陸游','宋','宋诗','song-poetry','','[]','結宇溪一曲，兩山左右之。',72,'全唐诗/poet.song.135000.json','["結宇溪一曲，兩山左右之。", "橫木以爲門，斷竹作短籬。", "本無剝啄客，門牡固不施。", "甃路壞莫補，石罅生棘茨。", "野蔓不知名，丹實何纍纍。", "村童摘不訶，吾亦愛吾兒。"]'),
('a4fff71a-8b2e-4dd0-9bff-bb9bd75a57fa','南門散策二首  其二','陸游','宋','宋诗','song-poetry','','[]','槐楸陰最茂，秋晚惟空枝。',72,'全唐诗/poet.song.135000.json','["槐楸陰最茂，秋晚惟空枝。", "今日晴無風，散步適其宜。", "右扶青溪杖，左挾斜川詩。", "石琢四腰鼓，可以休我疲。", "清言出正始，不雜世論卑。", "野僧何處來，成此一段奇。"]'),
('b7496495-5600-487c-8ba4-78d86fc141b3','思北鄰韓三翁西鄰因庵主南鄰章老秀才二首  其一','陸游','宋','宋诗','song-poetry','','[]','韓翁生不識官府，半醉長歌老烟浦。',64,'全唐诗/poet.song.135000.json','["韓翁生不識官府，半醉長歌老烟浦。", "因師老乃學長齋，白飯青蔬自炊煮。", "二君要是可喜人，未嘗一語欺其鄰。", "有過無過姑置之，後生孰能如此真。"]'),
('110e9229-923b-41ea-b4b7-b390fae7157b','思北鄰韓三翁西鄰因庵主南鄰章老秀才二首  其二','陸游','宋','宋诗','song-poetry','','[]','鄉閭耆宿非復前，老章病死今三年。',64,'全唐诗/poet.song.135000.json','["鄉閭耆宿非復前，老章病死今三年。", "朝來出門爲太息，不見此翁催社錢。", "我比翁雖差識字，向來推擇嘗爲吏。", "事功自計無一毫，尚不如翁終日醉。"]'),
('a0762100-d8f6-4431-a8fc-a7f2d6b85f68','二毀','陸游','宋','宋诗','song-poetry','','[]','茶杯得之久，石硯日在前。',72,'全唐诗/poet.song.135000.json','["茶杯得之久，石硯日在前。", "一朝忽墜地，質毀不復全。", "附著以膠漆，入用更可憐。", "杯猶奉飲啜，硯不廢磨研。", "向使遂破碎，亦當歸之天。", "動心則不可，此物何足捐。"]'),
('b1ae26ea-f371-44b2-b9d5-34c1c0bc477a','大風不能出戶','陸游','宋','宋诗','song-poetry','','[]','昨日欲出病見留，今日可出風復作。',64,'全唐诗/poet.song.135000.json','["昨日欲出病見留，今日可出風復作。", "室虛窗白爐火暖，閉戶幸有圖書樂。", "一杯淡粥飽則已，下箸豈復思藜藿。", "山禽念我太寂寥，故作叩門聲剝啄。"]'),
('6be91567-7866-476c-acf5-9a838cb01438','晚菊','陸游','宋','宋诗','song-poetry','','[]','蒲柳如懦夫，望秋已凋黄。',72,'全唐诗/poet.song.135000.json','["蒲柳如懦夫，望秋已凋黄。", "菊花如志士，過時有餘香。", "眷言東籬下，數株弄秋光。", "粲粲滋夕露，英英傲晨霜。", "高人寄幽情，采以泛酒觴。", "投分真耐久，歲晚歸枕囊。"]'),
('dae27ee1-00f7-4e62-b419-cb1f2304f785','舍南雜興三首  其一','陸游','宋','宋诗','song-poetry','','[]','淅淅暮風生，暉暉殘月明。',48,'全唐诗/poet.song.135000.json','["淅淅暮風生，暉暉殘月明。", "開門喜閑望，扶杖得徐行。", "霜薄樹多綠，泉流溝有聲。", "兒童殊可念，畫地作棋枰。"]'),
('f28de2c1-b971-45eb-b7f3-892c4b6986c7','舍南雜興三首  其二','陸游','宋','宋诗','song-poetry','','[]','莎徑依山曲，柴扉並水開。',48,'全唐诗/poet.song.135000.json','["莎徑依山曲，柴扉並水開。", "不因行藥出，即爲覓詩來。", "戒婢挑蔬甲，催兒斸芋魁。", "隨宜也能飽，漂母未須哀。"]'),
('85d7b697-4408-435f-97b3-bef3f532c31a','舍南雜興三首  其三','陸游','宋','宋诗','song-poetry','','[]','麻菽連枝熟，柴荆盡日關。',48,'全唐诗/poet.song.135000.json','["麻菽連枝熟，柴荆盡日關。", "臨池驚鷺起，倚柱待雲還。", "倦憩石腰鼓，行携銅博山。", "老人無定意，所到即開顔。"]'),
('2c3d23d2-857d-4e92-a8ad-932afbb29ef5','自詒二首  其一','陸游','宋','宋诗','song-poetry','','[]','足蹇須人慣，顔衰著黶多。',48,'全唐诗/poet.song.135000.json','["足蹇須人慣，顔衰著黶多。", "飯遲惟靜卧，酒至亦高歌。", "蝗死繁蔬甲，霜清長藥窠。", "經旬鄰父病，且喜復來過。"]'),
('c4c73bfd-8311-4158-a14b-b7f8efb12823','自詒二首  其二','陸游','宋','宋诗','song-poetry','','[]','莫笑幽棲僻，謀生亦未疏。',48,'全唐诗/poet.song.135000.json','["莫笑幽棲僻，謀生亦未疏。", "殘囷具薄粥，半俸補殘書。", "均節貧無患，安恬疾可除。", "雖云苦寒近，隨手蓄薪樗。"]'),
('6658c65a-715d-4192-a929-555ca0664fc2','風霜','陸游','宋','宋诗','song-poetry','','[]','天上風霜慘，人間日月遒。',48,'全唐诗/poet.song.135000.json','["天上風霜慘，人間日月遒。", "江湖南北雁，原野雨晴鳩。", "莽蒼新阡陌，凋零舊輩流。", "惟應赤藤杖，伴我送悠悠。"]'),
('59b04f60-1130-4ee6-8a5f-4c38a7888271','十月','陸游','宋','宋诗','song-poetry','','[]','紅樹平沙十月天，放翁今作水中仙。',64,'全唐诗/poet.song.135000.json','["紅樹平沙十月天，放翁今作水中仙。", "鼕鼕林外迎神鼓，隻隻溪頭下釣船。", "世事極知吾有命，俗人終與汝無緣。", "菊花枯盡香猶在，又付東籬一醉眠。"]'),
('895dc057-292d-4edc-b7a4-8b125651b58f','記夢','陸游','宋','宋诗','song-poetry','','[]','久住人間豈自期，斷砧殘角助凄悲。',64,'全唐诗/poet.song.135000.json','["久住人間豈自期，斷砧殘角助凄悲。", "征行忽入夜來夢，意氣尚如年少時。", "絕塞但驚天似水，流年不記鬢成絲。", "此身死去詩猶在，未必無人粗見知。"]'),
('1f3e1767-eeb6-44bb-8abf-ec21858e2e50','幽興','陸游','宋','宋诗','song-poetry','','[]','池水車初滿，荆籬補已成。',48,'全唐诗/poet.song.135000.json','["池水車初滿，荆籬補已成。", "身閑詩簡淡，心靜夢和平。", "雁後寒鴉至，楓先桕葉頳。", "居然足幽興，未嘆歲崢嶸。"]'),
('8c46bad8-5bd9-4fdd-8a3c-6b85a2f5acce','夜聞雨聲','陸游','宋','宋诗','song-poetry','','[]','我似騎驢孟浩然，帽邊隨意領山川。',64,'全唐诗/poet.song.135000.json','["我似騎驢孟浩然，帽邊隨意領山川。", "忽聞風雨掠窗外，便覺江湖在眼前。", "路過郵亭知幾處，身如估客不論年。", "未妨剩擁寒衾卧，贏取孤吟入斷編。"]'),
('1018dc6b-85ce-4973-96f2-a9539f31bba0','訪山家','陸游','宋','宋诗','song-poetry','','[]','捨舟步上若耶溪，壽櫟修藤路欲迷。',64,'全唐诗/poet.song.135000.json','["捨舟步上若耶溪，壽櫟修藤路欲迷。", "僧院倚山馴栗鼠，野塘漲水下茭雞。", "草侵古路迢迢遠，雲傍行人故故低。", "薄暮但尋遺毳去，山家正在鶴巢西。"]'),
('b6ee107f-b84c-475e-8d78-25a7c707a488','自法雲回過魯墟故居','陸游','宋','宋诗','song-poetry','','[]','枳籬數掩閉柴扉，臼碓聲中烟火微。',64,'全唐诗/poet.song.135000.json','["枳籬數掩閉柴扉，臼碓聲中烟火微。", "雪暗杜陵無雁下，雲迷遼海有人歸。", "耕疇且復償初願，官路那知脫駭機。", "更有冬來歡喜事，芋魁豆兩不勝肥。"]'),
('f2f14ef6-5993-4569-9eec-150882ecd0d2','旅舍','陸游','宋','宋诗','song-poetry','','[]','寺鐘吹動四山昏，繫纜來投江上村。',64,'全唐诗/poet.song.135000.json','["寺鐘吹動四山昏，繫纜來投江上村。", "木落不妨生意足，水歸猶有漲痕存。", "爐紅手暖書差健，鼎沸湯深酒易溫。", "勿爲無年憂寇竊，狺狺小犬護籬門。"]'),
('f613d1c5-b9f3-4d3f-b44a-251847dbc4f9','書几試筆','陸游','宋','宋诗','song-poetry','','[]','鬢毛蕭颯齒牙疏，九十侵尋八十餘。',64,'全唐诗/poet.song.135000.json','["鬢毛蕭颯齒牙疏，九十侵尋八十餘。", "屋小苦寒猶省火，窗明新霽倍添書。", "解梁已報偏師入，上谷方看大盜除。", "藥笈箸囊幸無恙，蓮峰吾亦葺吾廬。"]'),
('90c55e12-ca54-4a66-b517-79109b112aae','道室偶書','陸游','宋','宋诗','song-poetry','','[]','置心常在結繩前，縱未登仙亦永年。',32,'全唐诗/poet.song.135000.json','["置心常在結繩前，縱未登仙亦永年。", "秦不及期周過曆，灼然由我不由天。"]'),
('cf23d317-5454-408d-925a-9ed16a329a07','觀渡江諸人詩','陸游','宋','宋诗','song-poetry','','[]','中朝文有漢唐風，南渡詩人尚數公。',32,'全唐诗/poet.song.135000.json','["中朝文有漢唐風，南渡詩人尚數公。", "正使詞源有深淺，病懷羈思亦相同。"]'),
('0b68900d-b778-48ec-baa4-95f22208ccf2','村居閑甚戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','人厭塵囂欲學仙，上天官府更紛然。',32,'全唐诗/poet.song.135000.json','["人厭塵囂欲學仙，上天官府更紛然。", "不如嘯傲東籬下，且作人間過數年。"]'),
('e90013c8-7a8e-484d-bd65-bb8d8fe8523c','村居閑甚戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','題詩本是閑中趣，却爲吟哦占却閑。',32,'全唐诗/poet.song.135000.json','["題詩本是閑中趣，却爲吟哦占却閑。", "我欲從今焚筆硯，興來隨分看青山。"]'),
('bb6d95da-9963-4cea-975f-a04f0a393080','夜投山家四首  其一','陸游','宋','宋诗','song-poetry','','[]','驀溝上阪到山家，牧豎譍門兩髻丫。',32,'全唐诗/poet.song.135000.json','["驀溝上阪到山家，牧豎譍門兩髻丫。", "葑火正紅煨竽熟，豈知新貴筑堤沙。"]'),
('9cfa8792-ec3c-4257-b3d7-998473e6f2e9','夜投山家四首  其二','陸游','宋','宋诗','song-poetry','','[]','夜行山步鼓鼕鼕，小市優場炬火紅。',32,'全唐诗/poet.song.135000.json','["夜行山步鼓鼕鼕，小市優場炬火紅。", "喚起少年巴蜀夢，宕渠山寺看蠶叢。"]'),
('f001b56c-73f7-480a-889f-8bd9c7f1d348','夜投山家四首  其三','陸游','宋','宋诗','song-poetry','','[]','生草茨廬荆作扉，數家烟火自相依。',32,'全唐诗/poet.song.135000.json','["生草茨廬荆作扉，數家烟火自相依。", "大兒飼犢舍邊去，小兒捕魚溪口歸。"]'),
('78bc3c44-a94c-4e1d-a84a-55722587620c','夜投山家四首  其四','陸游','宋','宋诗','song-poetry','','[]','房櫳深深績火明，垣屋蕭蕭礱穀聲。',32,'全唐诗/poet.song.135000.json','["房櫳深深績火明，垣屋蕭蕭礱穀聲。", "作官覓飽最繆算，羨爾爲農過一生。"]'),
('597f50f0-16a4-4a25-a440-4f23adbb61a2','聞西師復華州二首  其一','陸游','宋','宋诗','song-poetry','','[]','西師驛上破番書，鄠杜真成可卜居。',32,'全唐诗/poet.song.135000.json','["西師驛上破番書，鄠杜真成可卜居。", "細肋卧沙非望及，且炊黍飯食河魚。"]'),
('1a8c3f3a-7362-47ea-a629-d1c443688204','聞西師復華州二首  其二','陸游','宋','宋诗','song-poetry','','[]','青銅三百飲旗亭，關路騎驢半醉醒。',32,'全唐诗/poet.song.135000.json','["青銅三百飲旗亭，關路騎驢半醉醒。", "雙鷺斜飛敷水綠，孤雲橫度華山青。"]'),
('4069c6df-a123-4931-9676-ef7d662ec826','舟中','陸游','宋','宋诗','song-poetry','','[]','捩柁柯橋北，維舟草市西。',48,'全唐诗/poet.song.135000.json','["捩柁柯橋北，維舟草市西。", "月添霜氣峭，天带斗杓低。", "浦凍無魚躍，林深有鶴棲。", "不嫌村酒惡，也復醉如泥。"]'),
('47a43233-381b-41e7-86fb-1f6d26a83fe4','得趙昌甫寄予及子遹詩','陸游','宋','宋诗','song-poetry','','[]','去國雙蓬鬢，還山一鹿車。',48,'全唐诗/poet.song.135000.json','["去國雙蓬鬢，還山一鹿車。", "壯慚稽古淺，老悔養生疏。", "俗態慵開眼，高吟獨起予。", "青燈對余子，併爲問何如。"]'),
('acf5d522-a700-4fa5-b2f7-070ac49638f4','飯後登東山','陸游','宋','宋诗','song-poetry','','[]','飯已茶未成，褰裳步山徑。',96,'全唐诗/poet.song.135000.json','["飯已茶未成，褰裳步山徑。", "雖云筋力衰，拄杖猶濟勝。", "天高樓塔麗，霜落溝港凈。", "豈惟野實丹，已覺林筍迸。", "井桐亦强項，葉脫枝愈勁。", "啼鳥久不去，將無助幽興。", "盤紆穿翠谷，欹仄下危磴。", "所嗟無客來，誰與持麈柄。"]'),
('25b36662-16b2-4bc4-a940-7b51ee766185','東村','陸游','宋','宋诗','song-poetry','','[]','今日風日和，衰病亦少平。',96,'全唐诗/poet.song.135000.json','["今日風日和，衰病亦少平。", "出門無所之，携幼東村行。", "吳地冬未冰，濺濺溝水聲。", "山卉與野蔓，結實丹漆并。", "雞犬亦蕭散，如有世外情。", "舉手叩柴扉，病叟喜出迎。", "從我語蟬聯，未寒疇昔盟。", "解囊付之藥，與爾偕長生。"]'),
('ce083e3d-2dd3-497f-ba35-b2e7ecd56389','石堰村','陸游','宋','宋诗','song-poetry','','[]','木落山不蔽，水縮洲自獻。',72,'全唐诗/poet.song.135000.json','["木落山不蔽，水縮洲自獻。", "寒日晚更明，村巷曲折見。", "小婦鳴機杼，童子陳筆硯。", "農家雖苦貧，終勝異鄉縣。", "君看宦遊子，豈無墳墓戀。", "生死在故鄉，切勿慕乘傳。"]'),
('f16a6311-93aa-4514-9c29-b834a240b48b','袖手','陸游','宋','宋诗','song-poetry','','[]','袖手地爐傍，身閑日自長。',48,'全唐诗/poet.song.135000.json','["袖手地爐傍，身閑日自長。", "窗明蠹簡字，簾約篆盤香。", "道士傳琴譜，山僧送藥方。", "自然塵事遠，不用濯滄浪。"]'),
('f3ca44c1-e4a2-448e-ba6a-894d3fcea5f6','幽居遣懷三首  其一','陸游','宋','宋诗','song-poetry','','[]','大患元因有此身，正須枵腹對空囷。',64,'全唐诗/poet.song.135000.json','["大患元因有此身，正須枵腹對空囷。", "扶持接客寧嗟老，質貸迎醫未厭貧。", "碓下罕遺雞啄粒，席間不掃鼠行塵。", "時時笑顧兒曹說，縱有烟霄莫問津。"]'),
('fe04be74-a8a9-428e-acff-80975215b997','幽居遣懷三首  其二','陸游','宋','宋诗','song-poetry','','[]','斜陽孤影嘆伶仃，橫按烏藤坐草亭。',64,'全唐诗/poet.song.135000.json','["斜陽孤影嘆伶仃，橫按烏藤坐草亭。", "閑久更知貧有味，病多那責藥無靈。", "農書甚欲從師授，忍字常須作座銘。", "更喜友生能餉酒，欣然一醉倒長瓶。"]'),
('175d197b-c89f-4cce-8919-f26cb31f6246','幽居遣懷三首  其三','陸游','宋','宋诗','song-poetry','','[]','習氣深知要掃除，時時褊忿獨何歟。',64,'全唐诗/poet.song.135000.json','["習氣深知要掃除，時時褊忿獨何歟。", "呼童不應自生火，待飯未來還讀書。", "世態詎堪閑處看，俗人自與我曹疏。", "作詩未必能傳後，要是幽懷得小攄。"]'),
('5d81b554-4b1c-4e2b-8fdd-65074589909f','湖上晚歸','陸游','宋','宋诗','song-poetry','','[]','蓬山再別四經秋，來日翩翩去日遒。',64,'全唐诗/poet.song.135000.json','["蓬山再別四經秋，來日翩翩去日遒。", "無酒可傾殊省事，有詩渾忘亦良籌。", "梅花遮路如撩客，槲葉飄風已滿溝。", "湖上榜舟歸薄暮，斜陽紅入寺家樓。"]'),
('d7d2f9c6-399d-4551-9730-e41bc0b1bae7','宿村舍','陸游','宋','宋诗','song-poetry','','[]','驢瘦童僵小作程，村翁也復解逢迎。',64,'全唐诗/poet.song.135000.json','["驢瘦童僵小作程，村翁也復解逢迎。", "霜林已熟橙相饋，雪窖初開芋可羹。", "土榻圍爐豆郿暖，荻簾當戶布機鳴。", "解囊自取殘編讀，何處人間無短檠。"]'),
('30535569-411f-4297-8fa6-5a26a0cf9694','村飲二首  其一','陸游','宋','宋诗','song-poetry','','[]','雪前雪後梅初動，街北街南酒易賒。',32,'全唐诗/poet.song.135000.json','["雪前雪後梅初動，街北街南酒易賒。", "身健不妨隨處醉，有家未必勝無家。"]'),
('3b8a1fd2-fa1c-4dc4-abc7-c19408c7fa5f','村飲二首  其二','陸游','宋','宋诗','song-poetry','','[]','醉插江梅老更宜，猶能小樹揀繁枝。',32,'全唐诗/poet.song.135000.json','["醉插江梅老更宜，猶能小樹揀繁枝。", "假令住世十小劫，應愛此花無厭時。"]'),
('6a8a8014-7c6e-4010-a00a-27226d047dd2','食野味包子戲作','陸游','宋','宋诗','song-poetry','','[]','珍餉貧居少，寒雲萬里寬。',48,'全唐诗/poet.song.135000.json','["珍餉貧居少，寒雲萬里寬。", "疊雙初中鵠，牢九已登盤。", "放箸摩便腹，呼童破小團。", "猶勝瀼西老，菜把仰園官。"]'),
('9d06bad4-db7f-4178-a875-80265391dfd5','醉中作','陸游','宋','宋诗','song-poetry','','[]','名醞羔兒拆密封，香粳玉粒出新舂。',64,'全唐诗/poet.song.135000.json','["名醞羔兒拆密封，香粳玉粒出新舂。", "披綿珍𩺃經旬熟，斫雪雙螯洗手供。", "吟罷欲沉江渚月，夢回初動寺樓鐘。", "爐烟裊裊衣篝暖，未覺家風是老農。"]'),
('7552d5a3-dca2-42cb-9be3-8ca39c6cde57','感老','陸游','宋','宋诗','song-poetry','','[]','人生六十已爲衰，况我頹齡及耄期。',64,'全唐诗/poet.song.135000.json','["人生六十已爲衰，况我頹齡及耄期。", "對酒尚如年少日，愛書不減布衣時。", "遠遊每動辭家興，大藥方從出世師。", "但向青編觀曩事，英雄何代不兒嬉。"]'),
('b0074653-0eb7-4473-8620-725db5c5fc4b','寺壁偶題','陸游','宋','宋诗','song-poetry','','[]','斷山支徑得行吟，度磵穿林不厭深。',64,'全唐诗/poet.song.135000.json','["斷山支徑得行吟，度磵穿林不厭深。", "雉挾兩雌飛谷口，烏將數子下牆陰。", "前三喜接高人語，方寸寧容俗慮侵。", "少待新春好風日，不妨携客更相尋。"]'),
('2671fe39-6673-4f6e-843a-b75fe0db557e','贈道流','陸游','宋','宋诗','song-poetry','','[]','羽人邂逅飲旗亭，自說經年醉不醒。',64,'全唐诗/poet.song.135000.json','["羽人邂逅飲旗亭，自說經年醉不醒。", "曾伴翰林遊赤壁，仍邀內史寫黄庭。", "古琴蛇蚹評無價，寶劍魚腸託有靈。", "太華何時尋此約，九霄風露宿青冥。"]'),
('12422405-6960-45e5-93b2-b64af24f852d','冬夕閑詠','陸游','宋','宋诗','song-poetry','','[]','柳眼梅鬚漏泄春，江南又見物華新。',64,'全唐诗/poet.song.135000.json','["柳眼梅鬚漏泄春，江南又見物華新。", "終年幽興遺身世，半夜孤吟愴鬼神。", "客有疏親俱握手，酒無賢聖總濡唇。", "放翁自命君無笑，家世從來是散人。"]'),
('3b39fdce-d27e-4c60-ba64-f4071cb55ff9','飯後自嘲','陸游','宋','宋诗','song-poetry','','[]','歲熟家彌困，天寒酒闕傾。',48,'全唐诗/poet.song.135000.json','["歲熟家彌困，天寒酒闕傾。", "僅能炊稻飯，敢望糝藜羹。", "一榻解腰卧，四廊摩腹行。", "詩人要疏瘦，此日愧膨脝。"]'),
('4fed9b8e-c739-4102-aafa-b9650dc84282','感舊二首  其一','陸游','宋','宋诗','song-poetry','','[]','憶昔初乘上峽船，雪灘雲岫過聯翩。',32,'全唐诗/poet.song.135000.json','["憶昔初乘上峽船，雪灘雲岫過聯翩。", "匆匆不暇尋高隱，遺恨于今四十年。"]'),
('ad2940e0-9535-4b54-b68b-b4c3968b7850','感舊二首  其二','陸游','宋','宋诗','song-poetry','','[]','雕鞍送客雙流驛，銀燭看花萬里橋。',32,'全唐诗/poet.song.135000.json','["雕鞍送客雙流驛，銀燭看花萬里橋。", "三十三年真一夢，茆簷寒雨夜蕭蕭。"]'),
('f2387c5e-ac17-4151-aa48-2accd5b72ef0','村老留飲','陸游','宋','宋诗','song-poetry','','[]','乘興出遊眺，初不言所之。',120,'全唐诗/poet.song.135000.json','["乘興出遊眺，初不言所之。", "家人固難求，我亦不自知。", "投杖却人扶，疾步莫能追。", "荒寒野廟壖，枯涸漚菅池。", "過門爭邀留，具食不容辭。", "濁醪小甕釀，香飯別甑炊。", "瓦盆進豚肩，石臼擣花飺。", "新冬不易見，醉倒理亦宜。", "舉手謝主人，外强中實衰。", "一觴可以起，它日更爲期。"]'),
('e82572e5-10b6-4d28-955b-40d85a09edb0','醉歌二首  其一','陸游','宋','宋诗','song-poetry','','[]','草書大叫寫成圖，博簺隨聲喝作盧。',32,'全唐诗/poet.song.135000.json','["草書大叫寫成圖，博簺隨聲喝作盧。", "何似即今雲海上，千鈞强弩射天吳。"]'),
('accde833-2281-4410-9096-21b6e3e485fa','醉歌二首  其二','陸游','宋','宋诗','song-poetry','','[]','百騎河灘獵盛秋，至今血漬短貂裘。',32,'全唐诗/poet.song.135000.json','["百騎河灘獵盛秋，至今血漬短貂裘。", "誰知老卧江湖上，猶枕當年虎髑髏。"]'),
('d38e7764-0a61-4fd9-bbfe-d8641a64f2ad','力耕','陸游','宋','宋诗','song-poetry','','[]','力耕歲有一囷米，殘俸月無三萬錢。',64,'全唐诗/poet.song.135000.json','["力耕歲有一囷米，殘俸月無三萬錢。", "莫怪窮空心不動，正緣愚拙氣差全。", "學經亹亹懸車後，秉禮拳拳易簀前。", "猶恨未能忘筆硯，小兒收拾又成編。"]'),
('6e87437d-4b11-4457-9cd9-352d06160935','春近','陸游','宋','宋诗','song-poetry','','[]','開禧忽見第三春，身寄楓林野水濱。',64,'全唐诗/poet.song.135000.json','["開禧忽見第三春，身寄楓林野水濱。", "吾道幸逢天道在，物華又與歲華新。", "郊原處處堪行樂，道路人人可問津。", "剩辦青鞋并布襪，若耶已報綠生鱗。"]'),
('6c44d37d-0bf6-4be6-b839-26a01cb8681a','夜坐聞鼓聲','陸游','宋','宋诗','song-poetry','','[]','村居樂飲鼓鼕鼕，亭障無虞歲屢豐。',32,'全唐诗/poet.song.135000.json','["村居樂飲鼓鼕鼕，亭障無虞歲屢豐。", "誰道喧呼妨熟睡，老人自愛地爐紅。"]'),
('b6ed7603-2f5d-4791-9690-614f353a3390','小室','陸游','宋','宋诗','song-poetry','','[]','地褊焚香室，窗昏釀雪天。',48,'全唐诗/poet.song.135000.json','["地褊焚香室，窗昏釀雪天。", "爛炊二龠飯，側枕一肱眠。", "身似嬰兒日，家如太古年。", "狸奴不執鼠，同我愛青氈。"]'),
('39de84a1-ac4a-4ce9-a47b-007ba86a7ad6','老景','陸游','宋','宋诗','song-poetry','','[]','老死知無日，天公偶見寬。',48,'全唐诗/poet.song.135000.json','["老死知無日，天公偶見寬。", "疾行逾百步，健啖每三餐。", "身瘦短裁褐，髮稀低作冠。", "年來更小黠，不據伏波鞍。"]'),
('89dd5840-dfa9-4f0c-9d43-a322ee90402a','夜坐','陸游','宋','宋诗','song-poetry','','[]','地僻少人迹，屋低便老人。',48,'全唐诗/poet.song.135000.json','["地僻少人迹，屋低便老人。", "爐紅得清坐，酒綠慰孤斟。", "吠犬驚飄葉，栖禽換暗林。", "人間固多難，感慨不須深。"]'),
('4bc68509-b68c-41b2-bec5-051bf11163c5','晨起','陸游','宋','宋诗','song-poetry','','[]','小疾蠲除盡，閑愁墾闢空。',48,'全唐诗/poet.song.135000.json','["小疾蠲除盡，閑愁墾闢空。", "時光雞唱裏，生計碓聲中。", "戒婢儲猿果，看奴織鶴籠。", "老人新得道，處處見神通。"]'),
('3f3823a6-0ecc-440d-ba04-5d4bcb7c705f','貧述','陸游','宋','宋诗','song-poetry','','[]','寒生肌粟苦衣單，瘦減頭圍覺帽寬。',64,'全唐诗/poet.song.135000.json','["寒生肌粟苦衣單，瘦減頭圍覺帽寬。", "荒寂在家猶逆旅，窮空養老亦蔬餐。", "柴青竈突騰烟細，膏盡燈缸照字難。", "猶喜新醅三斗熟，半窗梅影助清歡。"]'),
('de873f38-7095-430a-a7fe-f223e1a9c383','自述','陸游','宋','宋诗','song-poetry','','[]','勃落爲衣隱薜蘿，掃空塵抱養天和。',64,'全唐诗/poet.song.135000.json','["勃落爲衣隱薜蘿，掃空塵抱養天和。", "過期未死更强健，與世不諧猶嘯歌。", "野市蕭條殘葉滿，酒家零落廢壚多。", "石帆山下孤舟雨，借問君如此老何。"]'),
('581def32-6973-45e6-9a34-185f173d31cc','十一月廿七日夜分披衣起坐神光自兩眥出若初日室中皆明作詩志之','陸游','宋','宋诗','song-poetry','','[]','靈府無思踵息微，神光出眥射窗扉。',64,'全唐诗/poet.song.135000.json','["靈府無思踵息微，神光出眥射窗扉。", "大冠長劍竟何有，尺宅寸園今始歸。", "憂患過前皆夢事，功名自古與心違。", "三峰二室烟塵靜，要試霜天槲葉衣。"]'),
('8ea9f9e9-7644-41cd-a649-efd452ab7b33','歲暮遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','昔慕騷人賦遠遊，放懷蜀棧楚山秋。',64,'全唐诗/poet.song.135000.json','["昔慕騷人賦遠遊，放懷蜀棧楚山秋。", "橘中尚可著四老，海外誰云無九州。", "薄酒時須澆舌本，閑愁莫遣上眉頭。", "幅巾短褐吾差便，實厭衣冠裹沐猴。"]'),
('6a13a9d7-1cbf-4d58-9b4e-3cb59cc102f7','歲暮遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','病著愁侵併不支，孤村况遇歲殘時。',64,'全唐诗/poet.song.135000.json','["病著愁侵併不支，孤村况遇歲殘時。", "水軒客散成舒嘯，山寺僧來得劇棋。", "銅鴨香生風嫋嫋，竹雞聲斷雨絲絲。", "新詩煅煉功何似，問著衰翁自不知。"]'),
('1bc6b123-8405-4eba-a7a6-fc620f8aeacb','道室即事四首  其一','陸游','宋','宋诗','song-poetry','','[]','看盡吳山看蜀山，歸來不減舊朱顔。',32,'全唐诗/poet.song.135000.json','["看盡吳山看蜀山，歸來不減舊朱顔。", "宣和遺老凋零盡，况說祥符景德間。"]'),
('7affdc7f-d5be-4b4f-a2fb-6c4f8a268f9c','道室即事四首  其二','陸游','宋','宋诗','song-poetry','','[]','松根茯苓味絕珍，甑中枸杞香動人。',32,'全唐诗/poet.song.135000.json','["松根茯苓味絕珍，甑中枸杞香動人。", "勸君下筯不領略，終作邙山一窖塵。"]'),
('2571f4ce-2228-49a1-9c9c-32b0c704fde5','道室即事四首  其三','陸游','宋','宋诗','song-poetry','','[]','徧遊海嶽却歸秦，除却南山萬事新。',32,'全唐诗/poet.song.135000.json','["徧遊海嶽却歸秦，除却南山萬事新。", "長劍高車何足道，金人十二也成塵。"]'),
('f89c097c-32c2-4b0c-a315-fdc02742f6d1','道室即事四首  其四','陸游','宋','宋诗','song-poetry','','[]','黄金堆屋無處用，甲第連雲誰與居。',32,'全唐诗/poet.song.135000.json','["黄金堆屋無處用，甲第連雲誰與居。", "莫笑先生無僕馬，風雷萬里跨鯨魚。"]'),
('a9ce1acd-5316-4908-88cb-dc7c547ac1a8','泛舟過金家埂贈賣薪王翁四首  其一','陸游','宋','宋诗','song-poetry','','[]','水生浦溆多浮鴨，風急汀洲有斷鴻。',32,'全唐诗/poet.song.135000.json','["水生浦溆多浮鴨，風急汀洲有斷鴻。", "渺渺江天無限景，一時分付與樵翁。"]'),
('adb364ff-9ad8-4134-bd64-76dd6a76f998','泛舟過金家埂贈賣薪王翁四首  其二','陸游','宋','宋诗','song-poetry','','[]','老人不復事農桑，點數雞豚亦未忘。',32,'全唐诗/poet.song.135000.json','["老人不復事農桑，點數雞豚亦未忘。", "洗脚上牀真一快，稚孫漸長解燒湯。"]'),
('ce62e44c-da06-41ca-a19e-590093597f91','泛舟過金家埂贈賣薪王翁四首  其三','陸游','宋','宋诗','song-poetry','','[]','賣薪自可了鹽酪，治地何妨栽果蔬。',32,'全唐诗/poet.song.135000.json','["賣薪自可了鹽酪，治地何妨栽果蔬。", "我老鈍頑請半俸，此渠只有不能如。"]'),
('160a92cd-241d-42b3-846e-1c2473c9d19f','泛舟過金家埂贈賣薪王翁四首  其四','陸游','宋','宋诗','song-poetry','','[]','軟炊豆飯可支日，厚絮布襦聊過冬。',32,'全唐诗/poet.song.135000.json','["軟炊豆飯可支日，厚絮布襦聊過冬。", "閭巷家家歌聖澤，子孫世世業春農。"]'),
('44df4f51-015c-4f7e-a13a-72cfe5d3e40e','冬晴','陸游','宋','宋诗','song-poetry','','[]','歲暮常年雪正豪，今年暄暖減綈袍。',64,'全唐诗/poet.song.135000.json','["歲暮常年雪正豪，今年暄暖減綈袍。", "春回山圃梅爭發，睡足茆簷日已高。", "倉庾家家儲舊穀，笙歌店店賣新醪。", "太平氣象方如許，寄語殘胡早遁逃。"]'),
('fe3019d9-62b9-4f27-a982-99b3536b02af','寄隱士','陸游','宋','宋诗','song-poetry','','[]','乳竇寒猶滴，巖扉夜不扃。',48,'全唐诗/poet.song.135000.json','["乳竇寒猶滴，巖扉夜不扃。", "奇書窺鳥跡，靈藥得人形。", "浩浩天風積，冥冥海氣清。", "儻逢王內史，更爲乞黄庭。"]'),
('ae617ec7-69bb-41b7-bbf8-b3deecb41215','幽事','陸游','宋','宋诗','song-poetry','','[]','老大常愁節物催，東皇又挽斗杓回。',64,'全唐诗/poet.song.135000.json','["老大常愁節物催，東皇又挽斗杓回。", "江天慘慘不成雪，山驛蕭蕭初見梅。", "隱士寄雲從地肺，遊僧問路上天台。", "戲書幽事無時闕，古錦詩囊暮暮開。"]'),
('a9dad6e9-dff0-46f1-aac8-589b204116eb','去新春纔旬餘霽色可愛','陸游','宋','宋诗','song-poetry','','[]','宦遊强半侍僊祠，况是懸車耄及時。',64,'全唐诗/poet.song.135000.json','["宦遊强半侍僊祠，况是懸車耄及時。", "厚薄人情窮易見，陰晴天氣病先知。", "綠樽一醉真當勉，白髮千莖莫自疑。", "野渡山村梅柳動，身閑何處不熙熙。"]'),
('9579a47e-d7e4-4fa4-af84-ef73ef788f31','作雪遇大風遂晴','陸游','宋','宋诗','song-poetry','','[]','雪作風散之，雪止風亦定。',72,'全唐诗/poet.song.135000.json','["雪作風散之，雪止風亦定。", "霽日上窗扉，明暖起我病。", "去春財十日，共喜時序正。", "晨興盥頮罷，白髮滿清鏡。", "門前無客至，默卧弄麈柄。", "叢竹如有情，代我發孤詠。"]'),
('9911f0bf-1a26-4656-be5d-af48e975d8cf','冬夜','陸游','宋','宋诗','song-poetry','','[]','我生何多艱，塌地皆九折。',72,'全唐诗/poet.song.135000.json','["我生何多艱，塌地皆九折。", "君恩許歸休，幸與世俗絕。", "幽居鄰不覿，奚止掃車轍。", "地爐清夜中，危坐燈欲滅。", "開門月滿庭，皓皓如積雪。", "隔溪聞鶴鳴，靈府爲澄澈。"]'),
('4df7402d-bd46-477d-902f-d1e10e6e07d8','書意三首  其一','陸游','宋','宋诗','song-poetry','','[]','飲酒以散愁，服藥以去病。',72,'全唐诗/poet.song.135000.json','["飲酒以散愁，服藥以去病。", "區區賴外物，豈足語性命。", "清晨坐堂上，萬事一袖手。", "愁病初無根，孰謂藥與酒。", "掀髯笑嵇阮，舉袂謝和緩。", "氣住則神住，時至骨自換。"]'),
('41c613df-d7ab-4fef-8a9a-83a2101d918c','書意三首  其二','陸游','宋','宋诗','song-poetry','','[]','解牛悟養生，牧羊知治民。',72,'全唐诗/poet.song.135000.json','["解牛悟養生，牧羊知治民。", "通一萬事畢，我每思古人。", "小園財三畝，手自藝嘉木。", "先當培其根，又戒無欲速。", "老松卧澗底，千歲陵冰霜。", "我豈樗櫟哉，但取無伐傷。"]'),
('6b9fd66c-917a-4d32-a1de-a087f064b162','書意三首  其三','陸游','宋','宋诗','song-poetry','','[]','唐堯授人時，妙用均造化。',72,'全唐诗/poet.song.135000.json','["唐堯授人時，妙用均造化。", "我讀七月詩，周室亦其亞。", "彼用治四海，我斂之一身。", "至理之所在，太山等微塵。", "鍊氣以成真，豈復有它術。", "譬如尊六經，百氏當盡黜。"]'),
('59acbb3f-2586-4cf9-83df-0281766d6b3e','山房','陸游','宋','宋诗','song-poetry','','[]','擾擾人間歲月移，山房幾度換茅茨。',64,'全唐诗/poet.song.135000.json','["擾擾人間歲月移，山房幾度換茅茨。", "身遊與世相忘地，詩到令人不愛時。", "老鶴初來未丹頂，稚松親種已虬枝。", "東塗西抹非無意，皺面朱鉛太不宜。"]'),
('a3f52ad3-0644-4937-9bc0-ee0c7bad1d34','即事六首  其一','陸游','宋','宋诗','song-poetry','','[]','老來百事似嬰兒，美睡甘餐只自知。',32,'全唐诗/poet.song.135000.json','["老來百事似嬰兒，美睡甘餐只自知。", "陋屋略如營窟世，淳風不減結繩時。"]'),
('219a608d-0b13-4d13-9e57-e7b4a6a801f1','即事六首  其二','陸游','宋','宋诗','song-poetry','','[]','鴻冥固自辭矰繳，樗散猶能謝斧斤。',32,'全唐诗/poet.song.135000.json','["鴻冥固自辭矰繳，樗散猶能謝斧斤。", "况是溪山幽絕地，有人高卧百重雲。"]'),
('033c780e-0a3d-4080-a1b7-a5fe1e84affb','即事六首  其三','陸游','宋','宋诗','song-poetry','','[]','閑行靜坐樂誰知，紅飯青蔬美有餘。',32,'全唐诗/poet.song.135000.json','["閑行靜坐樂誰知，紅飯青蔬美有餘。", "常笑癡人不更事，時時愁嘆欲何須。"]'),
('b0445ca1-07d3-45f9-b920-477ea90d3f7c','即事六首  其四','陸游','宋','宋诗','song-poetry','','[]','有人叩戶皆吾友，得屋施床即我家。',32,'全唐诗/poet.song.135000.json','["有人叩戶皆吾友，得屋施床即我家。", "緩步東西行飯耳，元非看竹探梅花。"]'),
('3cfa3a35-886c-4a2c-915e-90ba8fd879b3','即事六首  其五','陸游','宋','宋诗','song-poetry','','[]','了事如何省事奇，無心始覺有心癡。',32,'全唐诗/poet.song.135000.json','["了事如何省事奇，無心始覺有心癡。", "三更急雨打窗破，正是擁爐危坐時。"]'),
('8dbe351c-7164-4e77-992d-67d3591dc539','即事六首  其六','陸游','宋','宋诗','song-poetry','','[]','高人鬻駱放柳枝，豪士駿馬換蛾眉。',32,'全唐诗/poet.song.135000.json','["高人鬻駱放柳枝，豪士駿馬換蛾眉。", "人間解事誰如我，小蹇小童自謂宜。"]'),
('605eb01a-2626-4562-8be8-2d43c00d5747','戍兵有新婚之明日遂行者予聞而悲之爲作絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','送女忽忽不擇日，綵繞羊身花照席。',32,'全唐诗/poet.song.135000.json','["送女忽忽不擇日，綵繞羊身花照席。", "暮婚晨別已可悲，猶勝空房未相識。"]'),
('fed80a2b-30d3-4b88-aacf-f3f0710ac2e1','戍兵有新婚之明日遂行者予聞而悲之爲作絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','夜靜孤村聞笛聲，溪頭月落欲三更。',32,'全唐诗/poet.song.135000.json','["夜靜孤村聞笛聲，溪頭月落欲三更。", "不須吹徹陽關曲，中有征人萬里情。"]'),
('c06bef67-958b-4966-b7ce-023da9c3071a','夢中作','陸游','宋','宋诗','song-poetry','','[]','野鶴翩僊啄粒微，碧桃縹緲著花稀。',32,'全唐诗/poet.song.135000.json','["野鶴翩僊啄粒微，碧桃縹緲著花稀。", "海山又見春風到，丹竈苔封人未歸。"]'),
('553f9350-9785-4adc-9ebf-cf9db26393af','啜茶示兒輩','陸游','宋','宋诗','song-poetry','','[]','圍坐團欒且勿譁，飯餘共舉此甌茶。',64,'全唐诗/poet.song.135000.json','["圍坐團欒且勿譁，飯餘共舉此甌茶。", "粗知道義死無憾，已迫耄期生有涯。", "小圃花光還滿眼，高城漏鼓不停撾。", "閑人一笑真當勉，小榼何妨問酒家。"]'),
('72acc6ae-25a1-4113-97cc-9bca4ee4f0a7','雨中示鄰里','陸游','宋','宋诗','song-poetry','','[]','寒風吹細雨，白晝見日罕。',72,'全唐诗/poet.song.135000.json','["寒風吹細雨，白晝見日罕。", "經旬廢讀書，天豈成我懶。", "比鄰各無聊，會面苦不款。", "未嘗燒茶鐺，而况把酒碗。", "高談極奇趣，散去意亦滿。", "癡黠未易名，要是工用短。"]'),
('fdb816b3-c7cb-4640-ae86-e87f4f5ae965','記出遊所見','陸游','宋','宋诗','song-poetry','','[]','我行初無折簡招，出門十里未覺遥。',96,'全唐诗/poet.song.135000.json','["我行初無折簡招，出門十里未覺遥。", "憩裝蕭蕭北崦寺，策蹇渺渺西村橋。", "眉頭那可遣愁到，舌本正要著酒澆。", "寒風朝作入裘褐，荒祠暮過奠桂椒。", "平郊烟斂見聚落，細路日落逢漁樵。", "安得丹青王右轄，爲寫此段傳生綃。"]'),
('ae8dc8fa-be84-4d1a-a89b-a8bde69b1e2f','立春前七日聞有預作春盤邀客者戲作','陸游','宋','宋诗','song-poetry','','[]','蓼芽蔬甲簇青紅，盤筯紛紛笑語中。',32,'全唐诗/poet.song.135000.json','["蓼芽蔬甲簇青紅，盤筯紛紛笑語中。", "一餅不分空恨望，暮年知有幾春風。"]'),
('3a6148f6-70b2-41fe-8853-9e0717c35d72','春前六日作','陸游','宋','宋诗','song-poetry','','[]','夜枕夢回春雨聲，曉窗日出春鳥鳴。',32,'全唐诗/poet.song.135000.json','["夜枕夢回春雨聲，曉窗日出春鳥鳴。", "典衣沽酒莫辭醉，自有梅花爲解酲。"]'),
('d6a85287-9fcb-45a0-a32e-17c031028f1a','立春後作','陸游','宋','宋诗','song-poetry','','[]','春不遺窮僻，天如念寂寥。',48,'全唐诗/poet.song.135000.json','["春不遺窮僻，天如念寂寥。", "鳥鳴知節換，池溜覺冰消。", "冷餠供新薺，輕裘換故貂。", "豐年無疾苦，鄰曲遞相招。"]'),
('f34ec864-7dca-41c2-8813-d92722a78c4c','舟中','陸游','宋','宋诗','song-poetry','','[]','江天雲斷漏斜暉，靡迤群山翠作圍。',64,'全唐诗/poet.song.135000.json','["江天雲斷漏斜暉，靡迤群山翠作圍。", "帆影似經吳赤壁，櫓聲如下蜀青衣。", "卧聞裂水長魚出，起看凌風健鶻飛。", "禹會橋邊最清絕，憶曾深夜叩漁扉。"]'),
('fd0e23d2-283e-4b91-93b7-566d103faac6','小園春思二首  其一','陸游','宋','宋诗','song-poetry','','[]','小軒愁入丁香結，幽徑春生豆蔻梢。',32,'全唐诗/poet.song.135000.json','["小軒愁入丁香結，幽徑春生豆蔻梢。", "若論此時吟思苦，縱磨鐵硯也成凹。"]'),
('33a43695-0693-4e2d-9f58-d2dc2fbc8e7e','小園春思二首  其二','陸游','宋','宋诗','song-poetry','','[]','重臺諼草初離土，百葉緗梅已滿枝。',32,'全唐诗/poet.song.135000.json','["重臺諼草初離土，百葉緗梅已滿枝。", "莫道山家殺風景，也能醉倒向東籬。"]'),
('90bf2419-87eb-43bd-8646-83a21ecf9f8f','禹祠','陸游','宋','宋诗','song-poetry','','[]','祠宇嵯峨接寶坊，扁舟又繫畫橋傍。',64,'全唐诗/poet.song.135000.json','["祠宇嵯峨接寶坊，扁舟又繫畫橋傍。", "豉添滿筯蓴絲紫，蜜漬堆盤粉餌香。", "團扇賣時春漸晚，夾衣換後日初長。", "故人零落今何在，空吊頹垣墨數行。"]'),
('7cd9ec42-4c82-4daf-8805-e6b1107bca5b','今年開歲三日上元三夕立春人日皆大晴','陸游','宋','宋诗','song-poetry','','[]','今歲晴和歷歲無，江城歌舞溢通衢。',32,'全唐诗/poet.song.135000.json','["今歲晴和歷歲無，江城歌舞溢通衢。", "天心只向人心卜，不用殷勤問紫姑。"]'),
('b405cfe8-4610-4c73-9f66-b6007a677daf','題野人壁','陸游','宋','宋诗','song-poetry','','[]','身如魚鳥出池籠，常在陂湖草莽中。',64,'全唐诗/poet.song.135000.json','["身如魚鳥出池籠，常在陂湖草莽中。", "簫鼓相聞村社密，桑麻無際歲時豐。", "市墟買酒何人識，僧閤煎茶欠客同。", "久欲瀟湘寄清嘯，它年一棹莫匆匆。"]'),
('8224b621-180a-4550-9b59-2590a928fd60','小市','陸游','宋','宋诗','song-poetry','','[]','春風小市畫橋橫，橋北橋南次第行。',64,'全唐诗/poet.song.135000.json','["春風小市畫橋橫，橋北橋南次第行。", "絕景惟詩號勍敵，閑愁頼酒作長城。", "樓臺到處靈和柳，簾幕誰家子晉笙。", "薄暮歸來漁火閙，放翁自笑欲忘情。"]'),
('3974888a-9593-40ed-97f8-6ca97aa6ea58','柳','陸游','宋','宋诗','song-poetry','','[]','春來無處不春風，偏在湖橋柳色中。',32,'全唐诗/poet.song.135000.json','["春來無處不春風，偏在湖橋柳色中。", "看得淺黄成嫩綠，始知造物有全功。"]'),
('dfd54408-df4f-437e-820f-614349800aec','見事','陸游','宋','宋诗','song-poetry','','[]','流光莫恨去聯翩，見事還疑勝昔年。',64,'全唐诗/poet.song.135000.json','["流光莫恨去聯翩，見事還疑勝昔年。", "細改新詩須枕上，少留劇飲待花前。", "陰陰竹塢安茶竈，淺淺蘋汀著釣船。", "物外家風吾豈敢，散人名號亦充員。"]'),
('a0d3c971-cb68-4cc2-9eb9-e43041b2d022','夜雨','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江邊依舊釣舟橫，萬事何曾有一成。',32,'全唐诗/poet.song.135000.json','["江邊依舊釣舟橫，萬事何曾有一成。", "空憶廬山風雨夜，自吹小竈煮蔓菁。"]'),
('3c687b5b-254f-49ae-a6e7-a0ba1803f8df','自詒','陸游','宋','宋诗','song-poetry','','[]','一廛東近會稽城，鑿破烟蕪俋俋耕。',64,'全唐诗/poet.song.135000.json','["一廛東近會稽城，鑿破烟蕪俋俋耕。", "上藥養神非近效，善言銘座要躬行。", "論書尚欲心先正，學道寧容氣不平。", "天付吾儕元自足，滿園春薺又堪烹。"]'),
('af415d57-9c0e-4b2d-bec2-100000496367','初春幽居二首  其一','陸游','宋','宋诗','song-poetry','','[]','滿榼芳醪手自携，陂湖南北埭東西。',64,'全唐诗/poet.song.135000.json','["滿榼芳醪手自携，陂湖南北埭東西。", "茂林處處見松鼠，幽圃時時聞竹鷄。", "零落斷雲斜鄣日，霏微過雨未成泥。", "老民不預人間事，但喜農疇漸可犁。"]'),
('b3419972-f9e2-470c-83a5-4876b1e7cdd0','初春幽居二首  其二','陸游','宋','宋诗','song-poetry','','[]','小築園林淺鑿池，身閑隨事得遊嬉。',64,'全唐诗/poet.song.135000.json','["小築園林淺鑿池，身閑隨事得遊嬉。", "幽花折得露猶溼，嘉木移來根不知。", "小蝶弄晴飛不去，珍禽喜靜語多時。", "風光未忍輕拋擲，聊付詩囊與酒卮。"]'),
('f00e1024-0a81-4907-96ce-c7d11ad7c148','自勉','陸游','宋','宋诗','song-poetry','','[]','學詩當學陶，學書當學顔。',72,'全唐诗/poet.song.135000.json','["學詩當學陶，學書當學顔。", "正復不能到，趣鄉已可觀。", "養氣要使完，處身要使端。", "勿謂在屋漏，人見汝肺肝。", "節義實大閑，忠孝後代看。", "汝雖老將死，更勉未死間。"]'),
('00b5187a-df7e-4a69-94e3-36993fa5cc09','春遊','陸游','宋','宋诗','song-poetry','','[]','梅市移舟過古城，此行亦未闕逢迎。',64,'全唐诗/poet.song.135000.json','["梅市移舟過古城，此行亦未闕逢迎。", "負薪野老無妻子，施藥山人隠姓名。", "風雨偏宜宿茅店，鹽醯不遣到藜羹。", "宣和版籍今誰在，似是天教樂太平。"]'),
('ccde6194-a551-4088-bf20-a4f30df50561','晝坐','陸游','宋','宋诗','song-poetry','','[]','早春風雨暗江干，羔酒狐裘不敵寒。',32,'全唐诗/poet.song.135000.json','["早春風雨暗江干，羔酒狐裘不敵寒。", "輸與蒲龕深袖手，一爐真火養金丹。"]'),
('8a5fc8d8-38bc-4e05-8880-e2a3d50b11a0','正月十六日送子虡至梅市歸舟示子遹','陸游','宋','宋诗','song-poetry','','[]','策府還山白盡頭，一廛隨分葺菟裘。',64,'全唐诗/poet.song.135000.json','["策府還山白盡頭，一廛隨分葺菟裘。", "看燈雖幸新春健，無食猶懷卒歲憂。", "稚子與翁俱襏襫，大兒出塞習兜鍪。", "它時別作謀生計，賣藥惟當學伯休。"]'),
('4419098a-9cef-4360-b8ab-af3c73bab592','聞百舌','陸游','宋','宋诗','song-poetry','','[]','春鳥雖儳言，春盡能齰舌。',48,'全唐诗/poet.song.135000.json','["春鳥雖儳言，春盡能齰舌。", "秋蚓與寒螿，亦各知時節。", "微物顧能此，人乃獨不然。", "君看甘陵黨，作孽非由天。"]'),
('d18d570e-aa4d-4135-9d33-8bfd8787e972','畜一鷄報曉聲清圓而鳴每晚戲書絕句','陸游','宋','宋诗','song-poetry','','[]','鷄鳴平旦未爲遲，恰是山房睡覺時。',32,'全唐诗/poet.song.135000.json','["鷄鳴平旦未爲遲，恰是山房睡覺時。", "著屐起尋溪上路，野梅猶有未殘枝。"]'),
('6311eee1-99f3-4797-a735-1deeb92a619e','書村落間事','陸游','宋','宋诗','song-poetry','','[]','東巷西巷新月明，南村北村戲鼓聲。',96,'全唐诗/poet.song.135000.json','["東巷西巷新月明，南村北村戲鼓聲。", "家家輸賦及時足，耕有讓畔桑無爭。", "一村婚聘皆鄰里，婦姑孝慈均母子。", "兒從城中懷肉歸，婦滌鐺釜供刀匕。", "再拜進酒壽老人，慈顔一笑溫如春。", "太平無象今有象，窮虜何地生烟塵。"]'),
('d2100259-8549-4cbb-826d-af47f125d4b1','行歌','陸游','宋','宋诗','song-poetry','','[]','孤村小市負薪歌，造物其如此老何。',32,'全唐诗/poet.song.135000.json','["孤村小市負薪歌，造物其如此老何。", "靈藥已能驅疾豎，醇醪不用戰悲魔。"]'),
('b5da6c28-cf05-4c55-8cce-dc24f71aba25','開歲頗思江湖遊適','陸游','宋','宋诗','song-poetry','','[]','健筆當年賦遠遊，即今局促但堪羞。',64,'全唐诗/poet.song.135000.json','["健筆當年賦遠遊，即今局促但堪羞。", "雖爲月下孤舟客，未醉天涯七澤秋。", "丹熟竟當金換骨，客來從笑雪蒙頭。", "龍泉本約同歸隠，肯爲春耕欲換牛。"]'),
('6ab7d7a7-f653-44ff-af01-850457f9e75a','憶昨三首  其一','陸游','宋','宋诗','song-poetry','','[]','入蜀還吳迹已陳，蘭亭道上又逢春。',32,'全唐诗/poet.song.135000.json','["入蜀還吳迹已陳，蘭亭道上又逢春。", "諸君試取吾詩看，何異前身與後身。"]'),
('8b858dee-cc3d-4c7c-b8c1-a31b0df6a6dc','憶昨三首  其二','陸游','宋','宋诗','song-poetry','','[]','當年落魄錦江邊，物外常多宿世緣。',32,'全唐诗/poet.song.135000.json','["當年落魄錦江邊，物外常多宿世緣。", "先主廟中逢市隠，丈人觀裏識巢僊。"]'),
('866b635e-3bec-470e-a8b1-608e29cf7ecc','憶昨三首  其三','陸游','宋','宋诗','song-poetry','','[]','萬里曾爲汗漫遊，豈知白首弄漁舟。',32,'全唐诗/poet.song.135000.json','["萬里曾爲汗漫遊，豈知白首弄漁舟。", "會騎一鶴凌風去，何處人間無酒樓。"]'),
('1c6ceb6a-9dc4-46ef-ae43-85574fefde60','排悶','陸游','宋','宋诗','song-poetry','','[]','抱耒返東皋，初非憚作勞。',48,'全唐诗/poet.song.135000.json','["抱耒返東皋，初非憚作勞。", "饑寒凜未免，老病適相遭。", "開卷無如懶，飛觥豈復豪。", "不辭窮到死，猶足竊名高。"]'),
('40f4f7cc-ab6b-4754-9d1d-c6a7983d1352','識喜','陸游','宋','宋诗','song-poetry','','[]','齒搖徐自定，髮脫却重生。',48,'全唐诗/poet.song.135000.json','["齒搖徐自定，髮脫却重生。", "意適簪花舞，身輕捨杖行。", "僧招决棋戰，客讓主詩盟。", "尚欲瀟湘去，烟帆不計程。"]'),
('368b4e86-b415-4a78-9fe7-52ff4209af31','枕上作','陸游','宋','宋诗','song-poetry','','[]','謝事還家一老農，悠然高卧聽晨舂。',64,'全唐诗/poet.song.135000.json','["謝事還家一老農，悠然高卧聽晨舂。", "雖無客共樽中酒，何至僧鳴飯後鐘。", "采若未能浮楚澤，思鱸猶欲釣吳松。", "自餘萬事慵開眼，知結宗門案幾重。"]'),
('b7a27fb6-72ec-4dc0-9147-e5215ecf3ed6','近村','陸游','宋','宋诗','song-poetry','','[]','去去柴車十里中，竹林密處路纔通。',64,'全唐诗/poet.song.135000.json','["去去柴車十里中，竹林密處路纔通。", "漸聞水磑知村近，遥望禾囷喜歲豐。", "漁艇往來春浪碧，人家高下夕陽紅。", "百錢又向旗亭醉，自笑吾生亦未窮。"]'),
('0f9be177-3a15-4f44-a8c5-7beb4087ef5d','讀史二首  其一','陸游','宋','宋诗','song-poetry','','[]','人間著脚盡危機，睡覺方知夢境非。',32,'全唐诗/poet.song.135000.json','["人間著脚盡危機，睡覺方知夢境非。", "莫怪富春江上客，一生不厭釣漁磯。"]'),
('32016428-9ed5-4b0d-8f5e-51c453a14cb2','讀史二首  其二','陸游','宋','宋诗','song-poetry','','[]','榮悴紛紛醉夢中，轉頭何事不成空。',32,'全唐诗/poet.song.135000.json','["榮悴紛紛醉夢中，轉頭何事不成空。", "全家采藥鹿門去，我憶襄陽龐德公。"]'),
('0e8d6ab2-c31e-4dd2-b124-1266b247a545','羸卧','陸游','宋','宋诗','song-poetry','','[]','羸卧將如老景何，小園風月且婆娑。',64,'全唐诗/poet.song.135000.json','["羸卧將如老景何，小園風月且婆娑。", "茶因春困論交密，酒爲家貧作態多。", "馬上元無聽鷄句，原頭那有飯牛歌。", "自憐遠屏猶多事，賣藥歸來買釣蓑。"]'),
('9a7c7e99-bd0d-439f-b777-1d4914bed2bb','春感','陸游','宋','宋诗','song-poetry','','[]','老厭紛紛懶入城，長亭小市近清明。',64,'全唐诗/poet.song.135000.json','["老厭紛紛懶入城，長亭小市近清明。", "隴頭下漏初芸草，陌上吹簫正賣餳。", "多病更知生是贅，九原那恨死無名。", "但餘一事猶關念，萬里唐安闕寄聲。"]'),
('4023670d-62d2-4214-aee2-15adbbdcfe14','八十三吟','陸游','宋','宋诗','song-poetry','','[]','石帆山下白頭人，八十三回見草春。',64,'全唐诗/poet.song.135000.json','["石帆山下白頭人，八十三回見草春。", "自愛安閑忘寂寞，天將强健報清貧。", "枯桐已爨寧求識，弊帚當捐却自珍。", "桑苧家風君勿笑，它年猶得作茶神。"]'),
('24a5641f-93f7-4053-bfbf-fc876e3f8e90','小園花盛開','陸游','宋','宋诗','song-poetry','','[]','厭住愁城徙醉鄉，春風也肯到山房。',64,'全唐诗/poet.song.135000.json','["厭住愁城徙醉鄉，春風也肯到山房。", "鴨頭綠漲池平岸，猩血紅深杏出牆。", "淡薄相遭心已懶，修行無力夢猶狂。", "更嗟著句多塵思，慚愧溪藤似截肪。"]'),
('df03a3de-2c8b-4c3b-8ad9-0106137e7d9e','出遊歸卧得雜詩八首  其一','陸游','宋','宋诗','song-poetry','','[]','江天缺月西南落，村路寒鷄一再鳴。',32,'全唐诗/poet.song.135000.json','["江天缺月西南落，村路寒鷄一再鳴。", "自笑此身羈旅慣，野橋孤店每關情。"]'),
('beae69f2-3263-4392-afb6-b141920a5141','出遊歸卧得雜詩八首  其二','陸游','宋','宋诗','song-poetry','','[]','江村何處小茅茨，紅杏青蒲雨過時。',32,'全唐诗/poet.song.135000.json','["江村何處小茅茨，紅杏青蒲雨過時。", "半幅生綃大年畫，一聯新句少游詩。"]'),
('b00381b8-cc51-4f64-9795-c6b60558b7d0','出遊歸卧得雜詩八首  其三','陸游','宋','宋诗','song-poetry','','[]','眼明未了觀山債，力在猶能涉水行。',32,'全唐诗/poet.song.135000.json','["眼明未了觀山債，力在猶能涉水行。", "莫笑軒然誇老健，身存終勝得浮名。"]'),
('2b1efdb3-6a87-475d-ade5-2e6cb492337a','出遊歸卧得雜詩八首  其四','陸游','宋','宋诗','song-poetry','','[]','壯歲經春在醉鄉，老來數酌不禁當。',32,'全唐诗/poet.song.135000.json','["壯歲經春在醉鄉，老來數酌不禁當。", "正須獨倚蒲團坐，領略明窗半篆香。"]'),
('b43a77cf-29ad-4b96-b727-7ca40d6216c5','出遊歸卧得雜詩八首  其五','陸游','宋','宋诗','song-poetry','','[]','兒扶行飯出柴扉，傴僂方嗟氣力微。',32,'全唐诗/poet.song.135000.json','["兒扶行飯出柴扉，傴僂方嗟氣力微。", "道側偶逢耘麥叟，倚鋤閑話兩忘歸。"]'),
('57402c2e-3ba4-4218-b96d-935efe2ca3b2','出遊歸卧得雜詩八首  其六','陸游','宋','宋诗','song-poetry','','[]','久讀僊經學養形，未容便應少微星。',32,'全唐诗/poet.song.135000.json','["久讀僊經學養形，未容便應少微星。", "一枝新鍛金雅觜，更向名山斸茯苓。"]'),
('bf184586-7652-48b3-a8ad-93bc7d5311da','出遊歸卧得雜詩八首  其七','陸游','宋','宋诗','song-poetry','','[]','薺花如雪滿中庭，乍出芭蕉一寸青。',32,'全唐诗/poet.song.135000.json','["薺花如雪滿中庭，乍出芭蕉一寸青。", "老子掩關常謝客，短蓑鋤菜伴園丁。"]'),
('fe5e227f-a9e5-421b-8027-28f4b9ae9de0','出遊歸卧得雜詩八首  其八','陸游','宋','宋诗','song-poetry','','[]','晚交數子多才傑，誰肯頻來寂寞鄉。',32,'全唐诗/poet.song.135000.json','["晚交數子多才傑，誰肯頻來寂寞鄉。", "但寄好詩三四幅，絕勝共笑億千場。"]'),
('f584b487-6d0f-4e1b-b062-eb310a3310c7','感舊','陸游','宋','宋诗','song-poetry','','[]','自蜀還吳會，先憑劍換牛。',48,'全唐诗/poet.song.135000.json','["自蜀還吳會，先憑劍換牛。", "掃除狂習氣，謝絕醉朋儔。", "去死時猶遠，餘生已覺浮。", "即今真憊矣，閉戶尚何求。"]'),
('ef4023c0-cab1-41e0-9e0d-275b684ebb82','寄龔立道','陸游','宋','宋诗','song-poetry','','[]','龔子吳中第一流，老農何幸接英遊。',64,'全唐诗/poet.song.135000.json','["龔子吳中第一流，老農何幸接英遊。", "難逢正似玉杵臼，易散便成風馬牛。", "清夜話端思滾滾，暮年心事恐悠悠。", "何由喚得閶門櫂，一醉千巖萬壑秋。"]'),
('3f30ab1b-54e2-40da-bfeb-bc1ef6e9747e','寓嘆','陸游','宋','宋诗','song-poetry','','[]','五福惟無富，嗟予得已多。',48,'全唐诗/poet.song.135000.json','["五福惟無富，嗟予得已多。", "禪房時託宿，酒市每酣歌。", "詩瘦慵看鏡，棋鏖恐爛柯。", "殘年猶有幾，切莫負漁蓑。"]'),
('5575f7f0-d8f6-418c-9701-412a63c36f4e','春晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','客夢初回夜漏殘，東村想見杏花繁。',32,'全唐诗/poet.song.135000.json','["客夢初回夜漏殘，東村想見杏花繁。", "未能便逐啼鴉起，自掩屏風護曉寒。"]'),
('615b25b2-bde1-4fb8-8510-87efc36c9b6a','春晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','湖上春寒雁已歸，宿酲殘夢兩依依。',32,'全唐诗/poet.song.135000.json','["湖上春寒雁已歸，宿酲殘夢兩依依。", "也知晨起元無事，窗白爐紅且攬衣。"]'),
('e6b7f7f5-e660-4416-95c7-96430994a5d0','幽事二首  其一','陸游','宋','宋诗','song-poetry','','[]','跌宕人間歲月遷，賞心幽事故依然。',64,'全唐诗/poet.song.135000.json','["跌宕人間歲月遷，賞心幽事故依然。", "潮通支浦漁舟活，露溼繁花醉帽偏。", "才盡賦詩愁壓倒，氣衰對弈怯饒先。", "光陰風月空如昨，悵望蘭亭祓禊年。"]'),
('23199e78-1526-4629-995c-a48cb3f9ad9a','幽事二首  其二','陸游','宋','宋诗','song-poetry','','[]','塵抱年來盡掃空，柴門幽事與誰同。',64,'全唐诗/poet.song.135000.json','["塵抱年來盡掃空，柴門幽事與誰同。", "水生初漲一溪綠，花落已浮千點紅。", "愁頼橐泉存舊法，困憑顧渚策新功。", "故人岷下無消息，尺素憑誰寄斷鴻。"]'),
('6d28f836-5ce9-4b9f-91a5-a4dd26b037cb','讀李杜詩','陸游','宋','宋诗','song-poetry','','[]','濯錦滄浪客，青蓮澹蕩人。',48,'全唐诗/poet.song.135000.json','["濯錦滄浪客，青蓮澹蕩人。", "才名塞天地，身世老風塵。", "士固難推挽，人誰不賤貧。", "明窗數編在，長與物華新。"]'),
('216c503f-3b88-46af-ab20-84a15ad4911a','烟波即事十首  其一','陸游','宋','宋诗','song-poetry','','[]','短髮垂肩不裹巾，世人誰識此翁真。',32,'全唐诗/poet.song.135000.json','["短髮垂肩不裹巾，世人誰識此翁真。", "阻風江浦詩成束，賣藥山城醉過春。"]'),
('eece6922-20bc-4095-bd44-5647dfdcf563','烟波即事十首  其二','陸游','宋','宋诗','song-poetry','','[]','烟波深處卧孤篷，宿酒醒時聞斷鴻。',32,'全唐诗/poet.song.135000.json','["烟波深處卧孤篷，宿酒醒時聞斷鴻。", "最是平生會心事，蘆花千頃月明中。"]'),
('83de57a5-dcb5-42f9-8dcc-864757b47b60','烟波即事十首  其三','陸游','宋','宋诗','song-poetry','','[]','家浮野艇無常處，身是閑人不屬官。',32,'全唐诗/poet.song.135000.json','["家浮野艇無常處，身是閑人不屬官。", "但有濁醪吾事足，浮名不作一錢看。"]'),
('cfd0a333-9ee3-44fe-b210-98574f18f6a5','烟波即事十首  其四','陸游','宋','宋诗','song-poetry','','[]','落雁沙邊艇子斜，分明清夢上三巴。',32,'全唐诗/poet.song.135000.json','["落雁沙邊艇子斜，分明清夢上三巴。", "眼明一點炊烟起，不是漁家即酒家。"]'),
('c0a72a84-232c-4733-9942-2a8b3b9ada1b','烟波即事十首  其五','陸游','宋','宋诗','song-poetry','','[]','雕胡炊飯芰荷衣，水退浮萍尚半扉。',32,'全唐诗/poet.song.135000.json','["雕胡炊飯芰荷衣，水退浮萍尚半扉。", "莫爲風波羨平地，人間處處是危機。"]'),
('bf6d8ff6-edb6-42dd-83e2-257eba69e347','烟波即事十首  其六','陸游','宋','宋诗','song-poetry','','[]','夢筆橋邊聽午鐘，無窮烟水似吳松。',32,'全唐诗/poet.song.135000.json','["夢筆橋邊聽午鐘，無窮烟水似吳松。", "前年送客曾來此，惟有山僧認得儂。"]'),
('46a49263-4476-4945-893a-0e3c184a7711','烟波即事十首  其七','陸游','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','浪迹人間數十年，年年散髮醉江天。',32,'全唐诗/poet.song.135000.json','["浪迹人間數十年，年年散髮醉江天。", "岳陽樓上留三日，聊與瀟湘結後緣。"]'),
('e04580f2-291e-42c1-9faa-8bd5e2ca5eec','烟波即事十首  其八','陸游','宋','宋诗','song-poetry','','[]','烟水蒼茫絕四鄰，幽棲無地著纖塵。',32,'全唐诗/poet.song.135000.json','["烟水蒼茫絕四鄰，幽棲無地著纖塵。", "蕭條鷄犬楓林下，似是無懷太古民。"]'),
('0b3b7624-ebe7-499c-954e-e7fcf97bc1d0','烟波即事十首  其九','陸游','宋','宋诗','song-poetry','','[]','歸老何須乞鏡湖，秋來日日飽蓴鱸。',32,'全唐诗/poet.song.135000.json','["歸老何須乞鏡湖，秋來日日飽蓴鱸。", "正令霖雨稱賢佐，未及烟波號釣徒。"]'),
('72c434fd-338b-48e7-b130-3de532840088','烟波即事十首  其一○','陸游','宋','宋诗','song-poetry','','[]','父子團欒到死時，漁家可樂更何疑。',32,'全唐诗/poet.song.135000.json','["父子團欒到死時，漁家可樂更何疑。", "高文大策人皆有，且聽烟波十絕詩。"]'),
('493ddbd1-352f-4aa5-8b2d-a52a2aa29487','茅舍','陸游','宋','宋诗','song-poetry','','[]','茅舍晨鷄復暝鴉，暮年別自是生涯。',64,'全唐诗/poet.song.135000.json','["茅舍晨鷄復暝鴉，暮年別自是生涯。", "貪眠久已遺人事，對酒猶能惜物華。", "出有兒孫持几杖，歸從鄰曲話桑麻。", "日長亦莫憎春困，小竈何妨自煮茶。"]'),
('8069da4c-915d-4ed4-a498-69529aaca56a','子遹入城三宿而歸獨坐凄然示以此篇','陸游','宋','宋诗','song-poetry','','[]','吾兒早自立，所懼非饑寒。',120,'全唐诗/poet.song.135000.json','["吾兒早自立，所懼非饑寒。", "我歸自僊蓬，再疏請挂冠。", "明恩華其行，汝亟忝一官。", "得祿寧甚遠，懼違菽水歡。", "我年且九十，亦覺去汝難。", "生死要相守，豈憚聯征鞍。", "但恐老益衰，千里愁關山。", "官期猶累歲，言之已辛酸。", "村醪瀉盎盆，山果亦滿盤。", "春風吹桃李，一笑且團欒。"]'),
('3f5fde04-4438-4ead-ac87-c21539935853','暮春新路至湖上示元敏','陸游','宋','宋诗','song-poetry','','[]','時雨作未成，蒸溽思出門。',84,'全唐诗/poet.song.135000.json','["時雨作未成，蒸溽思出門。", "湖塘直東西，行人各歸村。", "翻翻鳥投林，杳杳鐘鳴昏。", "羊牛爭迮路，烟火出短垣。", "吾兒望未到，誰與共盤餐。", "幽獨多惻愴，且復携斯孫。", "歸來蓬窗下，聊可與晤言。"]'),
('540e4f1f-20ab-4094-9cf9-e6e4b822c218','閔雨','陸游','宋','宋诗','song-poetry','','[]','臘雪不濡土，春風吹早塵。',60,'全唐诗/poet.song.135000.json','["臘雪不濡土，春風吹早塵。", "東吳貴粳稻，布種當及晨。", "千里方囂囂，坐視膏澤屯。", "民孽實自作，所頼天公仁。", "何時見秋穫，如山築高囷。"]'),
('f3589e5b-3466-46ab-8e48-1646e17ddf8b','春和初遷坐堂中','陸游','宋','宋诗','song-poetry','','[]','九月天始霜，澤中多烈風。',120,'全唐诗/poet.song.135000.json','["九月天始霜，澤中多烈風。", "東廂尋丈地，聊以安我躬。", "薪炭南山來，地爐晨暮紅。", "二月春始和，如蟲思舊螫。", "草堂雖褊小，門戶隨事葺。", "闢窗對小山，峰嶂爭嶪岌。", "筆硯陳橫几，圖書羅矮床。", "頡頏燕雀聲，左右蘭茝芳。", "有時苦頑痹，杖藜寄相羊。", "折花與弄水，自適亦何常。"]'),
('43937714-4801-45fd-b4a6-3a60a674fc0e','春晴暄甚花開略無餘矣賦以寓感','陸游','宋','宋诗','song-poetry','','[]','常年看花時，輒苦風雨厄。',96,'全唐诗/poet.song.135000.json','["常年看花時，輒苦風雨厄。", "今年獨異此，遊人滿阡陌。", "翩翩出聯騎，往往醉墮幘。", "轉盼桃杏空，遂見辛夷坼。", "海棠尤可念，不耐暖日炙。", "胭脂成白雪，其意亦自惜。", "曾未淹旬時，春事欲掃迹。", "安得愛花心，堅頑如鐵石。"]'),
('5b08ce16-669c-47ca-a18f-20e7eec94fbb','春晚','陸游','宋','宋诗','song-poetry','','[]','南陌東阡自在身，黄塵不污接䍦巾。',64,'全唐诗/poet.song.135000.json','["南陌東阡自在身，黄塵不污接䍦巾。", "無方可染星星鬢，有酒能留盎盎春。", "下豉已添蓴菜美，銜泥又見燕巢新。", "作公何益辛毗事，且是人間九十人。"]'),
('1025556b-edd5-4cd4-81b5-e68a2921a91e','春陰溪上小軒作','陸游','宋','宋诗','song-poetry','','[]','午醉初醒倚釣軒，悠然無與共清言。',64,'全唐诗/poet.song.135000.json','["午醉初醒倚釣軒，悠然無與共清言。", "風微僅足吹花片，雨細纔能見水痕。", "杳杳暝鐘浮遠浦，離離烟樹識孤村。", "故人萬里岷山下，安得書來慰斷魂。"]'),
('51c33d44-f6b7-43be-9793-4b6d337c1d40','散策至湖上民家','陸游','宋','宋诗','song-poetry','','[]','曳杖翩然入莽蒼，人間有此白雲鄉。',64,'全唐诗/poet.song.135000.json','["曳杖翩然入莽蒼，人間有此白雲鄉。", "風傳高樹珍禽語，露溼幽叢藥草香。", "農事正看春水白，客途漸愛午陰凉。", "餘年且就無羈束，社鼓鼕鼕樂未央。"]'),
('3d9d4720-47b5-4c3e-9dad-3087c026abf2','枕上聞雨聲','陸游','宋','宋诗','song-poetry','','[]','小雨廉纖不濡土，忽聞簷溜喜無窮。',32,'全唐诗/poet.song.135000.json','["小雨廉纖不濡土，忽聞簷溜喜無窮。", "斷知不作西山餓，多稼如雲在眼中。"]'),
('308c014d-c79e-4c24-b872-2206ac38d89d','聞里中有鬬者作此示之','陸游','宋','宋诗','song-poetry','','[]','老翁無所長，惟是更事多。',72,'全唐诗/poet.song.135000.json','["老翁無所長，惟是更事多。", "生世與人處，烏可傷至和。", "秋毫不能忍，平地尋干戈。", "唾面聽自乾，彼忿自消磨。", "鄉鄰皆世舊，何至誓弗過。", "勗哉養子壽，它年住鷄窠。"]'),
('f52a6e35-352f-4373-a933-b08de6c60eca','春寒','陸游','宋','宋诗','song-poetry','','[]','漁艇水流去，柴門風自開。',48,'全唐诗/poet.song.135000.json','["漁艇水流去，柴門風自開。", "餘寒爲醉地，多病作慵媒。", "莎草鋤還出，鷗群去復來。", "流年殊衮衮，殘鬢不禁催。"]'),
('80bfaf43-0e52-467a-81be-41f5109b4d64','石帆山下','陸游','宋','宋诗','song-poetry','','[]','久矣移家住鹿門，偶然信脚到桃源。',64,'全唐诗/poet.song.135000.json','["久矣移家住鹿門，偶然信脚到桃源。", "尚嫌名挂東林社，那問塵生北海樽。", "才盡極知詩草草，睡多常覺氣昏昏。", "舊聞福地多靈藥，安得高人與細論。"]'),
('c4e5a8cb-204f-434f-ac89-4bf7ee3a84b5','餘寒','陸游','宋','宋诗','song-poetry','','[]','漠漠餘寒透客衣，江村倍覺失春期。',32,'全唐诗/poet.song.135000.json','["漠漠餘寒透客衣，江村倍覺失春期。", "頡頏燕比常年晚，開落花爭數日遲。"]'),
('bd53d249-c0e0-4dae-92b6-ec7f9cbf3951','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其一','陸游','宋','宋诗','song-poetry','','[]','桐帽絁裘擁半酣，肩輿咿軋轉城南。',64,'全唐诗/poet.song.135000.json','["桐帽絁裘擁半酣，肩輿咿軋轉城南。", "牛過野水將新犢，女采柔桑起稚蠶。", "遺老年光垂九十，故鄉春事及重三。", "種花築室知難辦，借地猶能結草庵。"]'),
('c2ce4f61-90b1-4c4a-8288-92e0e048500a','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其二','陸游','宋','宋诗','song-poetry','','[]','細雨如絲映晚暉，店家小憩換征衣。',64,'全唐诗/poet.song.135000.json','["細雨如絲映晚暉，店家小憩換征衣。", "春農耕罷負犁去，村社祭餘懷肉歸。", "黄犢自依殘照卧，白鷗爭傍小灘飛。", "道邊舊識凋零盡，誰記遼天老令威。"]'),
('a2bb0d47-6164-469c-93a4-c2cac13b7ad4','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其三','陸游','宋','宋诗','song-poetry','','[]','老子無心老尚狂，山程隨處寄倀倀。',64,'全唐诗/poet.song.135000.json','["老子無心老尚狂，山程隨處寄倀倀。", "雲歸岫穴初收雨，水入陂塘正下秧。", "野客就林煨燕筍，蠶家負籠采鷄桑。", "遠遊萬里知何樂，却喜東歸住故鄉。"]'),
('f3a3caae-2b60-42f5-b0fa-5dc440fb2ce3','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其四','陸游','宋','宋诗','song-poetry','','[]','老子山行肯遽回，直穿犖确上崔嵬。',64,'全唐诗/poet.song.135000.json','["老子山行肯遽回，直穿犖确上崔嵬。", "未誇脚力如平昔，且喜眉頭得暫開。", "廟後故梁龍化去，山前遺箭鶴銜來。", "囊錢已盡君無笑，草草猶能把一杯。"]'),
('f2da3074-242e-4732-8003-d4aeb18c3657','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其五','陸游','宋','宋诗','song-poetry','','[]','我來恰值暮春初，晝漏微長小雨餘。',64,'全唐诗/poet.song.135000.json','["我來恰值暮春初，晝漏微長小雨餘。", "苔蝕秦碑亡舊刻，龍歸禹穴護遺書。", "燕巢已壘泥猶溼，花片雖殘葉尚疏。", "到處不妨俱可樂，詩人爲底愛吾廬。"]'),
('dc0b1703-b11b-4459-b4c1-2431ca1f9b53','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其六','陸游','宋','宋诗','song-poetry','','[]','輿似鷄栖寄兩竿，山程三月尚春寒。',64,'全唐诗/poet.song.135000.json','["輿似鷄栖寄兩竿，山程三月尚春寒。", "麥苗吐穗初成實，梅子生仁已带酸。", "買飯猶勝乞墦客，看耕僭學勸農官。", "還家莫道虛懷袖，筍蕨隨宜亦滿槃。"]'),
('0589269a-1113-4f7b-bc52-20c6789f577b','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其七','陸游','宋','宋诗','song-poetry','','[]','點點桃花糝綠苔，入門倚杖意悠哉。',64,'全唐诗/poet.song.135000.json','["點點桃花糝綠苔，入門倚杖意悠哉。", "數聲茶飯齋初散，一片溪雲雨欲來。", "老宿龍鍾嗟獨在，高松磊砢憶新栽。", "世間萬事俱難料，未死重遊更幾回。"]'),
('b7661d45-e4c0-4fb8-89eb-6d5a250b30a0','自九里平水至雲門陶山歷龍瑞禹祠而歸凡四日八首  其八','陸游','宋','宋诗','song-poetry','','[]','我行隨處叩巖扉，覓得生薪旋燎衣。',64,'全唐诗/poet.song.135000.json','["我行隨處叩巖扉，覓得生薪旋燎衣。", "道士已驂鸞鶴去，山僧初自水雲歸。", "甕頭酒壓松肪熟，盤里蔬供藥汞肥。", "老覺論心須世外，溪陰回首尚依依。"]'),
('bdcd7054-d638-483c-9b9e-9f2bbc979f5c','春早得雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','春早得甘澍，村鄰喜欲狂。',24,'全唐诗/poet.song.135000.json','["春早得甘澍，村鄰喜欲狂。", "天公終老手，處處出新秧。"]'),
('e133abb5-7760-4b0a-b5c1-14e82a2346f3','春早得雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','稻陂方渴雨，蠶箔却憂寒。',24,'全唐诗/poet.song.135000.json','["稻陂方渴雨，蠶箔却憂寒。", "更有難知處，朱門惜牡丹。"]'),
('eb012a43-80a9-4753-9435-9d8d501de7d1','春晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','窗戶迎新燕，階除集乳鴉。',24,'全唐诗/poet.song.135000.json','["窗戶迎新燕，階除集乳鴉。", "欲知春已暮，地上亦無花。"]'),
('4f731791-e906-4727-8b09-3003d4f267b4','春晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','思與春爲別，匆匆置一樽。',24,'全唐诗/poet.song.135000.json','["思與春爲別，匆匆置一樽。", "明年尚强健，扶杖候柴門。"]'),
('1ab522e8-1c0b-432e-8e91-8f91259a611e','春晚南堂晨起二首  其一','陸游','宋','宋诗','song-poetry','','[]','秋風樹瘦勁，春露葉扶疏。',72,'全唐诗/poet.song.135000.json','["秋風樹瘦勁，春露葉扶疏。", "夙興立堂上，短髮未暇梳。", "高謝世俗攖，遊於物之初。", "青黄災斷木，三四調群狙。", "長生豈有巧，要令方寸虛。", "今年幸差健，小雨聊荷鋤。"]'),
('5801af53-5d86-4624-bcc4-712dbd82fd0b','春晚南堂晨起二首  其二','陸游','宋','宋诗','song-poetry','','[]','春陽染柳條，春風落花片。',72,'全唐诗/poet.song.135000.json','["春陽染柳條，春風落花片。", "化工本無心，誰與催漏箭。", "俯仰財幾時，梁間有雛燕。", "人亦隨物遷，蒼然鏡中面。", "要當心鐵石，先登酣百戰。", "我豈兒女哉，秋風感團扇。"]'),
('9f4cced7-5e22-40f1-99c1-69bf9c54a313','見鵲補巢戲作','陸游','宋','宋诗','song-poetry','','[]','卧看銜枝鵲補巢，方知此老懶堪嘲。',32,'全唐诗/poet.song.135000.json','["卧看銜枝鵲補巢，方知此老懶堪嘲。", "山村四十餘年住，未省曾添一把茅。"]'),
('069d31c3-2f84-4cde-a4cf-fdd8a0f612d1','予素不工書故硯筆墨皆取具而已作詩自嘲','陸游','宋','宋诗','song-poetry','','[]','我昔生兵間，淮洛靡安宅。',120,'全唐诗/poet.song.135000.json','["我昔生兵間，淮洛靡安宅。", "髧髦入小學，童丱聚十百。", "先生依靈肘，教以兔園冊。", "僅能記姓名，筆硯固不擇。", "竈煤磨斷瓦，荻管隨手畫。", "稍長遊名場，粗若分菽麥。", "偶窺文房譜，雖慕無由獲。", "筆惟可把握，墨取黑非白。", "硯得石即已，殆可供搗帛。", "從渠膏粱子，竊視笑啞啞。"]'),
('4d266cb4-0693-4d05-990b-49cc9bb99693','春晚即事四首  其一','陸游','宋','宋诗','song-poetry','','[]','桑麻夾道蔽行人，桃李隨風旋作塵。',32,'全唐诗/poet.song.135000.json','["桑麻夾道蔽行人，桃李隨風旋作塵。", "煜煜紅燈迎婦擔，鼕鼕畫鼓祭蠶神。"]'),
('77221967-d3e6-47ea-b358-018e9d460aa1','春晚即事四首  其二','陸游','宋','宋诗','song-poetry','','[]','小時抵死願春留，老大逢春去即休。',32,'全唐诗/poet.song.135000.json','["小時抵死願春留，老大逢春去即休。", "今歲禹祠纔一到，安能分日作遨遊。"]'),
('f2a40813-9b35-4199-9ba4-7469aeb722dd','春晚即事四首  其三','陸游','宋','宋诗','song-poetry','','[]','漁村樵市過殘春，八十三年老病身。',32,'全唐诗/poet.song.135000.json','["漁村樵市過殘春，八十三年老病身。", "殘虜遊魂苗渴雨，杜門憂國復憂民。"]'),
('1bfb2995-6289-413f-8301-d75eba463ff5','春晚即事四首  其四','陸游','宋','宋诗','song-poetry','','[]','龍骨車鳴水入塘，雨來猶可望豐穰。',32,'全唐诗/poet.song.135000.json','["龍骨車鳴水入塘，雨來猶可望豐穰。", "老農愛犢行泥緩，幼婦憂蠶采葉忙。"]'),
('5fe85e23-4439-4980-ab71-8171e72cb00e','懷昔','陸游','宋','宋诗','song-poetry','','[]','高皇布網收鳳麟，我得定交猶數人。',32,'全唐诗/poet.song.135000.json','["高皇布網收鳳麟，我得定交猶數人。", "陳山清真王逸少，李石風流賀季真。"]'),
('487a2a8f-1dda-4121-b6b9-c2c88f936d2e','書感','陸游','宋','宋诗','song-poetry','','[]','一是端能服萬人，施行自足掃胡塵。',32,'全唐诗/poet.song.135000.json','["一是端能服萬人，施行自足掃胡塵。", "南州不可無高士，東國何妨有逐臣。"]'),
('85b2da4e-f19e-4a76-ba98-ea4db08c0b95','夜中獨步庭下','陸游','宋','宋诗','song-poetry','','[]','山月明如晝，江風冷借秋。',48,'全唐诗/poet.song.135000.json','["山月明如晝，江風冷借秋。", "衰遲亦可嘆，幽獨自成愁。", "斗柄垂江渚，笳聲下戍樓。", "我惟詩思在，從此亦宜休。"]'),
('2ba36983-25aa-4117-bffd-04fd791f7896','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔紹興中，束带陪衆彥。',216,'全唐诗/poet.song.135000.json','["憶昔紹興中，束带陪衆彥。", "沐浴雨露私，草木盡葱蒨。", "一朝窮達異，相遇忘慶唁。", "遠官楚蜀間，寂寞返鄉縣。", "于時同舍郎，貴者至鼎鉉。", "數奇益自屏，短褐失貧賤。", "俯仰五十載，未愧金百鍊。", "忍饑菰蘆間，生理僅如綫。", "窮交誰耐久，晨暮一破硯。", "嘯歌楓林下，萬事付露電。", "惟有孤舟興，所至多勝踐。", "衡茅無定止，何處非郵傳。", "炊烟起沙際，跳魚裂波面。", "嘔啞緯車鳴，隠翳漁火見。", "簫鼓樂水神，鐘梵閙竹院。", "我詩雖日衰，得句尚悲健。", "巍巍闕里門，未嘗棄狂狷。", "放浪終餘年，造物不汝譴。"]'),
('234db8d3-195c-47ea-8d21-547c92c47e0f','雜詠十首  其一','陸游','宋','宋诗','song-poetry','','[]','仕困風波歸可樂，生如疣贅死何悲。',32,'全唐诗/poet.song.135000.json','["仕困風波歸可樂，生如疣贅死何悲。", "極如此手終無巧，那得隨人儘作癡。"]'),
('413e95a8-8be5-42c4-971e-8b60044b616e','雜詠十首  其二','陸游','宋','宋诗','song-poetry','','[]','鏡中顔狀年年改，海內交朋日日疏。',32,'全唐诗/poet.song.135000.json','["鏡中顔狀年年改，海內交朋日日疏。", "一慟寢門生意盡，從今無復季長書。"]'),
('bed1fd96-2689-4bae-ab3b-afc89b554f34','雜詠十首  其三','陸游','宋','宋诗','song-poetry','','[]','女郎花樹新移種，官長梅園亦探租。',32,'全唐诗/poet.song.135000.json','["女郎花樹新移種，官長梅園亦探租。", "作盡人間兒戲事，誰知空橐一錢無。"]'),
('63b9e05c-4bac-48ce-a851-3512d8ca469e','雜詠十首  其四','陸游','宋','宋诗','song-poetry','','[]','一日日窮窮不醒，一年年老老如期。',32,'全唐诗/poet.song.135000.json','["一日日窮窮不醒，一年年老老如期。", "黄河却有逢清日，白髮應無返黑時。"]'),
('23986be3-2116-4265-873d-f886a084501c','雜詠十首  其五','陸游','宋','宋诗','song-poetry','','[]','世間萬事本悠悠，自古詩人易白頭。',32,'全唐诗/poet.song.135000.json','["世間萬事本悠悠，自古詩人易白頭。", "莫羨老夫垂九十，一年添得一年愁。"]'),
('74f8316c-9fda-4ef1-958d-33e1aeb6c3ee','雜詠十首  其六','陸游','宋','宋诗','song-poetry','','[]','夸士騎牛著鐵冠，往來城市擁途觀。',32,'全唐诗/poet.song.135000.json','["夸士騎牛著鐵冠，往來城市擁途觀。", "爭如老子無奇怪，惟是蓑衣伴釣竿。"]'),
('49b29135-9fcf-4ad0-9e28-5f430ae40a9b','雜詠十首  其七','陸游','宋','宋诗','song-poetry','','[]','家圃菜肥忘肉食，村場酒美勝官壺。',32,'全唐诗/poet.song.135000.json','["家圃菜肥忘肉食，村場酒美勝官壺。", "終年醉飽無憂責，莫怪愚公老不枯。"]'),
('064a3dff-0e4b-4b58-94b2-95e23aaee2ee','雜詠十首  其八','陸游','宋','宋诗','song-poetry','','[]','宦途所至尚偷閑，何况湖邊晝掩關。',32,'全唐诗/poet.song.135000.json','["宦途所至尚偷閑，何况湖邊晝掩關。", "未愛好風吹醉袖，且貪微雨養盆山。"]'),
('5fc67470-7062-46b0-8c5b-01bd8c43ac89','雜詠十首  其九','陸游','宋','宋诗','song-poetry','','[]','斜風吹雨晚空濛，獨立溪邊兩鬢蓬。',32,'全唐诗/poet.song.135000.json','["斜風吹雨晚空濛，獨立溪邊兩鬢蓬。", "便過此生何所恨，百年强半水雲中。"]'),
('4f03bc73-e84d-4315-a603-fb3e84de5fc0','雜詠十首  其一○','陸游','宋','宋诗','song-poetry','','[]','病起清臞不自持，紗巾一幅倚筇枝。',32,'全唐诗/poet.song.135000.json','["病起清臞不自持，紗巾一幅倚筇枝。", "水沉香冷紅蕉晚，恰似道山群玉時。"]'),
('87864bd0-6d00-4c77-b27c-ab43d4e9b4ff','曉思','陸游','宋','宋诗','song-poetry','','[]','暮年多感愴，孤夢久不成。',72,'全唐诗/poet.song.135000.json','["暮年多感愴，孤夢久不成。", "殘燈暗無焰，宿雨滴有聲。", "食少夜常饑，展轉空腸鳴。", "老鷄雖三號，山窗終未明。", "默誦舊記書，更覺負平生。", "披衣搔短髮，壯志浩縱橫。"]'),
('7d1f5baa-d541-4e44-8061-ac80c0b6aae3','幽居二首  其一','陸游','宋','宋诗','song-poetry','','[]','策府還家又五年，心常無事氣常全。',64,'全唐诗/poet.song.135000.json','["策府還家又五年，心常無事氣常全。", "平生本不營三窟，此日何須直一錢。", "雨霽桑麻皆沃若，地偏鷄犬亦翛然。", "閉門便造桃源境，不必秦人始是仙。"]'),
('743e8750-4854-4ec5-9dfc-70cee54bd9b3','幽居二首  其二','陸游','宋','宋诗','song-poetry','','[]','橫草無功負主恩，一生强半卧衡門。',64,'全唐诗/poet.song.135000.json','["橫草無功負主恩，一生强半卧衡門。", "蠹書身世元無憾，伏櫪光陰不更論。", "春雨負薪蘭渚市，秋風采藥石帆村。", "更思旋糴場中麥，暖熱塵埃老瓦盆。"]'),
('92ec9e21-8c1b-4633-aa40-57ded25be264','幽居即事九首  其一','陸游','宋','宋诗','song-poetry','','[]','采藥鹿門山，釣魚富春渚。',48,'全唐诗/poet.song.135000.json','["采藥鹿門山，釣魚富春渚。", "君看此氣象，何止輩伊呂。", "直令終不偶，後人會知汝。", "亦不妨著書，世世祕囊褚。"]'),
('4e5905b0-a4d6-4735-84d4-e69af05cfc78','幽居即事九首  其二','陸游','宋','宋诗','song-poetry','','[]','野寺促晨裝，古驛休破橐。',48,'全唐诗/poet.song.135000.json','["野寺促晨裝，古驛休破橐。", "雖云行役苦，客子心獨樂。", "家山幸歸來，未免嘆拘縛。", "安得萬里天，翩然下孤鶴。"]'),
('6f68de78-ae21-4842-b579-fc24a92e6ed6','幽居即事九首  其三','陸游','宋','宋诗','song-poetry','','[]','暮年乞殘骸，窮巷事幽屏。',48,'全唐诗/poet.song.135000.json','["暮年乞殘骸，窮巷事幽屏。", "晨興食一簞，有味敵五鼎。", "終日無再炊，奈此夏晝永。", "枯腸不禁攪，戒婢罷煮茗。"]'),
('1df3e4e7-607f-4793-a010-04c72f8dac44','幽居即事九首  其四','陸游','宋','宋诗','song-poetry','','[]','小磑落雪花，修綆汲牛乳。',48,'全唐诗/poet.song.135000.json','["小磑落雪花，修綆汲牛乳。", "幽人作茶供，爽氣生眉宇。", "年來不把酒，杯榼委塵士。", "卧石聽松風，蕭然老桑苧。"]'),
('85aa561f-5ac4-4e57-8e02-ee30eecdc353','幽居即事九首  其五','陸游','宋','宋诗','song-poetry','','[]','日鑄歲幾何，苞苴遍權門。',48,'全唐诗/poet.song.135000.json','["日鑄歲幾何，苞苴遍權門。", "野人求其類，金墺實弟晜。", "超然高世韵，何獨驅睡昏。", "安得如吾宗，坐致顧渚園。"]'),
('fa3278f0-1305-4d4a-bb9a-46a902e26c65','幽居即事九首  其六','陸游','宋','宋诗','song-poetry','','[]','酒能忘事物，不過在醉時。',48,'全唐诗/poet.song.135000.json','["酒能忘事物，不過在醉時。", "麴糵力既盡，萬緒如盎絲。", "阿堵雅見疏，歡伯難與期。", "自憐善用短，時誦止酒詩。"]'),
('1f4cd9ed-0f7d-4eba-82f1-c6a724070973','幽居即事九首  其七','陸游','宋','宋诗','song-poetry','','[]','薰艾割蜜房，荷鋤掘吳朮。',48,'全唐诗/poet.song.135000.json','["薰艾割蜜房，荷鋤掘吳朮。", "誰烹彌明鼎，來薦維摩室。", "厚味不腊毒，上藥能愈疾。", "今夕風月佳，良會不可失。"]'),
('d359685c-5dab-4797-bc20-a2d1ef198781','幽居即事九首  其八','陸游','宋','宋诗','song-poetry','','[]','古人在山林，躬自事樵汲。',48,'全唐诗/poet.song.135000.json','["古人在山林，躬自事樵汲。", "我雖迫耄期，勤慎亦在習。", "掃地拂几硯，何遽力弗給。", "却笑杜陵翁，多卧少行立。"]'),
('a041fefc-1fa0-4373-80cf-39579f67a86e','幽居即事九首  其九','陸游','宋','宋诗','song-poetry','','[]','屏居江海涯，杳杳菰蒲深。',48,'全唐诗/poet.song.135000.json','["屏居江海涯，杳杳菰蒲深。", "俯仰夏令中，澤國正多陰。", "桑椹熟以紫，水鳥時遺音。", "偶得一瓢酒，鄰里聊相尋。"]'),
('0f0becdb-d43e-480a-af13-ab94ee5db52d','醉歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','夜分飲散酒家壚，歸路迢迢月滿湖。',32,'全唐诗/poet.song.135000.json','["夜分飲散酒家壚，歸路迢迢月滿湖。", "小豎竊言翁未醉，入門猶記露菖蒲。"]'),
('f36bb0fa-d75a-4479-acaa-ced8e31470c5','醉歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','烏桕陰中把酒杯，山園處處熟楊梅。',32,'全唐诗/poet.song.135000.json','["烏桕陰中把酒杯，山園處處熟楊梅。", "醉行踸踔人爭看，蹋盡斜陽蹋月來。"]'),
('b92d8eb3-9e57-47db-a642-81f87f54f8e7','書南堂壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','數間破屋住荒郊，暑雨時須自補茅。',64,'全唐诗/poet.song.135000.json','["數間破屋住荒郊，暑雨時須自補茅。", "多病篇章無傑思，長閑樵牧有新交。", "荒唐但向先師愧，骯髒寧辭薄俗嘲。", "偶有會心成獨笑，一林春筍放烟梢。"]'),
('42037b00-c788-44bf-843c-41552f550451','書南堂壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','心溷元知面合團，愚公骨相却酸寒。',64,'全唐诗/poet.song.135000.json','["心溷元知面合團，愚公骨相却酸寒。", "雲山萬疊猶嫌淺，茆屋三間已覺寬。", "菜長何妨供小摘，花開聊得助幽歡。", "今朝忽有西村興，著起芒鞋不作難。"]'),
('8693fd19-3677-4c48-9920-18c8de62721a','五月雨','陸游','宋','宋诗','song-poetry','','[]','空濛五月雨，景氣一番新。',48,'全唐诗/poet.song.135000.json','["空濛五月雨，景氣一番新。", "換盡園林葉，洗空衢路塵。", "山郵惱行客，野渡滯歸人。", "獨有龜堂叟，凉風吹角巾。"]'),
('769334df-30a8-48c9-835f-2d81183c3414','蠶麥','陸游','宋','宋诗','song-poetry','','[]','村村桑暗少桑姑，戶戶麥豐無麥奴。',32,'全唐诗/poet.song.135000.json','["村村桑暗少桑姑，戶戶麥豐無麥奴。", "又是一年春事了，繅絲擣麨笑相呼。"]'),
('a470d158-7fc1-49fc-92d3-4d4d8df3a935','早至園中','陸游','宋','宋诗','song-poetry','','[]','湖上空濛雨熟梅，清晨岸幘一悠哉。',64,'全唐诗/poet.song.135000.json','["湖上空濛雨熟梅，清晨岸幘一悠哉。", "幽花不恨草埋沒，密樹豈知禽去來。", "舊爲愛茶分水器，近緣炊爨得琴材。", "小丘僅見山如髻，尚愧韓公八尺臺。"]'),
('a63e9f43-ff6c-4224-a692-82f8ba69fcfc','憶雲門諸寺','陸游','宋','宋诗','song-poetry','','[]','三百六十日，安可日日愁。',120,'全唐诗/poet.song.135000.json','["三百六十日，安可日日愁。", "四百八十寺，要須寺寺遊。", "雲門若耶間，到處可淹留。", "金像閟古殿，霜鐘發重樓。", "臨澗見魚躍，穿林聞鹿呦。", "亦有疏豁處，白鷺下綠疇。", "僧固非盡佳，終勝從公侯。", "夜闌煎蜜湯，豈不賢杯甌。", "澤居厭溽暑，慨思風露秋。", "晴雨俱可人，亦莫占鳴鳩。"]'),
('8e652407-411c-44fc-a601-d81c6565a72f','贛士曾興宗字光祖以其居篔簹谷圖來求詩','陸游','宋','宋诗','song-poetry','','[]','高人心虛萬物宗，家世常以仕易農。',64,'全唐诗/poet.song.135000.json','["高人心虛萬物宗，家世常以仕易農。", "買山本愛坡上竹，手種已偃巖前松。", "瀑泉三伏凜冰雪，谷聲十里酣笙鏞。", "了知自是一丘壑，不與金精爲附庸。"]'),
('67551e66-8c6b-4559-ae73-22553a7b8604','以菜茹飲酒自嘲','陸游','宋','宋诗','song-poetry','','[]','山澤有臞儒，殘年病滿軀。',48,'全唐诗/poet.song.135000.json','["山澤有臞儒，殘年病滿軀。", "拙疏難救藥，貧困不枝梧。", "海客留苔脯，山僧餉筍枯。", "衰顔得村酒，猶解暫時朱。"]'),
('ccfbf14d-587d-4aa1-966e-ba9cb1a773b2','五月二十一日風雨大作','陸游','宋','宋诗','song-poetry','','[]','風雨縱橫夜徹明，須臾更覺勢如傾。',64,'全唐诗/poet.song.135000.json','["風雨縱橫夜徹明，須臾更覺勢如傾。", "出門已絕近村路，對面不聞高語聲。", "銜舳江關多蜀估，宿師淮浦飽吳粳。", "老民願忍須臾死，傳檄方聞下百城。"]'),
('6e7d778a-9db1-4387-82c2-7b67ec80879b','寄題括蒼陳伯予主簿平楚亭','陸游','宋','宋诗','song-poetry','','[]','琵琶洲上暮山奇，五十餘年役夢思。',64,'全唐诗/poet.song.135000.json','["琵琶洲上暮山奇，五十餘年役夢思。", "與子定交雖可樂，念身垂老亦成悲。", "遠遊倦似風枝鵲，愁思多於繭盎絲。", "安得往尋平楚約，一樽相屬醉題詩。"]'),
('f5ddc43a-07cd-4056-920d-09cf18597492','即事','陸游','宋','宋诗','song-poetry','','[]','歸卧已如狐首丘，不妨解劍換吳牛。',64,'全唐诗/poet.song.135000.json','["歸卧已如狐首丘，不妨解劍換吳牛。", "掃空身外閑榮辱，閲盡樽前舊輩流。", "學道漫希僧坐夏，憂時常愧士防秋。", "一年曆日開强半，嘆息人間歲月遒。"]'),
('7734b1a8-7f11-4ac8-84f3-d36c0889891c','梅雨初霽','陸游','宋','宋诗','song-poetry','','[]','梅雨忽已過，松風來颯然。',48,'全唐诗/poet.song.135000.json','["梅雨忽已過，松風來颯然。", "吟多錦囊富，影瘦角巾偏。", "客祝加餐飯，兒憂少睡眠。", "衰骸累人久，撫事感餘年。"]'),
('f1df6644-419d-4faf-ab48-10291d26499f','夏日雜題六首  其一','陸游','宋','宋诗','song-poetry','','[]','東吳五月黄梅雨，南浦孤舟白髮翁。',32,'全唐诗/poet.song.135000.json','["東吳五月黄梅雨，南浦孤舟白髮翁。", "貂插朝冠金絡馬，多年不入夢魂中。"]'),
('64783d2d-13e3-4358-9655-e73beafe02b5','夏日雜題六首  其二','陸游','宋','宋诗','song-poetry','','[]','午夢初回理舊琴，竹爐重炷海南沉。',32,'全唐诗/poet.song.135000.json','["午夢初回理舊琴，竹爐重炷海南沉。", "茅簷三日蕭蕭雨，又展芭蕉數尺陰。"]'),
('85118b03-069a-4660-8a6f-967d0cb02682','夏日雜題六首  其三','陸游','宋','宋诗','song-poetry','','[]','新縫細葛作蟁裯，簟展風漪凜欲秋。',32,'全唐诗/poet.song.135000.json','["新縫細葛作蟁裯，簟展風漪凜欲秋。", "啼鳥一聲呼夢斷，依然書卷在床頭。"]'),
('0672ec3a-3368-49eb-9eb6-c3a3c476b3ff','夏日雜題六首  其四','陸游','宋','宋诗','song-poetry','','[]','簷前桐影偏宜夏，葉底蟬聲漸報秋。',32,'全唐诗/poet.song.135000.json','["簷前桐影偏宜夏，葉底蟬聲漸報秋。", "莫道衰翁怯風露，也能覓醉水邊樓。"]'),
('b06d4228-e920-4cf8-baa8-0608b494afe1','夏日雜題六首  其五','陸游','宋','宋诗','song-poetry','','[]','渚蒲經雨送微馨，野鶴凌風有墮翎。',32,'全唐诗/poet.song.135000.json','["渚蒲經雨送微馨，野鶴凌風有墮翎。", "歸入衡門天薄暮，清溝淺浸兩三星。"]'),
('9c9df38b-82b7-4ca3-933e-2da9b98f6c3e','夏日雜題六首  其六','陸游','宋','宋诗','song-poetry','','[]','一葉兩葉病木霣，一點兩點疏螢流。',32,'全唐诗/poet.song.135000.json','["一葉兩葉病木霣，一點兩點疏螢流。", "水底星河秋脈脈，髮根風露夜颼颼。"]'),
('2ca6cd1f-0c49-475a-8165-2c051525ad67','晚興','陸游','宋','宋诗','song-poetry','','[]','地荒蓬藋與人齊，局促何曾厭屋低。',64,'全唐诗/poet.song.135000.json','["地荒蓬藋與人齊，局促何曾厭屋低。", "村市船歸聞犬吠，寺樓鐘暝送鴉栖。", "山童新斫朱藤杖，傖婢能醃白苣虀。", "政欲出門尋酒伴，霏霏小雨又成泥。"]'),
('fb12a670-09f7-49ef-b6bc-bc4fd0198beb','急雨','陸游','宋','宋诗','song-poetry','','[]','蝸廬四壁僅容身，赫赫炎曦不貸人。',64,'全唐诗/poet.song.135000.json','["蝸廬四壁僅容身，赫赫炎曦不貸人。", "正喜風清三伏暑，已看雨壓九衢塵。", "寒泉不減中𤃩味，貢茗初嘗正焙新。", "安得凌空雙健羽，徑隨猿鶴上嶙峋。"]'),
('f37fee63-0230-488d-871e-260ef56f6c2a','聽雨','陸游','宋','宋诗','song-poetry','','[]','老態龍鍾疾未平，更堪俗事敗幽情。',32,'全唐诗/poet.song.135000.json','["老態龍鍾疾未平，更堪俗事敗幽情。", "紗幮笛簟差堪樂，且聽蕭蕭暮雨聲。"]'),
('05251e17-4e44-4c69-b30a-379680c79672','窮居戲詠','陸游','宋','宋诗','song-poetry','','[]','賦分雖云薄，謀生亦自疏。',48,'全唐诗/poet.song.135000.json','["賦分雖云薄，謀生亦自疏。", "但令書有種，敢恨食無餘。", "身病慵行立，庭荒廢掃除。", "寒溫雖泛禮，猶辱問何如。"]'),
('b11e066f-bf0e-4546-835f-c15feb67412e','讀窮居五字慨然有感復作一首自解','陸游','宋','宋诗','song-poetry','','[]','布褐營身足，茅茨置榻寬。',48,'全唐诗/poet.song.135000.json','["布褐營身足，茅茨置榻寬。", "食非依漂母，菜不仰園官。", "小蹇鞍韉黑，羸僮骨相酸。", "丹青能寫此，千載尚傳觀。"]'),
('884c008a-e2e7-40dc-99d2-cd6477c5099b','蒙恩封渭南縣伯因刻渭南伯印','陸游','宋','宋诗','song-poetry','','[]','旋著朝衫拜九天，榮光夜半屬星躔。',32,'全唐诗/poet.song.135000.json','["旋著朝衫拜九天，榮光夜半屬星躔。", "渭南且作詩人伴，敢望移封向酒泉。"]'),
('5f7b1018-60c1-47e1-9b2f-3e6e46f78d5b','題門壁','陸游','宋','宋诗','song-poetry','','[]','四十年來住此村，勝衣拜起有曾孫。',64,'全唐诗/poet.song.135000.json','["四十年來住此村，勝衣拜起有曾孫。", "市壚分熟容賒酒，鄰舍情親每饋飧。", "居似窮邊荒馬驛，身如深谷老桑門。", "幸知歲惡緣陂廢，安得農官與細論。"]'),
('02c8a413-1c45-4903-8c56-cd9c03b604db','雨霽','陸游','宋','宋诗','song-poetry','','[]','雨霽禽魚樂，風生草木香。',48,'全唐诗/poet.song.135000.json','["雨霽禽魚樂，風生草木香。", "老驚時易失，閑覺日偏長。", "閤閤蛙何怒，翩翩蝶許忙。", "閉門真得計，切勿變軒昂。"]'),
('3b8ceea3-2851-48f9-b7b5-2dc5498ee08e','西村晚歸','陸游','宋','宋诗','song-poetry','','[]','小塢花垂盡，平堤草次迷。',48,'全唐诗/poet.song.135000.json','["小塢花垂盡，平堤草次迷。", "日長鶑語久，風定絮飛低。", "子響聞棋院，舟橫傍釣溪。", "歸途不知處，依約埭東西。"]'),
('e6cb7da3-30b9-4986-ace2-a2cc7d60701d','連日雲興氣濁雨意欲成西南風輒大作比夜月明如晝','陸游','宋','宋诗','song-poetry','','[]','鳩自呼鳴蚓自歌，何時甘澍一滂沱。',32,'全唐诗/poet.song.135000.json','["鳩自呼鳴蚓自歌，何時甘澍一滂沱。", "封姨漫妒陽臺夢，却付長空與素娥。"]'),
('767cac8d-6efe-45ea-a7fb-212bd7ecc3d5','考古','陸游','宋','宋诗','song-poetry','','[]','考古無長晝，憂時少熟眠。',48,'全唐诗/poet.song.135000.json','["考古無長晝，憂時少熟眠。", "偷生迫鐘漏，戰死愧兜鞬。", "莫報乾坤施，空驚歲月遷。", "藜羹安用糝，吾事本蕭然。"]'),
('43467138-e912-4d12-b231-b096a59b50fe','殘春無幾述意二首  其一','陸游','宋','宋诗','song-poetry','','[]','試筆書盈紙，烹茶睡解圍。',48,'全唐诗/poet.song.135000.json','["試筆書盈紙，烹茶睡解圍。", "新蔬供冷麵，熟練製單衣。", "雛燕飛初穩，殘花見漸稀。", "年衰學不進，默默訟吾非。"]'),
('d26de3d3-520a-47c8-b2b5-0d5775501164','殘春無幾述意二首  其二','陸游','宋','宋诗','song-poetry','','[]','衰疾來無已，流年過若馳。',48,'全唐诗/poet.song.135000.json','["衰疾來無已，流年過若馳。", "家貧食易美，身老夢常悲。", "草長增蛙怒，花空失蝶期。", "不堪多難日，更賦送春詩。"]'),
('4ed96a2c-bd15-4d6b-ba16-fdb6d1659c0f','南堂晨坐','陸游','宋','宋诗','song-poetry','','[]','鏡湖清絕似瀟湘，晨起焚香坐草堂。',64,'全唐诗/poet.song.135000.json','["鏡湖清絕似瀟湘，晨起焚香坐草堂。", "日暖遊絲垂百尺，花殘新蜜釀千房。", "綠桑糝箔開蠶食，白水翻車浸稻秧。", "莫道村翁殺風景，也能沽酒答年光。"]'),
('bdcdbae9-58e8-48c4-a405-25fea44be6db','記悔','陸游','宋','宋诗','song-poetry','','[]','我悔不學農，力耕泥水中。',144,'全唐诗/poet.song.135000.json','["我悔不學農，力耕泥水中。", "二月始穡事，十月畢農功。", "我悔不學醫，早讀黄帝書。", "名方手自緝，上藥如山儲。", "不然去從戎，白首捍塞壖。", "最下作巫祝，爲國祈豐年。", "猶勝業文辭，志在斗升祿。", "一朝陪衆雋，所望亦已足。", "豈知賦命薄，平地成怨仇。", "生爲馬伏櫪，死爲狐首丘。", "已矣何所悲，但悔始謀錯。", "賦詩置座傍，聊以志吾怍。"]'),
('db961b36-fbad-4cd1-a6f6-4c164062c7cd','東園晚興','陸游','宋','宋诗','song-poetry','','[]','宿葉自脫新葉生，東園忽已清陰成。',96,'全唐诗/poet.song.135000.json','["宿葉自脫新葉生，東園忽已清陰成。", "老夫東行復西行，烏藤瘦勁青鞋輕。", "竹鷄群號似知雨，鵓鴣相喚還疑晴。", "萋萋幽草上牆綠，㶁㶁細水循階鳴。", "蕭然濯手坐盤石，心地平安體紓適。", "青山缺處紅日沉，杳杳長空送歸翮。"]'),
('51ec4893-d219-4aa9-a4ed-bc616f722477','晨起行園中','陸游','宋','宋诗','song-poetry','','[]','晨日未出林，庭戶有爽氣。',48,'全唐诗/poet.song.135000.json','["晨日未出林，庭戶有爽氣。", "僮奴課薪水，老子自擁篲。", "稻陂方閔雨，草木亦憔悴。", "群蛙汝何心，尚復作鼓吹。"]'),
('0ef3a277-8f9a-4723-a425-b44293990afc','雷雨','陸游','宋','宋诗','song-poetry','','[]','雲昏失南山，雷過撼北戶。',72,'全唐诗/poet.song.135000.json','["雲昏失南山，雷過撼北戶。", "天其哀此民，畀以三日雨。", "未言高下足，十已得四五。", "雨勢殊未已，喜色徧農圃。", "稽手謁龍公，願言終有秋。", "民饑不敢辭，懼貽明主憂。"]'),
('a7c8a1d2-7220-48a5-9aa3-804a97d24a5d','戲書燕几二首  其一','陸游','宋','宋诗','song-poetry','','[]','平生萬事付天公，白首山林不厭窮。',64,'全唐诗/poet.song.135000.json','["平生萬事付天公，白首山林不厭窮。", "一枕鳥聲殘夢裏，半窗花影獨吟中。", "柴荆日晚猶深閉，烟火年來只僅通。", "水品茶經常在手，前身疑是竟陵翁。"]'),
('fbc78902-11cf-4682-b7fd-2fa7854d8f17','戲書燕几二首  其二','陸游','宋','宋诗','song-poetry','','[]','飽知此手合鋤犁，剩喜東歸老故栖。',64,'全唐诗/poet.song.135000.json','["飽知此手合鋤犁，剩喜東歸老故栖。", "僧乞新詩題院壁，人扶半醉下樓梯。", "少通朝籍讒銷骨，晚畏京塵悔噬臍。", "尚有遠遊心未死，夢携猿鶴渡敷溪。"]'),
('46e765c1-8591-4a62-b302-467dc85797a5','喜雨','陸游','宋','宋诗','song-poetry','','[]','一雨洗旱塵，吾廬氣疏豁。',72,'全唐诗/poet.song.135000.json','["一雨洗旱塵，吾廬氣疏豁。", "土潤竹萌出，水長漁舟活。", "桑麻鬰千里，夾道光如潑。", "憑高望歸雲，更覺原野闊。", "沉憂寬旅食，分喜到僧鉢。", "但仰皇天慈，不必尤旱魃。"]'),
('a551297d-bffe-48c3-a607-a1af1d5026c4','閑適','陸游','宋','宋诗','song-poetry','','[]','閉門萬事不相關，飽受人間一味閑。',64,'全唐诗/poet.song.135000.json','["閉門萬事不相關，飽受人間一味閑。", "琴薦潤生諳雨至，衣篝香冷嘆春殘。", "早曾寄傲風烟表，晚尚鍾情水石間。", "小市酒旗能喚客，試尋鄰曲共開顔。"]'),
('e642af6f-b343-487e-9b6c-5d6f0dba91d4','早晴','陸游','宋','宋诗','song-poetry','','[]','老病常貪睡，蕭蕭厭雨聲。',24,'全唐诗/poet.song.135000.json','["老病常貪睡，蕭蕭厭雨聲。", "翩然兩烏鵲，爲我報新晴。"]'),
('736263b3-69dc-44a3-896b-f05df2dfb145','翦牡丹感懷','陸游','宋','宋诗','song-poetry','','[]','雨聲點滴漏聲殘，短褐猶如二月寒。',64,'全唐诗/poet.song.135000.json','["雨聲點滴漏聲殘，短褐猶如二月寒。", "閉戶自憐今伏老，聯鞍誰記舊追歡。", "欲持藤榼沽春碧，自傍朱欄翦牡丹。", "不爲挂冠方寂寞，宦遊强半是祠官。"]'),
('eb7f56d7-79e4-4ae6-a6a7-f267cf79a2e4','偶觀舊詩書嘆','陸游','宋','宋诗','song-poetry','','[]','吾道運無積，何至墮畦畛。',120,'全唐诗/poet.song.135000.json','["吾道運無積，何至墮畦畛。", "醯鷄舞甕天，乃復自拘窘。", "外物豈移人，子顧不少忍。", "鶴井與狐妖，正可付一哂。", "繁華夢境閙，零亂空花霣。", "可憐憨書生，尚學居易稹。", "我昔亦未免，吟哦琢肝腎。", "落筆過白雨，聚稿森束筍。", "幸能悟差早，念念常自憫。", "安得從碩儒，稽首謝不敏。"]'),
('c419ef22-00b0-4e94-8284-573d7bf00918','聞蜀盜已平獻馘廟社喜而有述','陸游','宋','宋诗','song-poetry','','[]','北伐西征盡聖謨，天聲萬里慰來蘇。',64,'全唐诗/poet.song.135000.json','["北伐西征盡聖謨，天聲萬里慰來蘇。", "橫戈已見吞封豕，徒手何難取短狐。", "學士誰陳平蔡雅，將軍方上取燕圖。", "老生自憫歸耕久，無地能捐六尺軀。"]'),
('31593dff-ee45-4c75-a4bc-341eed7757cd','晚雨','陸游','宋','宋诗','song-poetry','','[]','萬里雙芒屩，終年一布裘。',48,'全唐诗/poet.song.135000.json','["萬里雙芒屩，終年一布裘。", "病侵消壯志，醉著失閑愁。", "琴料憑僧問，巢居與鶴謀。", "晚來疏雨過，探借北窗秋。"]'),
('0299c203-6210-409e-a62c-5fbe5dfbea48','雨晴','陸游','宋','宋诗','song-poetry','','[]','旱暵常思雨，沉陰却喜晴。',48,'全唐诗/poet.song.135000.json','["旱暵常思雨，沉陰却喜晴。", "放船蓮蕩遠，岸幘竹風清。", "淮浦戎初遁，興州盜甫平。", "爲邦要持重，恐復議消兵。"]'),
('a37a26eb-4e94-40ce-9677-b06e0137a6c0','起晚自嘲','陸游','宋','宋诗','song-poetry','','[]','辛苦一生何所獲，老向東阡與南陌。',64,'全唐诗/poet.song.135000.json','["辛苦一生何所獲，老向東阡與南陌。", "頭眩眼暗牙齒疏，能作人間幾時客。", "爾來偷惰更可笑，卧聽場中打新麥。", "老鷄失旦也似儂，引頸一呼窗已白。"]'),
('5365e729-8023-4412-925d-5d6d1743e83e','閑中偶詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','斷編殘稿本徒勞，橫得虛名亦已叨。',64,'全唐诗/poet.song.135000.json','["斷編殘稿本徒勞，橫得虛名亦已叨。", "不識狐書那是博，尚分鶴料敢言高。", "巢山且欲營丹竈，跨海何當看雪濤。", "與世不諧終自許，笑人苦勸學餔糟。"]'),
('c5a54a3c-4a33-46f5-8753-b4416ed41ca1','閑中偶詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','舉世紛紛名利間，天公偏賦此身閑。',64,'全唐诗/poet.song.135000.json','["舉世紛紛名利間，天公偏賦此身閑。", "塵衣濯罷滄浪水，茅舍歸來會計山。", "鄰舍擎盤分麥飯，野人曳杖叩柴關。", "酒逋詩債何時了，未死何妨且旋還。"]'),
('12c5efd5-5811-4e4f-a3b3-ae74f768d068','晚步湖塘少休民家','陸游','宋','宋诗','song-poetry','','[]','瓜蔓緣籬竹，蘆芽刺岸沙。',48,'全唐诗/poet.song.135000.json','["瓜蔓緣籬竹，蘆芽刺岸沙。", "橫陂浮雁鶩，古道暗桑麻。", "適遇扶犁叟，同休織屨家。", "村童亦可念，喚客手吒叉。"]'),
('d9b92e61-7ab8-4954-9bab-9edc1413612b','獨酌罷夜坐','陸游','宋','宋诗','song-poetry','','[]','不見麴生久，惠然相與娛。',48,'全唐诗/poet.song.135000.json','["不見麴生久，惠然相與娛。", "安能論斗石，僅可具盤盂。", "聽雨蒙僧衲，挑燈擁地爐。", "勿生孤寂念，道伴有狸奴。"]'),
('94aa3e22-5d6c-467c-85f0-d30938fb72e2','雨中出門閑望有作','陸游','宋','宋诗','song-poetry','','[]','急雨初來已瀉簷，清香欲散更穿簾。',64,'全唐诗/poet.song.135000.json','["急雨初來已瀉簷，清香欲散更穿簾。", "年開九秩尚不死，坐對一編殊未饜。", "人笑黠癡俱得半，自憐貧病每相兼。", "說梅古謂能蠲渴，戲出街頭望酒帘。"]'),
('fa3a5084-34e3-461e-b868-796fd50d44cb','示二子','陸游','宋','宋诗','song-poetry','','[]','豈不懷榮畏友朋，一生凜凜蹈春冰。',64,'全唐诗/poet.song.135000.json','["豈不懷榮畏友朋，一生凜凜蹈春冰。", "任真雖笑拘邊幅，達節寧容出準繩。", "自喜殘年如白傅，更憐諸子慕崔丞。", "耄期尚有江湖興，頑健人言見未曾。"]'),
('2b1283ef-6d9a-421a-88f2-c47f53d730ec','道室秋夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','江上窮秋日，庵中獨夜時。',48,'全唐诗/poet.song.135000.json','["江上窮秋日，庵中獨夜時。", "丹靈驅豎子，神定出嬰兒。", "粱熟猶餘夢，柯摧未畢棋。", "神仙元可學，往矣不須疑。"]'),
('047b4f3d-451e-41b3-80de-248ccd5f3630','道室秋夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','道室生虛白，仙經寫硬黄。',48,'全唐诗/poet.song.135000.json','["道室生虛白，仙經寫硬黄。", "晨杯擎石髓，夜几照松肪。", "眼力新生犢，心源百鍊鋼。", "何當登日觀，萬里看扶桑。"]'),
('223bcd5d-8ead-43b6-bcc0-8e8ac23c5b07','醉題','陸游','宋','宋诗','song-poetry','','[]','雲棲澗飲未爲高，起舞行歌亦足豪。',64,'全唐诗/poet.song.135000.json','["雲棲澗飲未爲高，起舞行歌亦足豪。", "試問食時觀本草，何如酒後讀離騷。", "遊山不待飛雙舄，翦水無因得快刀。", "熟睡市壚君勿笑，年來隨事學餔糟。"]'),
('5fa7e2ca-6977-46eb-9146-e7cfadd66191','自詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','忽忽殘年及耄期，清晨對鏡不須悲。',32,'全唐诗/poet.song.135000.json','["忽忽殘年及耄期，清晨對鏡不須悲。", "遠行久立雖差倦，未到人扶見客時。"]'),
('4f4f5f65-f0b2-4a16-bf04-8febe099765b','自詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','食飲從來戒失時，衣裘亦復要隨宜。',32,'全唐诗/poet.song.135000.json','["食飲從來戒失時，衣裘亦復要隨宜。", "老人最索調停處，正在初寒與半饑。"]'),
('297a6c88-7c02-4026-bc5d-112114ffebe6','秋晴','陸游','宋','宋诗','song-poetry','','[]','身健心閑百慮輕，秋晴未必減春晴。',64,'全唐诗/poet.song.135000.json','["身健心閑百慮輕，秋晴未必減春晴。", "晨窗暖日烘花氣，午枕微風送鳥聲。", "韞玉硯凹宜墨色，冷金箋滑助詩情。", "少年風味嗟猶在，虛道歸休學力耕。"]'),
('c0a44418-f6a3-4387-948f-3bd33a616386','門外獨望','陸游','宋','宋诗','song-poetry','','[]','離離遠樹傍烟津，又見清秋一歲新。',64,'全唐诗/poet.song.135000.json','["離離遠樹傍烟津，又見清秋一歲新。", "老眼厭看南北路，流年暗換往來人。", "鑄金遺像誰能記，執玉來朝適已陳。", "况我風中斷蓬耳，夕陽空復一傷神。"]'),
('0cc4199e-237c-47c5-b875-961cbe5488a2','貧歌','陸游','宋','宋诗','song-poetry','','[]','壽居福之首，貧爲士之常。',72,'全唐诗/poet.song.135000.json','["壽居福之首，貧爲士之常。", "造物賦我貧，乃以壽見償。", "處常而受福，每恐不得當。", "掬澗以沃渴，屑柏以爲糧。", "雖云未免饑，何至死道傍。", "猶勝遼東丁，化鶴還故鄉。"]'),
('0ac362f1-47fd-46c6-aac2-043cc75fa80d','秋晚雜興十二首  其一','陸游','宋','宋诗','song-poetry','','[]','汀樹猶青未著霜，壟間稗穗已先黄。',32,'全唐诗/poet.song.135000.json','["汀樹猶青未著霜，壟間稗穗已先黄。", "放翁皓首歸民籍，爛醉狂歌坐簀床。"]'),
('f353912b-ba14-4b2d-bd94-89236df8e880','秋晚雜興十二首  其二','陸游','宋','宋诗','song-poetry','','[]','昔遇高皇起衆材，姓名曾得厠鄒枚。',32,'全唐诗/poet.song.135000.json','["昔遇高皇起衆材，姓名曾得厠鄒枚。", "年逾八十猶賒死，却伴鄰翁斸芋魁。"]'),
('c0f990ca-4735-4335-8856-eb7b681d8dc1','秋晚雜興十二首  其三','陸游','宋','宋诗','song-poetry','','[]','老病侵凌不可當，時時攬鏡自悲傷。',32,'全唐诗/poet.song.135000.json','["老病侵凌不可當，時時攬鏡自悲傷。", "西風吹散朝來酒，依舊衰顔似葉黄。"]'),
('bb707f19-12dc-4e1a-8968-d2a2b2635f1d','秋晚雜興十二首  其四','陸游','宋','宋诗','song-poetry','','[]','冷落秋風把酒杯，半酣直欲挽春回。',32,'全唐诗/poet.song.135000.json','["冷落秋風把酒杯，半酣直欲挽春回。", "今年菰菜嘗新晚，正與鱸魚一併來。"]'),
('4d2ce255-dab3-46b6-b2c8-44d1c43c2fe7','秋晚雜興十二首  其五','陸游','宋','宋诗','song-poetry','','[]','置酒何由辦咄嗟，清言深愧淡生涯。',32,'全唐诗/poet.song.135000.json','["置酒何由辦咄嗟，清言深愧淡生涯。", "聊將橫浦紅絲磑，自作蒙山紫筍茶。"]'),
('bf67e899-4162-47b4-b4e0-b5b5177e63a4','秋晚雜興十二首  其六','陸游','宋','宋诗','song-poetry','','[]','洗耳高人耻見堯，看渠應不受弓招。',32,'全唐诗/poet.song.135000.json','["洗耳高人耻見堯，看渠應不受弓招。", "精神徇物那能久，刀礪君看日日銷。"]'),
('d64549c0-ecb0-483c-9770-1bfeed775751','秋晚雜興十二首  其七','陸游','宋','宋诗','song-poetry','','[]','石帆山下醉清秋，常伴漁翁弄小舟。',32,'全唐诗/poet.song.135000.json','["石帆山下醉清秋，常伴漁翁弄小舟。", "箬笠照溪吾自喜，貂蟬誰管出兜鍪。"]'),
('178988dd-6e12-4b65-a307-ce0ef8b71611','秋晚雜興十二首  其八','陸游','宋','宋诗','song-poetry','','[]','烟波萬頃鏡湖秋，清嘯雖聞不可求。',32,'全唐诗/poet.song.135000.json','["烟波萬頃鏡湖秋，清嘯雖聞不可求。", "自是世間知者少，山林何代乏巢由。"]'),
('26640182-bde3-41da-8dac-62b8a4fb5ea4','秋晚雜興十二首  其九','陸游','宋','宋诗','song-poetry','','[]','禹巡吾國三千歲，陳迹銷沉渺莽中。',32,'全唐诗/poet.song.135000.json','["禹巡吾國三千歲，陳迹銷沉渺莽中。", "豈獨江山無定主，苔磯知換幾漁翁。"]'),
('01a62002-8fe0-4924-b43e-a132b156bfcd','秋晚雜興十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','江東誰復識重瞳，遺廟欹斜草棘中。',32,'全唐诗/poet.song.135000.json','["江東誰復識重瞳，遺廟欹斜草棘中。", "若比咿嚶念如意，烏江戰死尚英雄。"]'),
('3ca580b8-4dd2-45c2-8f4a-82450e770d17','秋晚雜興十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','漠漠漁村烟雨中，參差蒼檜映丹楓。',32,'全唐诗/poet.song.135000.json','["漠漠漁村烟雨中，參差蒼檜映丹楓。", "古來畫手知多少，除却范寬無此工。"]'),
('f4d4c499-804f-4ffa-a69e-3ed74a0bbf30','秋晚雜興十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','渺渺風烟接小江，牛頭山色滿蓬窗。',32,'全唐诗/poet.song.135000.json','["渺渺風烟接小江，牛頭山色滿蓬窗。", "門前西走錢塘路，也有閑人似老龐。"]'),
('0bee2d5a-230f-43cb-ab24-40ca0059b11e','霜風','陸游','宋','宋诗','song-poetry','','[]','霜風近海夜颼颼，敢效庸人念褐裘。',64,'全唐诗/poet.song.135000.json','["霜風近海夜颼颼，敢效庸人念褐裘。", "關吏雖通西域貢，王師猶護北平秋。", "黄旗馳奏有三捷，金印酬功多列侯。", "願補顔行身已老，區區畎畝亦私憂。"]'),
('d02d008e-44cd-48c9-a390-e0efe479273a','贈丐士','陸游','宋','宋诗','song-poetry','','[]','志士寧聞畢世窮，此間從古混蛇龍。',32,'全唐诗/poet.song.135000.json','["志士寧聞畢世窮，此間從古混蛇龍。", "尚能忍耻墦間祭，安用追慚飯後鐘。"]'),
('304f546a-1f78-48fc-8e2c-7b8810282d27','贈目眇者','陸游','宋','宋诗','song-poetry','','[]','達人所遇有生涯，高卧窮閻自一家。',32,'全唐诗/poet.song.135000.json','["達人所遇有生涯，高卧窮閻自一家。", "閲世正嫌巖下電，開樽且看霧中花。"]'),
('83bdd257-d746-4607-90af-6423fe7efb1b','閑遊所至少留得長句五首  其一','陸游','宋','宋诗','song-poetry','','[]','畫橈艇子短馿鞦，野店山郵每小留。',64,'全唐诗/poet.song.135000.json','["畫橈艇子短馿鞦，野店山郵每小留。", "瓜蔓水生初抹岸，梅黄雨細欲遮樓。", "遼東邂逅從歸鶴，海上逢迎得狎鷗。", "豈是人間偏好異，暮年難復作沉浮。"]'),
('bf76aa76-54ae-4976-b50c-935e380f0773','閑遊所至少留得長句五首  其二','陸游','宋','宋诗','song-poetry','','[]','垣屋參差桑竹繁，意行漫漫不知村。',64,'全唐诗/poet.song.135000.json','["垣屋參差桑竹繁，意行漫漫不知村。", "眼明可數遠山疊，足健直窮流水源。", "鷺引釣船經荻浦，牛隨牧笛入柴門。", "試尋高處休行李，清絕應須入夢魂。"]'),
('b02883c9-5a03-4bc7-9e75-68f92e587b9b','閑遊所至少留得長句五首  其三','陸游','宋','宋诗','song-poetry','','[]','太平人物自諧嬉，及我青鞋布襪時。',64,'全唐诗/poet.song.135000.json','["太平人物自諧嬉，及我青鞋布襪時。", "丁壯趁晴收早粟，比鄰結伴絡新絲。", "圓鼙坎坎迎神社，大字翩翩賣酒旗。", "晤語豈無黄叔度，欲尋幽徑過牛醫。"]'),
('ac5d6827-e9af-4d93-aa21-9c5a83ecd20a','閑遊所至少留得長句五首  其四','陸游','宋','宋诗','song-poetry','','[]','已過樵塢到漁村，逢著人家即叩門。',64,'全唐诗/poet.song.135000.json','["已過樵塢到漁村，逢著人家即叩門。", "僧釜藜羹加糝美，市壚黍酒带醅渾。", "頹齡更愧才能薄，故里方知輩行尊。", "身迫九原兒亦老，一經猶欲教諸孫。"]'),
('bfdaacfb-20dc-40eb-bae0-e6271de4e067','閑遊所至少留得長句五首  其五','陸游','宋','宋诗','song-poetry','','[]','高僧宴坐雪蒙頭，閑牧從來水牯牛。',64,'全唐诗/poet.song.135000.json','["高僧宴坐雪蒙頭，閑牧從來水牯牛。", "深院陰陰四簷雨，高堂寂寂一簾秋。", "光明本自無餘欠，夢幻何曾有去留。", "我亦翛然五湖客，不妨相與試茶甌。"]'),
('a84820d5-7cc8-4335-9a56-7a04990f1170','晚雨','陸游','宋','宋诗','song-poetry','','[]','春旱久閔雨，夏潦復望晴。',72,'全唐诗/poet.song.135000.json','["春旱久閔雨，夏潦復望晴。", "米盡薪亦絕，漲水與階平。", "山信得新粟，欣然聽舂聲。", "書生易滿足，筆硯還施行。", "南風柱礎乾，西照窗戶明。", "雨其遂已乎，努力趣秋成。"]'),
('14a6314f-7313-4507-8e6a-89522bb4a8b6','翌日早晴','陸游','宋','宋诗','song-poetry','','[]','澤居傍海壖，暑雨困積潦。',96,'全唐诗/poet.song.135000.json','["澤居傍海壖，暑雨困積潦。", "四顧路俱絕，所至泥浩浩。", "坐卧敗屋中，兀若在孤島。", "得米無束薪，端憂令人老。", "今朝復何朝，浮雲散如掃。", "一蟬鳴高槐，兩蝶點平草。", "欣然受凉颸，便欲事幽討。", "呼童羈我駒，東走天台道。"]'),
('38e7208f-d9d8-4c9f-b915-102a9e3a947b','一雨二十日','陸游','宋','宋诗','song-poetry','','[]','一雨二十日，雨意殊未闌。',72,'全唐诗/poet.song.135000.json','["一雨二十日，雨意殊未闌。", "我廬大澤中，四顧烟水寬。", "東家有小舟，借我不作難。", "鸕鷀與鵁鶄，自是平生歡。", "更作十日期，水淺生小灘。", "相與極幽賞，勿待江月殘。"]'),
('181c4959-625c-41a2-820f-f4e93590e8a3','入夏多雨雖止復作六月甲寅始大晴','陸游','宋','宋诗','song-poetry','','[]','兼旬大雨無晝夜，積潦深虞敗吾稼。',96,'全唐诗/poet.song.135000.json','["兼旬大雨無晝夜，積潦深虞敗吾稼。", "豈惟一飽墮渺茫，直恐下溼侵腰胯。", "南風忽從木末來，新月徘徊出雲罅。", "州家出符縣家喜，泄水漸空梁可架。", "放翁亦復扶病起，旋築頹牆補茆舍。", "便合觀身作老禪，安心穩坐今年夏。"]'),
('436837e5-7052-406c-935b-4a62a39b6a02','題尊信齋','陸游','宋','宋诗','song-poetry','','[]','於虖孔孟何其卓，如天日月地海嶽。',160,'全唐诗/poet.song.135000.json','["於虖孔孟何其卓，如天日月地海嶽。", "正令舉世皆楊墨，邪正豈復勞商榷。", "雖然此道久橫流，執熱其誰不思濯。", "魯鄒遺書世皆讀，要以尊信爲善學。", "吾友希真蓋其人，不肯俯首爲齷齪。", "羹藜飯豆欲老矣，功雖未竟志則慤。", "我居山陰子在閩，闕然不見千里邈。", "澤中久雨道路絕，叩戶忽聞聲剝啄。", "尊信二字子所知，妙質豈復須斤斲。", "伏生九十語已訛，失旦自慚猶喔喔。"]'),
('d35ac23f-9f90-481d-8b47-0cd3983dcbde','夏日雜詠四首  其一','陸游','宋','宋诗','song-poetry','','[]','閑居自無客，况復暑如焚。',48,'全唐诗/poet.song.135000.json','["閑居自無客，况復暑如焚。", "百折赴溪水，數峰當戶雲。", "幽尋窮鹿徑，靜釣雜鷗群。", "舊愛南華語，今方踐所聞。"]'),
('96a86d45-d6a5-4a96-b1e4-4ec14a39fbdc','夏日雜詠四首  其二','陸游','宋','宋诗','song-poetry','','[]','兀兀從誰語，𥉂𥉂寄一床。',48,'全唐诗/poet.song.135000.json','["兀兀從誰語，𥉂𥉂寄一床。", "不嗟頭似葆，但苦汗如漿。", "欹枕風生竹，鈎簾日轉廊。", "非由靜勝熱，本體自清凉。"]'),
('a73b5a3e-b74d-4596-b70e-6abc3960a56a','夏日雜詠四首  其三','陸游','宋','宋诗','song-poetry','','[]','蒲葦蕭蕭晚，楸梧肅肅陰。',48,'全唐诗/poet.song.135000.json','["蒲葦蕭蕭晚，楸梧肅肅陰。", "山童驚大鼾，林鳥伴微吟。", "蠻硯深潴墨，吳箋熟擣碪。", "新詩與醉帖，自笑尚童心。"]'),
('37b87303-268f-4e90-a503-4c6da1044c63','夏日雜詠四首  其四','陸游','宋','宋诗','song-poetry','','[]','省事心君靜，忘情眼界平。',48,'全唐诗/poet.song.135000.json','["省事心君靜，忘情眼界平。", "食便餐酪美，浴試葛衣輕。", "鶴整千年駕，鷗尋萬里盟。", "秋風即在眼，作意上青城。"]'),
('20c1a1dd-ff6f-46c6-a457-d8d2fc0ea671','夏日四首  其一','陸游','宋','宋诗','song-poetry','','[]','颼颼風露髮根凉，月落菱歌盡意長。',32,'全唐诗/poet.song.135000.json','["颼颼風露髮根凉，月落菱歌盡意長。", "分得鏡湖纔一曲，喫虧堪笑賀知章。"]'),
('8f855b98-afd0-4d74-9d5e-27e200b627bb','夏日四首  其二','陸游','宋','宋诗','song-poetry','','[]','新闢虛堂痛掃除，蕭然終日屏僮奴。',32,'全唐诗/poet.song.135000.json','["新闢虛堂痛掃除，蕭然終日屏僮奴。", "此間恐是維摩室，除却藜床一物無。"]'),
('0b735fe5-c1c5-4ca5-b888-b635bb5a02ba','夏日四首  其三','陸游','宋','宋诗','song-poetry','','[]','平明一浴汗無餘，坐覺胸中合太虛。',32,'全唐诗/poet.song.135000.json','["平明一浴汗無餘，坐覺胸中合太虛。", "舂玉作糜天所賜，不妨數筯進山蔬。"]'),
('31aecba0-e4a8-48f6-ac78-ea52aaa1c2ca','夏日四首  其四','陸游','宋','宋诗','song-poetry','','[]','草芝方出峨眉老，力比金丹似更多。',32,'全唐诗/poet.song.135000.json','["草芝方出峨眉老，力比金丹似更多。", "秦不及期周過曆，始知養壽在中和。"]'),
('d3fe3144-b101-446e-918c-7802bdca71e4','苦熱','陸游','宋','宋诗','song-poetry','','[]','炎歊行中天，曼膚汗翻水。',96,'全唐诗/poet.song.135000.json','["炎歊行中天，曼膚汗翻水。", "纖絺薄如霧，不異鎧被體。", "散髮垂兩肩，萬事棄不理。", "寸陰若度歲，日暮何可俟。", "頗聞交廣間，暑又烈於此。", "此如不可耐，彼豈皆暍死。", "聊當扶短策，北澗弄清泚。", "豈必拜賜冰，恩光動閭里。"]'),
('233ce12f-957e-4a62-a71b-63a49dfa3788','予頃遊青城數從上官道翁遊暑中忽思其人','陸游','宋','宋诗','song-poetry','','[]','往年屢遊丈人祠，上官八十如嬰兒。',96,'全唐诗/poet.song.135000.json','["往年屢遊丈人祠，上官八十如嬰兒。", "自言少年聾不治，芝房松鬣可無饑。", "叩之不答但解頤，德人之容端可師。", "我聞學道當精思，畢世不可須臾離。", "公雖泯默意可知，亡羊要是緣多岐。", "逝從公遊亦未遲，聯杖跨海尋安期。"]'),
('d1505ab0-4a33-42dd-a271-d0292156eb2e','龜堂','陸游','宋','宋诗','song-poetry','','[]','障日松棚正策功，幅巾聊得受微風。',64,'全唐诗/poet.song.135000.json','["障日松棚正策功，幅巾聊得受微風。", "蟬聲不斷草堂靜，潦水已歸村路通。", "拄杖閑行穿犖确，孤雲時見起巃嵸。", "東陽醇酎無由到，知負今年幾碧筩。"]'),
('8a3c8897-a9e7-491b-a7eb-5f3ac9bb9672','夢中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','試說山翁事，諸君且勿譁。',48,'全唐诗/poet.song.135000.json','["試說山翁事，諸君且勿譁。", "百年看似夢，萬里不思家。", "夜艾猶添酒，春殘更覓花。", "却嗤勾漏令，辛苦學丹砂。"]'),
('54f6c77a-77db-4f12-8bed-8de592bd836c','夢中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','平羌江上月，伴我故山來。',48,'全唐诗/poet.song.135000.json','["平羌江上月，伴我故山來。", "幽興依然在，浮雲正爾開。", "清秋纔幾日，黄葉已成堆。", "未醉江樓酒，扁舟可得回。"]'),
('14541055-5e5b-4dcf-aa81-50df765e4da0','秋近頗有凉意','陸游','宋','宋诗','song-poetry','','[]','平旦麵數箸，晡時飯一杯。',48,'全唐诗/poet.song.135000.json','["平旦麵數箸，晡時飯一杯。", "枝梧長日過，悵望早秋來。", "團扇尋詩寫，緇巾借樣裁。", "惟應水邊坐，待得市船回。"]'),
('ea2ea845-2d39-43e1-a7b4-4f8d1952a5d6','夜坐中庭凉甚','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','銀漢迢迢夜氣澄，都忘朝暮困蚊蠅。',64,'全唐诗/poet.song.135000.json','["銀漢迢迢夜氣澄，都忘朝暮困蚊蠅。", "月從東涌行空闊，風自南來洗鬰蒸。", "渴解似嘗仙掌露，魂清如近玉壺冰。", "誰知此際超然處，不減廬山入定僧。"]'),
('c606ff7a-201c-494f-820e-2c276f4c91de','東偏小室去日最遠每爲逃暑之地戲作五字','陸游','宋','宋诗','song-poetry','','[]','肅肅簷陰轉，泠泠筧水鳴。',48,'全唐诗/poet.song.135000.json','["肅肅簷陰轉，泠泠筧水鳴。", "高墉日氣遠，方簟午風清。", "渴愛餐漿美，慵便葛屨輕。", "新秋忽在眼，結束問山程。"]'),
('84179f07-1672-4590-870f-92355258bd9b','野寺','陸游','宋','宋诗','song-poetry','','[]','僧壁題名半闕訛，重來嘆息屢摩挲。',64,'全唐诗/poet.song.135000.json','["僧壁題名半闕訛，重來嘆息屢摩挲。", "林蟬欲斷暮復急，竹露如傾秋更多。", "半俸漸償賒酒券，故衫已換釣魚蓑。", "西窗一看枯棋罷，歸去還憂爛斧柯。"]'),
('f5c05867-5810-49f5-a731-d7bdf7596e78','南堂雜興八首  其一','陸游','宋','宋诗','song-poetry','','[]','車馬無聲晝漏長，野人與世已相忘。',64,'全唐诗/poet.song.135000.json','["車馬無聲晝漏長，野人與世已相忘。", "屏除長物軒楹爽，洗濯塵襟肺腑凉。", "秋近平郊鳴鸛鶴，日斜荒徑下牛羊。", "興來欲喚筇枝去，更盡銅爐一炷香。"]'),
('1537f70b-48bc-4b3d-943e-15475ca22b54','南堂雜興八首  其二','陸游','宋','宋诗','song-poetry','','[]','新凉一夜入郊墟，晨起衣巾爽有餘。',64,'全唐诗/poet.song.135000.json','["新凉一夜入郊墟，晨起衣巾爽有餘。", "燕欲委巢雛盡去，扇猶在手意先疏。", "題詩又滿牛腰束，采樂常携鴉觜鋤。", "湖上從今風月好，不妨隨處命籃輿。"]'),
('779cbf98-1d28-4e73-a481-8b21aa181a2b','南堂雜興八首  其三','陸游','宋','宋诗','song-poetry','','[]','蛩聲每續蟬聲起，桐葉仍兼柳葉凋。',64,'全唐诗/poet.song.135000.json','["蛩聲每續蟬聲起，桐葉仍兼柳葉凋。", "懶惰心情疏筆硯，久長生計屬漁樵。", "鬋茅旋補東廂屋，伐石新成北港橋。", "物外高人來往熟，等閑折簡也能招。"]'),
('2fccb3e1-3ce5-49cb-be7a-51ec62245948','南堂雜興八首  其四','陸游','宋','宋诗','song-poetry','','[]','耄齒東歸息故廬，聊持頑健託鄉閭。',64,'全唐诗/poet.song.135000.json','["耄齒東歸息故廬，聊持頑健託鄉閭。", "未忘麈尾清談興，常讀蠅頭細字書。", "貧甚尚能耕有犢，步輕那嘆出無馿。", "南堂又見秋風起，卧看溪雲自捲舒。"]'),
('68d9df6f-a217-4850-a671-4128d6ee471f','南堂雜興八首  其五','陸游','宋','宋诗','song-poetry','','[]','奔走當年一念差，歸休別覺是生涯。',64,'全唐诗/poet.song.135000.json','["奔走當年一念差，歸休別覺是生涯。", "茆簷喚客家常飯，竹院隨僧自在茶。", "禪欠遍參寧得髓，詩緣獨學不名家。", "如今百事無能解，只擬清秋上釣槎。"]'),
('bd228c8d-5135-4aff-892d-6df5772aa7a1','南堂雜興八首  其六','陸游','宋','宋诗','song-poetry','','[]','十里城南禾黍村，白頭心事與誰論。',64,'全唐诗/poet.song.135000.json','["十里城南禾黍村，白頭心事與誰論。", "惰偷已墜先人訓，迂拙仍辜聖主恩。", "病退時時親蠹簡，興來往往出柴門。", "斜陽倚杖君知否，收點鷄豚及未昏。"]'),
('75881842-fe1f-4b32-a188-53c808831bff','南堂雜興八首  其七','陸游','宋','宋诗','song-poetry','','[]','年過八十更應稀，又向清秋聽擣衣。',64,'全唐诗/poet.song.135000.json','["年過八十更應稀，又向清秋聽擣衣。", "一片雨來書幔黑，數聲鐘斷釣船歸。", "酒壚好事能焚券，齏甕無情未解圍。", "剩欲出門尋一笑，故人零落嘆疇依。"]'),
('7d96f425-839c-4b19-a021-e092c3a5f953','南堂雜興八首  其八','陸游','宋','宋诗','song-poetry','','[]','北連大澤驚秋早，東限連林覺曉遲。',64,'全唐诗/poet.song.135000.json','["北連大澤驚秋早，東限連林覺曉遲。", "數筯藥苗留客話，一爐松火約僧棋。", "人間掃迹雖堪笑，物外論心頗自奇。", "有恨未償猶絕嘆，青城交舊待多時。"]'),
('d7263b8b-1958-47f2-971e-b79efa39ea42','新秋往來湖山間四首  其一','陸游','宋','宋诗','song-poetry','','[]','車似鷄栖舟似葉，百里何曾勞步屧。',64,'全唐诗/poet.song.135000.json','["車似鷄栖舟似葉，百里何曾勞步屧。", "朝遊樵風弄清泚，暮泊石帆登岌嶪。", "旅飯雖舂纔脫粟，僧羹無菜寧用挾。", "歸來村落未上燈，除却御風無此捷。"]'),
('37c2e89b-27fc-4971-9741-cbd0dff9231d','新秋往來湖山間四首  其二','陸游','宋','宋诗','song-poetry','','[]','會稽山下樵風溪，翠屏倒影青玻璃。',64,'全唐诗/poet.song.135000.json','["會稽山下樵風溪，翠屏倒影青玻璃。", "尤奇峭壁立千仞，行子欲上無階梯。", "商山坐看紫芝老，武陵無奈桃花迷。", "人間得意妄自喜，一鬨憐汝真醯鷄。"]'),
('58b5547f-cdde-40e6-8ad4-5e22fa7d03a4','新秋往來湖山間四首  其三','陸游','宋','宋诗','song-poetry','','[]','禹祠巍巍閲千代，廣殿修廊半傾壞。',64,'全唐诗/poet.song.135000.json','["禹祠巍巍閲千代，廣殿修廊半傾壞。", "屹然遺窆每摩挲，石長苔侵字猶在。", "去年已愧曳杖來，今者更用兒扶拜。", "聊持一酌薦丹衷，衰疾龍鍾神所貸。"]'),
('17853ea9-7b6a-4f46-83d2-61fcfdebb6a2','新秋往來湖山間四首  其四','陸游','宋','宋诗','song-poetry','','[]','健席高檣梅市路，朱橋綠樹蘭亭步。',64,'全唐诗/poet.song.135000.json','["健席高檣梅市路，朱橋綠樹蘭亭步。", "兒時釣遊略可記，不料耄年猶此處。", "漁歌相和葦間起，菱船遠入烟中去。", "世間萬事等浮雲，耐久誰如兩芒屨。"]'),
('1b004fb0-5214-48c6-907b-e83e9f4c639b','北崦','陸游','宋','宋诗','song-poetry','','[]','毒熱憚輕出，新凉尋舊盟。',48,'全唐诗/poet.song.135000.json','["毒熱憚輕出，新凉尋舊盟。", "西郊猶近市，北崦漸謀耕。", "松菊有佳色，山林無俗情。", "行行望績火，一點隔林明。"]'),
('c7008aba-4d72-455c-91fc-6f6006ed569e','小室逃暑','陸游','宋','宋诗','song-poetry','','[]','千頃菰蒲萬里風，漁翁散髮卧孤篷。',32,'全唐诗/poet.song.135000.json','["千頃菰蒲萬里風，漁翁散髮卧孤篷。", "何如此室纔尋丈，常在冰壺雪窖中。"]'),
('e93620ca-7a6f-4262-a8e1-cf8b7564f9f6','秋雨中作','陸游','宋','宋诗','song-poetry','','[]','燈前劇論與誰同，中歲朋儕亦已空。',64,'全唐诗/poet.song.135000.json','["燈前劇論與誰同，中歲朋儕亦已空。", "行道敢希千載上，會心聊付一編中。", "雨侵壞甃新苔綠，秋入橫林數葉紅。", "莫怪又生湖海興，此身元自是孤篷。"]'),
('50500dd4-d823-4fb5-af82-b64091f3ef20','目昏有感','陸游','宋','宋诗','song-poetry','','[]','兩眥眵昏八十餘，爾來觸事覺空疏。',32,'全唐诗/poet.song.135000.json','["兩眥眵昏八十餘，爾來觸事覺空疏。", "何由四目如蒼頡，讀盡當年倚相書。"]'),
('33b78360-790f-437d-b007-ad43f94e893f','幽居','陸游','宋','宋诗','song-poetry','','[]','一曲清溪带淺山，幽居終日卧林間。',64,'全唐诗/poet.song.135000.json','["一曲清溪带淺山，幽居終日卧林間。", "丹經在昔曾親授，死籍從今或可刪。", "人笑拙疏安淡泊，天教强健享清閑。", "秋來漸有佳風月，擬與飛仙日往還。"]'),
('a1270c6a-5758-45c0-be7f-7533cc4c60bf','初秋即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','簾櫳雨過不勝清，秋氣依依似有情。',64,'全唐诗/poet.song.135000.json','["簾櫳雨過不勝清，秋氣依依似有情。", "高棟尚餘雙燕宿，短莎先放百蟲鳴。", "挑燈剩欲開書帙，擘蟹時須近酒觵。", "却愧鄰家常作苦，探租黄犢待寒耕。"]'),
('4ab6990b-4e85-42f4-8dd8-1e3d34c2d958','初秋即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','老來閲世苦匆匆，又見流年入鬢蓬。',64,'全唐诗/poet.song.135000.json','["老來閲世苦匆匆，又見流年入鬢蓬。", "山徑溼螢黏露草，井床病葉霣秋風。", "鄰翁每共藜羹味，稚子能終汗簡功。", "造物於人元不薄，未須抵掌嘆囊空。"]'),
('af3be817-63d1-4eb1-91fe-320c47a6ef82','山庖','陸游','宋','宋诗','song-poetry','','[]','新舂䆉䅉滑如珠，旋壓犁祁軟勝酥。',32,'全唐诗/poet.song.135000.json','["新舂䆉䅉滑如珠，旋壓犁祁軟勝酥。", "更翦藥苗挑野菜，山家不必遠庖厨。"]'),
('9df036f9-a240-46f2-9ebf-d32dd543a917','題道傍壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','晚境那禁歲月催，幽花又見澗邊開。',32,'全唐诗/poet.song.135000.json','["晚境那禁歲月催，幽花又見澗邊開。", "莫辭剩買旗亭酒，恐有騎馿李白來。"]'),
('8e3639f7-b1e8-4524-b555-6da2e7d3ead9','題道傍壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','湖廢財存十二三，拍堤漲水尚如藍。',32,'全唐诗/poet.song.135000.json','["湖廢財存十二三，拍堤漲水尚如藍。", "吾廬隠翳初非意，頗欲臨流結草庵。"]'),
('1a3165e9-02fb-4352-95c5-80f986535e1c','訪野老','陸游','宋','宋诗','song-poetry','','[]','農事元知要細評，野人有舊得尋盟。',64,'全唐诗/poet.song.135000.json','["農事元知要細評，野人有舊得尋盟。", "林深未見果蔬地，舍近先聞鷄犬聲。", "春水築塘謀竭作，陽坡卧犢約同耕。", "老來常嘆人情薄，深愧今朝倒屐迎。"]'),
('14005fa3-1933-46a5-98c1-0165d6c8e1dd','書適','陸游','宋','宋诗','song-poetry','','[]','架竹苫茅屋數椽，推開窗戶即江天。',64,'全唐诗/poet.song.135000.json','["架竹苫茅屋數椽，推開窗戶即江天。", "微饑未遽愁長日，小疾何妨度厄年。", "孤鶴入秋偏警露，斷山欲雨自生烟。", "囊中妙法君知否，買斷清閑不用錢。"]'),
('6a02f76e-3894-431a-bf05-d517f0db61b3','憶蜀','陸游','宋','宋诗','song-poetry','','[]','憶昔西遊日，岷峨勝事繁。',48,'全唐诗/poet.song.135000.json','["憶昔西遊日，岷峨勝事繁。", "題詩古柏廟，載酒海棠園。", "世故紛難料，年光浩莫論。", "所欣身尚健，短褐醉江村。"]'),
('5d791f4c-bb61-4f33-94f4-358d660b0654','生涯四首  其一','陸游','宋','宋诗','song-poetry','','[]','生涯數畦菜，心事一溪雲。',48,'全唐诗/poet.song.135000.json','["生涯數畦菜，心事一溪雲。", "樵擔斜陽下，漁歌靜夜聞。", "門無俗駕到，厨有遠泉分。", "但了麴糵事，功名烏足云。"]'),
('4780de52-5b00-437f-af62-8ec6313e330e','生涯四首  其二','陸游','宋','宋诗','song-poetry','','[]','身世茫如夢，門庭冷似冰。',48,'全唐诗/poet.song.135000.json','["身世茫如夢，門庭冷似冰。", "逢迎賣藥叟，辭謝乞錢僧。", "羸疾時時劇，衰顔日日增。", "人扶亦可出，要是藉烏藤。"]'),
('85d58881-0a5b-4e7e-9a4d-594d4368a6bf','生涯四首  其三','陸游','宋','宋诗','song-poetry','','[]','舊業桑麻在，頹齡耄耋過。',48,'全唐诗/poet.song.135000.json','["舊業桑麻在，頹齡耄耋過。", "虞卿著書晚，伏叟授經訛。", "井上磨樵斫，村東買釣蓑。", "傾身營一飽，自笑又蹉跎。"]'),
('74cdf73f-6cf6-4ef5-b5aa-98a70bc01141','生涯四首  其四','陸游','宋','宋诗','song-poetry','','[]','殘年端有幾，寂寞寄滄洲。',48,'全唐诗/poet.song.135000.json','["殘年端有幾，寂寞寄滄洲。", "鳥宿千林暮，蟲鳴四壁秋。", "風廊動碪杵，月壟把鉏耰。", "衣食隨宜具，何心復浪求。"]'),
('61f8c09c-e46a-4c79-8e1b-7732b0e3ea1a','對食作','陸游','宋','宋诗','song-poetry','','[]','潦餘多稼猶中熟，種晚嘉蔬亦半收。',64,'全唐诗/poet.song.135000.json','["潦餘多稼猶中熟，種晚嘉蔬亦半收。", "黄耳蕈生殊自喜，白頭韭長復何求。", "比量傍舍慚溫飽，誦詠農書儆墮偷。", "偶有一樽難獨啜，過門誰肯小遲留。"]'),
('b233f0ed-6a75-47f4-ad03-e2ac5e851894','曉思','陸游','宋','宋诗','song-poetry','','[]','昏昏斷夢带餘酲，散髮披衣坐待明。',64,'全唐诗/poet.song.135000.json','["昏昏斷夢带餘酲，散髮披衣坐待明。", "城角吹殘河漸隠，海氛消盡日初生。", "老農自得當年樂，癡子方爭後世名。", "莫怪閉門常懶出，即今車蓋爲誰傾。"]'),
('d45d367e-18f0-4468-b4fb-ad9431883233','戲書','陸游','宋','宋诗','song-poetry','','[]','柳下人家枳作籬，小姑不畫入時眉。',32,'全唐诗/poet.song.135000.json','["柳下人家枳作籬，小姑不畫入時眉。", "緯車聲出窗扉裏，正是新凉夜永時。"]'),
('0cdec03c-ab89-47f9-9337-2059a91c7a73','梅市舟中作','陸游','宋','宋诗','song-poetry','','[]','漕渠北向小橋通，漸入蒼茫大澤中。',32,'全唐诗/poet.song.135000.json','["漕渠北向小橋通，漸入蒼茫大澤中。", "造物將無知我醉，故吹急雨打船篷。"]'),
('ce58bfd1-896b-48bf-831d-505bce359a71','孤店','陸游','宋','宋诗','song-poetry','','[]','孤店門前千萬峰，酒濃不抵別愁濃。',32,'全唐诗/poet.song.135000.json','["孤店門前千萬峰，酒濃不抵別愁濃。", "明朝晴雨吾能卜，但聽蘭亭古寺鐘。"]'),
('72a8000c-bace-4089-9ccb-061562be8f77','過魯墟先太傅舊隠','陸游','宋','宋诗','song-poetry','','[]','桑竹蕭條带夕陽，故居依約古河傍。',32,'全唐诗/poet.song.135000.json','["桑竹蕭條带夕陽，故居依約古河傍。", "頹垣壞甃無尋處，父老猶言學士莊。"]'),
('1066378e-c675-4057-9e39-bafba58a016c','步月','陸游','宋','宋诗','song-poetry','','[]','鷗鷺論交有舊盟，越山勝處著柴荆。',64,'全唐诗/poet.song.135000.json','["鷗鷺論交有舊盟，越山勝處著柴荆。", "只思小閣焚香卧，偶作長堤蹋月行。", "湖闊烟鐘來縹緲，林疏漁火見分明。", "店家已賣新篘酒，一醉今宵似可成。"]'),
('4f2a5cfe-28de-4309-9f64-71189f072fb7','拄杖示子遹','陸游','宋','宋诗','song-poetry','','[]','拄杖相從四十年，交情耐久獨依然。',64,'全唐诗/poet.song.135000.json','["拄杖相從四十年，交情耐久獨依然。", "西窮巫峽岷江路，北抵岐山渭水邊。", "早已歸休弄泉石，老猶緩步歷風烟。", "會同鉢袋并禪版，付與兒孫世世傳。"]'),
('cadc80ae-0dd1-4638-9fc4-3b4905435bf0','讀道書','陸游','宋','宋诗','song-poetry','','[]','一境有神龍，歲不畏枯旱。',96,'全唐诗/poet.song.135000.json','["一境有神龍，歲不畏枯旱。", "爲國常得賢，百世不可亂。", "吾讀黄老書，掩卷每三嘆。", "正使未長生，去死亦差緩。", "如何不自力，白首猶漫漶。", "友朋死略盡，日月難把玩。", "豈無獨往願，兒孫苦羈絆。", "安得葛與陶，相從明此段。"]'),
('b8a6fb7c-4a26-4280-9b20-55c515d50150','秋日睡起','陸游','宋','宋诗','song-poetry','','[]','白露已過天益凉，練衣初覆篝爐香。',64,'全唐诗/poet.song.135000.json','["白露已過天益凉，練衣初覆篝爐香。", "天其閔我老且憊，付以美睡聲撼牆。", "離騷古文傍倦枕，砥柱巨刻懸高堂。", "睡餘一讀搔短髮，萬壑松風秋興長。"]'),
('db4cb47f-7937-40fd-ad0c-f56771ab28ba','書意','陸游','宋','宋诗','song-poetry','','[]','屋漏徙我床，窗破補其罅。',120,'全唐诗/poet.song.135000.json','["屋漏徙我床，窗破補其罅。", "衣穿傲狐貉，食淡忘膾炙。", "人生老可哀，百事就衰謝。", "我喜在得歸，味美如啖蔗。", "雖云茅茨陋，豈不賢傳舍。", "兒能牧鷄豚，身自種桑柘。", "市壚酒易賒，鄰廄馿可借。", "睡任門生嘲，醉無官長駡。", "見書眼先閉，惰懶亦自赦。", "却後五百年，林間作佳話。"]'),
('89634337-7767-40f4-823b-a80c1d6e97a1','寄題龔立道崑山棲閑堂','陸游','宋','宋诗','song-poetry','','[]','我居山陰古大澤，出門尚恨風烟迮。',96,'全唐诗/poet.song.135000.json','["我居山陰古大澤，出門尚恨風烟迮。", "欲求曠快舒眼力，夢中去作棲閑客。", "棲閑主人計不疏，萬卷讀盡家藏書。", "平時不喜入城府，况肯自屈承明廬。", "聽鷄束带誰不爾，明時可仕君獨止。", "不妨借地作園林，買山豈是巢由事。"]'),
('b4688ffe-01a5-49db-bd89-61603577c0f7','秋雨書感二首  其一','陸游','宋','宋诗','song-poetry','','[]','新舂赤米摘青蔬，一飽從來不願餘。',64,'全唐诗/poet.song.135000.json','["新舂赤米摘青蔬，一飽從來不願餘。", "門外久無溫卷客，架中寧有熱官書。", "濁醪未廢時時啜，短髮猶須日日梳。", "自笑少年風味在，滿川烟雨正愁予。"]'),
('58055349-c6ce-44e5-9ae1-72d9f7133131','秋雨書感二首  其二','陸游','宋','宋诗','song-poetry','','[]','晨起開門雪滿簪，東崗一徑得幽尋。',64,'全唐诗/poet.song.135000.json','["晨起開門雪滿簪，東崗一徑得幽尋。", "斷雲殘雨歲華晚，丹實碧花秋意深。", "林下已悲身老病，人間猶與俗浮沉。", "床頭小甕今朝熟，又喚鄰翁共淺斟。"]'),
('65e3117c-3cca-48c8-abee-49c67848dc39','弄筆','陸游','宋','宋诗','song-poetry','','[]','少學文章竟不成，暮年腕弱字欹傾。',32,'全唐诗/poet.song.135000.json','["少學文章竟不成，暮年腕弱字欹傾。", "抽毫欲下還休去，棐几空憐似砥平。"]'),
('6c282405-3ac3-4907-a739-f057d97e9043','睡覺作二首  其一','陸游','宋','宋诗','song-poetry','','[]','世言黄帝華胥境，千古蓁荒孰再遊。',32,'全唐诗/poet.song.135000.json','["世言黄帝華胥境，千古蓁荒孰再遊。", "但解消搖化蝴蝶，不須富貴慕蚍蜉。"]'),
('f44608cb-a0dc-45a6-8b05-0eefa36906dc','睡覺作二首  其二','陸游','宋','宋诗','song-poetry','','[]','邯鄲夢事豈關身，未熟黄粱迹已陳。',32,'全唐诗/poet.song.135000.json','["邯鄲夢事豈關身，未熟黄粱迹已陳。", "輸與烏衣老鈴下，日中睡覺一顰伸。"]'),
('3eabca93-fc10-4608-8a2e-08546c1054aa','秋思十首  其一','陸游','宋','宋诗','song-poetry','','[]','露濃壓架葡萄熟，日嫩登場䆉䅉香。',32,'全唐诗/poet.song.135000.json','["露濃壓架葡萄熟，日嫩登場䆉䅉香。", "商略人生如意事，及身强健得還鄉。"]'),
('bb2a634f-4119-43f0-b78a-3816a458d3b3','秋思十首  其二','陸游','宋','宋诗','song-poetry','','[]','三三兩兩戲魚行，香餌纔投去若驚。',32,'全唐诗/poet.song.135000.json','["三三兩兩戲魚行，香餌纔投去若驚。", "寄與扁舟五湖客，只當遠引過平生。"]'),
('630aed74-6112-4787-a452-9d7935750d2b','秋思十首  其三','陸游','宋','宋诗','song-poetry','','[]','一篇舊草天台賦，六幅新傳太華圖。',32,'全唐诗/poet.song.135000.json','["一篇舊草天台賦，六幅新傳太華圖。", "占盡人間清絕事，紫藤香起竹根爐。"]'),
('323d81c1-5bc0-4d16-9e0d-3bb6b3fea174','秋思十首  其四','陸游','宋','宋诗','song-poetry','','[]','村南村北鵓鴣鳴，小雨霏霏又作晴。',32,'全唐诗/poet.song.135000.json','["村南村北鵓鴣鳴，小雨霏霏又作晴。", "拂枕欹眠不成夢，却拖藤杖出門行。"]'),
('31929d14-dcdc-475a-8152-05e0c7eeb3ed','秋思十首  其五','陸游','宋','宋诗','song-poetry','','[]','出門東行復西行，處處人家打稻聲。',32,'全唐诗/poet.song.135000.json','["出門東行復西行，處處人家打稻聲。", "小甕秫醅雖未熟，後園楮蕈已堪烹。"]'),
('10cfb583-5851-4549-931b-7273317513c0','秋思十首  其六','陸游','宋','宋诗','song-poetry','','[]','看雲廬阜屏風疊，采藥嵩山冠子峰。',32,'全唐诗/poet.song.135000.json','["看雲廬阜屏風疊，采藥嵩山冠子峰。", "行盡四方心未快，不如一櫂醉吳松。"]'),
('7fa832d3-8521-4ab8-b280-f8efd5c9325b','秋思十首  其七','陸游','宋','宋诗','song-poetry','','[]','桑竹成陰不見門，牛羊分路各歸村。',32,'全唐诗/poet.song.135000.json','["桑竹成陰不見門，牛羊分路各歸村。", "前山雨過雲無迹，別浦潮回岸有痕。"]'),
('2579437c-0496-4dc6-8543-caddf269ec51','秋思十首  其八','陸游','宋','宋诗','song-poetry','','[]','鄰砧落日數聲殘，汀樹秋風幾葉丹。',32,'全唐诗/poet.song.135000.json','["鄰砧落日數聲殘，汀樹秋風幾葉丹。", "冉冉清愁來不斷，無方能使酒腸寬。"]'),
('b0daa80d-1b39-477d-8063-245acb92b03d','秋思十首  其九','陸游','宋','宋诗','song-poetry','','[]','老子齋居罷擊鮮，木盤竹筯每隨緣。',32,'全唐诗/poet.song.135000.json','["老子齋居罷擊鮮，木盤竹筯每隨緣。", "鄰僧不用分香鉢，蓮芡猶堪過半年。"]'),
('97ebb824-7182-4c01-a140-8a994291dd44','秋思十首  其一○','陸游','宋','宋诗','song-poetry','','[]','存神止慮自長年，黄老遺書漢尚傳。',32,'全唐诗/poet.song.135000.json','["存神止慮自長年，黄老遺書漢尚傳。", "妙語雖傳人不省，却從丹竈覓神仙。"]'),
('7ac8a5dc-1beb-4f8e-a670-764de8b6ad5f','秋來苦貧戲作','陸游','宋','宋诗','song-poetry','','[]','閉門高卧養吾真，說著生涯笑倒人。',64,'全唐诗/poet.song.135000.json','["閉門高卧養吾真，說著生涯笑倒人。", "奴閔囊空辭雇直，婢愁爨冷拾炊薪。", "羹能有糝猶爲泰，地到無錐始是貧。", "一飯不妨支一日，讀書常愧聒比鄰。"]'),
('c7924f1b-16e5-48d0-9fe6-386f681b1c17','晚晴','陸游','宋','宋诗','song-poetry','','[]','雨餘殘日入疏籬，變化相乘乃爾奇。',64,'全唐诗/poet.song.135000.json','["雨餘殘日入疏籬，變化相乘乃爾奇。", "千嶂暮雲收盡後，一年秋暑洗空時。", "如山酒券不相貸，隔巷衣砧如許悲。", "剩欲出門紓滯思，交親零落與誰期。"]'),
('8a39c0b2-1e3d-4950-aa83-b1d6c3d10d6e','對月二首  其一','陸游','宋','宋诗','song-poetry','','[]','遠客厭征路，流年逢素秋。',24,'全唐诗/poet.song.135000.json','["遠客厭征路，流年逢素秋。", "不知今夜月，還照幾人愁。"]'),
('e315ad3b-e4b2-4a7d-999d-96280264b104','對月二首  其二','陸游','宋','宋诗','song-poetry','','[]','草草治杯盤，三更月露寒。',24,'全唐诗/poet.song.135000.json','["草草治杯盤，三更月露寒。", "茆簷雖隠翳，終勝客中看。"]'),
('79bbe4c9-9756-48a8-88c2-1c228ac6df03','出近村晚歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','松枝代如意，綀布製單衣。',48,'全唐诗/poet.song.135000.json','["松枝代如意，綀布製單衣。", "出每沾晨露，歸當送夕暉。", "野花當路發，沙鳥背人飛。", "到舍燈初上，茅簷聞踏機。"]'),
('9388b7ed-6ace-4e1c-8f33-6a008db5ca0f','出近村晚歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','苦雨秋將晚，羈愁酒易醺。',48,'全唐诗/poet.song.135000.json','["苦雨秋將晚，羈愁酒易醺。", "百年終腐骨，萬事盡浮雲。", "果熟多猿嗛，林疏過鹿群。", "亦思書觸目，老懶不成文。"]'),
('2c28de1f-3e6c-4048-9efe-566e09c70944','秋晚','陸游','宋','宋诗','song-poetry','','[]','鷄聲喔喔頻催曉，木葉颼颼已變秋。',64,'全唐诗/poet.song.135000.json','["鷄聲喔喔頻催曉，木葉颼颼已變秋。", "憂患縱多終强項，饑寒未至且優游。", "老羆尚欲身當道，乳虎何疑氣食牛。", "但有一愁消未得，大兒白髮戍邊頭。"]'),
('2bb4b752-3a50-442e-aaf7-4049f46bcd7f','犬鷄','陸游','宋','宋诗','song-poetry','','[]','小犬一何警，日夜吠籬落。',48,'全唐诗/poet.song.135000.json','["小犬一何警，日夜吠籬落。", "老鷄則不然，平旦方喔喔。", "勤惰各其性，於我何厚薄。", "糠粞一施之，且復慰寂寞。"]'),
('25a07a63-df7a-4a68-9e03-1f9f6895584f','賣藥翁','陸游','宋','宋诗','song-poetry','','[]','老翁如我老，賣藥以代耕。',48,'全唐诗/poet.song.135000.json','["老翁如我老，賣藥以代耕。", "得錢付酒家，一毫不自營。", "浩歌和鄰叟，苦語誨後生。", "我欲爲作傳，無人知姓名。"]'),
('565ce1aa-b916-404c-a4e8-0259c87fb406','書里中事','陸游','宋','宋诗','song-poetry','','[]','事近接耳目，誕信良易知。',48,'全唐诗/poet.song.135000.json','["事近接耳目，誕信良易知。", "頗疑有定數，一惑不可移。", "坐視非所安，忠告反取疑。", "雖抱愚直意，妄發悔曷追。"]'),
('c24bf85d-5e77-4da6-b6bf-e70477f83934','書室雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','秋水淺出灘，秋葉落成陣。',48,'全唐诗/poet.song.135000.json','["秋水淺出灘，秋葉落成陣。", "方喜風露清，已嘆霜霰近。", "衰疾雖向平，不死亦堇堇。", "燈青地爐冷，吾學其少進。"]'),
('4763842a-4512-4c43-b62b-52dd2b8486b7','書室雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','衣多藏之笥，食餘積之囷。',48,'全唐诗/poet.song.135000.json','["衣多藏之笥，食餘積之囷。", "我享既有限，富亦豈勝貧。", "布褐本自溫，筍蕨固已珍。", "君看梁伯鸞，寄食終其身。"]'),
('55623d2f-0bbd-4128-a82f-310a3f59d6a3','書室雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','老眼觀細書，紛然黑花墜。',48,'全唐诗/poet.song.135000.json','["老眼觀細書，紛然黑花墜。", "不如袖手坐，嘿誦舊所記。", "但恨志弗强，編簡頗失次。", "後身作書生，努力究此事。"]'),
('65472bd6-7942-43d5-aeb5-2119380a83a9','書室雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','學書五十年，其進不及寸。',48,'全唐诗/poet.song.135000.json','["學書五十年，其進不及寸。", "未能踐繩墨，况敢說豪健。", "雖然亦有用，尚足博粗飯。", "開學教牛經，坐市寫馿券。"]'),
('edff05f0-8c6c-4c34-9925-b08debac63b1','秋感','陸游','宋','宋诗','song-poetry','','[]','瘦盡腰圍白盡頭，悲蛩聲裏落梧秋。',64,'全唐诗/poet.song.135000.json','["瘦盡腰圍白盡頭，悲蛩聲裏落梧秋。", "短檠且慰經年別，豎褐猶懷卒歲憂。", "天地無私嗟獨困，風霜有信又殘秋。", "頑軀安得常强健，更倚東吳寺寺樓。"]'),
('6ed4ccd1-4990-4fb3-bb07-6691e2aeb908','秋夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','秋色滿江干，江楓已半丹。',48,'全唐诗/poet.song.135000.json','["秋色滿江干，江楓已半丹。", "身閑詩簡淡，道勝夢輕安。", "偃蹇憐腰折，清癯鄙面團。", "何妨杵衣夜，又見歲將殘。"]'),
('67df6e4a-74ea-411c-b9e9-4267cb1b030a','秋夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','落葉鳴遥夜，啼螿送暮秋。',48,'全唐诗/poet.song.135000.json','["落葉鳴遥夜，啼螿送暮秋。", "不知何許笛，故此作時愁。", "青海三年戍，黄旗萬里侯。", "何如石帆下，烟雨釣滄洲。"]'),
('cd699e76-ba9a-4eab-92ef-cc81247c9ab2','秋日村舍二首  其一','陸游','宋','宋诗','song-poetry','','[]','會稽城南古大澤，霜晴水落烟波迮。',64,'全唐诗/poet.song.135000.json','["會稽城南古大澤，霜晴水落烟波迮。", "寒風蕭蕭凋櫸柳，暖日暉暉秀蕎麥。", "傳聞新詔募新軍，復道公車納群策。", "忠誠所感金石開，勉建功名垂竹帛。"]'),
('92ce9ce3-fd66-45f7-8494-6bf87fb7b3ea','秋日村舍二首  其二','陸游','宋','宋诗','song-poetry','','[]','川雲慘慘欲成雨，宿麥蒼蒼初覆土。',64,'全唐诗/poet.song.135000.json','["川雲慘慘欲成雨，宿麥蒼蒼初覆土。", "芋肥一本可專車，蟹壯兩螯能敵虎。", "村村婚嫁花簇簷，廟廟禱祠神降語。", "兒孫力稼供賦租，千年萬年報明主。"]'),
('4e86b1b5-e8c0-4f97-a6ac-60fe0a50d54d','村遊','陸游','宋','宋诗','song-poetry','','[]','閉戶苦無憀，行行不覺遥。',48,'全唐诗/poet.song.135000.json','["閉戶苦無憀，行行不覺遥。", "人稀廢古井，水退築新橋。", "野店聽山雨，僧厨餽藥苗。", "湖中有高士，折簡恐難招。"]'),
('da35b8ca-ecda-44d5-9a1a-7c1c65295902','吳歌','陸游','宋','宋诗','song-poetry','','[]','勝負兩蝸角，榮枯一蟻窠。',48,'全唐诗/poet.song.135000.json','["勝負兩蝸角，榮枯一蟻窠。", "人情苦翻覆，吾意久蹉跎。", "困睫憑茶醒，衰顔頼酒酡。", "坐人能聽否，試爲若吳歌。"]'),
('a3cebb3f-856e-458c-895c-9bb8cb040986','秋感二首  其一','陸游','宋','宋诗','song-poetry','','[]','扶杖龍鍾迫耄期，江湖木落更堪悲。',64,'全唐诗/poet.song.135000.json','["扶杖龍鍾迫耄期，江湖木落更堪悲。", "醉中光景似得志，夢裏朋儕如少時。", "落筆龍蛇仲蒙帖，滿懷風月季長詩。", "前朝名勝凋零盡，百歲關心只自知。"]'),
('035535a3-d8cf-4b92-b257-fb9f0f83f7c5','秋感二首  其二','陸游','宋','宋诗','song-poetry','','[]','聖世優容許乞身，歸來猶幸齒齊民。',64,'全唐诗/poet.song.135000.json','["聖世優容許乞身，歸來猶幸齒齊民。", "漁家那有懸車地，蔬食何施祝鯁人。", "獠婢臨溪漂衣絮，蠻童掃葉續炊薪。", "生涯如此仍秋暮，頼是從來慣處貧。"]'),
('53feba9f-15bb-4fa9-a118-c55652fbc8fe','紹興辛未至丙子六年間予年方壯每遇重九多與一時名士登高於蕺山宇泰閣距開禧丁卯六十年憂患契闊何所不有追數同遊諸公乃無一人在者而予猶强健慘愴不能已賦詩識之','陸游','宋','宋诗','song-poetry','','[]','故里登高接雋遊，即今不計幾番秋。',64,'全唐诗/poet.song.135000.json','["故里登高接雋遊，即今不計幾番秋。", "一樽尚與菊花醉，萬事不禁江水流。", "薄命雖多死閭巷，逢時亦有至公侯。", "若論耄歲朱顔在，窮達皆當輸一籌。"]'),
('277e9429-ec41-4b79-9de2-e68d16b0f63c','結茅','陸游','宋','宋诗','song-poetry','','[]','結茆湖曲兩三間，客少柴荆盡日關。',64,'全唐诗/poet.song.135000.json','["結茆湖曲兩三間，客少柴荆盡日關。", "插架圖書娛晚暮，滿灘鷗鷺伴清閑。", "壁龕吳晉千年字，窗納秦稽萬疊山。", "自怪堅頑推不倒，時來臨水照蒼顔。"]'),
('7edfe0c5-a82f-452d-b9ab-7ef127cf8724','老健','陸游','宋','宋诗','song-poetry','','[]','年垂九十身猶健，竹屋荆扉不厭低。',64,'全唐诗/poet.song.135000.json','["年垂九十身猶健，竹屋荆扉不厭低。", "挈榼自沽深巷酒，擁衾遥聽別村鷄。", "家添豚柵還堪賦，路認牛欄每不迷。", "惟恨窮秋開霽少，晚來小雨又成泥。"]'),
('fd775398-6c6a-4d19-8c99-832870c792e6','幽居即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','壯歲本亡奇，頹齡又及斯。',48,'全唐诗/poet.song.135000.json','["壯歲本亡奇，頹齡又及斯。", "極知身有幾，惟是醉相宜。", "燒草溫新犢，編籬護伏雌。", "謀生未忘念，笑語路傍兒。"]'),
('e606574a-ace4-47e2-b6ee-bb2a68ea0c41','幽居即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','晚日照茅茨，西風吹接䍦。',48,'全唐诗/poet.song.135000.json','["晚日照茅茨，西風吹接䍦。", "貧思止酒易，老悔養丹遲。", "斸地秋畦藥，焚香夜揲蓍。", "呼兒具舟檝，吾欲上湘灕。"]'),
('878cf48a-f4e5-4428-ad56-8a53b9496ccd','秋晚書感','陸游','宋','宋诗','song-poetry','','[]','犧象初心豈願才，溝中雖斷不須哀。',64,'全唐诗/poet.song.135000.json','["犧象初心豈願才，溝中雖斷不須哀。", "吾生自信雲舒卷，客態誰論燕去來。", "夕露正看沾草棘，晨霜已見落楸槐。", "耄年閉戶真無憾，葑火更闌熟芋魁。"]'),
('bbe97d7b-4b40-4cd4-82f1-89cbc4042d86','小市暮歸','陸游','宋','宋诗','song-poetry','','[]','愛酒行行訪市酤，醉中亦有稚孫扶。',64,'全唐诗/poet.song.135000.json','["愛酒行行訪市酤，醉中亦有稚孫扶。", "林梢殘葉吹都盡，烟際孤舟遠欲無。", "野餉每思羹苜蓿，旅炊猶得飯雕胡。", "青山在眼何時到，堪嘆年來病滿軀。"]'),
('5a07a3f4-2113-46e0-991e-66c04c566c0f','寓嘆三首  其一','陸游','宋','宋诗','song-poetry','','[]','日夕羊牛下，月明烏鵲飛。',48,'全唐诗/poet.song.135000.json','["日夕羊牛下，月明烏鵲飛。", "林林皆有託，貿貿獨安歸。", "疾痼方求藥，秋高未製衣。", "岷峨不遂隠，更恨昔謀非。"]'),
('562a42e3-1231-4a4f-a8d4-1c5cf320bf49','寓嘆三首  其二','陸游','宋','宋诗','song-poetry','','[]','交世非初志，謀生又絕疏。',48,'全唐诗/poet.song.135000.json','["交世非初志，謀生又絕疏。", "家貧思辟穀，人忌悔知書。", "門異回軒巷，乘無禿尾馿。", "老頑君勿怪，萬事有乘除。"]'),
('71c3f198-421b-4fca-9fba-457243d8ba56','寓嘆三首  其三','陸游','宋','宋诗','song-poetry','','[]','短髮不禁搔，紓悲頼濁醪。',48,'全唐诗/poet.song.135000.json','["短髮不禁搔，紓悲頼濁醪。", "潦收溪瀨急，木落寺樓高。", "善飯餘何欠，看雲亦足豪。", "今朝有奇事，江浦得霜螯。"]'),
('5fe4f45b-ba85-42b4-befc-172fd7170ba1','題僧庵','陸游','宋','宋诗','song-poetry','','[]','細路穿雲塢，危橋渡野塘。',48,'全唐诗/poet.song.135000.json','["細路穿雲塢，危橋渡野塘。", "人稀土花碧，屋老瓦松長。", "憂患雙蓬鬢，裝資一布囊。", "燒薪藉餘暖，今夜有新霜。"]'),
('6a02d981-b2e7-48ad-b449-73cddd45b229','哭季長二首  其一','陸游','宋','宋诗','song-poetry','','[]','岷山剡曲各天涯，死籍前時偶脫遺。',64,'全唐诗/poet.song.135000.json','["岷山剡曲各天涯，死籍前時偶脫遺。", "三徑就荒俱已老，一樽相屬永無期。", "寢門哀慟今何及，泉壤從遊後不疑。", "邂逅子孫能記此，交情應似兩翁時。"]'),
('2a4a6069-16ca-456e-a244-c3a3d9d7e3dd','哭季長二首  其二','陸游','宋','宋诗','song-poetry','','[]','我荷鋤時君賜環，君歸我復造清班。',64,'全唐诗/poet.song.135000.json','["我荷鋤時君賜環，君歸我復造清班。", "無由促席暫握手，每得寄聲聊解顔。", "造物不令成老伴，著書猶喜在名山。", "半年僅得陳蓴鯽，白首臨風涕自潸。"]'),
('d1e8fba8-7056-428e-8d22-7212747c9113','魔境作頗思遠適賦此自遣','陸游','宋','宋诗','song-poetry','','[]','夜夜燃燈旦旦香，修行老尚墮微茫。',64,'全唐诗/poet.song.135000.json','["夜夜燃燈旦旦香，修行老尚墮微茫。", "齋居自許塵心盡，遇事方知業力强。", "兩屨生雲入灊皖，孤舟載月上瀟湘。", "道人行李君毋笑，惟是蓍筒與藥囊。"]'),
('84614d6f-9f21-4297-8a5a-5535734020d7','枕上','陸游','宋','宋诗','song-poetry','','[]','窗紙蕭蕭印月痕，數聲新雁過江村。',64,'全唐诗/poet.song.135000.json','["窗紙蕭蕭印月痕，數聲新雁過江村。", "孤愁不與夢俱斷，羸老豈知身尚存。", "世事萬端歸蠹簡，秋風百感集清樽。", "荷鋤家圃知何憾，猶勝生求入玉門。"]'),
('f40164a7-5cad-4dd6-808a-e18990eb4668','讀豳詩','陸游','宋','宋诗','song-poetry','','[]','我讀豳風七月篇，聖賢事事在陳編。',64,'全唐诗/poet.song.135000.json','["我讀豳風七月篇，聖賢事事在陳編。", "豈惟王業方興日，要是淳風未散前。", "屈宋遺音今尚絕，咸韶古奏更誰傳。", "吾曹所學非章句，白髮青燈一泫然。"]'),
('cb218083-d0a0-4197-9ece-a79db5a8453a','北窗','陸游','宋','宋诗','song-poetry','','[]','半世蟬嘶坐北窗，耄年依舊守殘缸。',64,'全唐诗/poet.song.135000.json','["半世蟬嘶坐北窗，耄年依舊守殘缸。", "買書安得黄金百，覓句如求白璧雙。", "老氣尚思吞夢澤，壯遊曾是釣巴江。", "寒生事業秋毫盡，筆力終慚鼎可扛。"]'),
('9f51cfbb-5e91-40a3-a87a-71d3599cc771','小圃醉中作','陸游','宋','宋诗','song-poetry','','[]','搖落園林探借春，耄期詩酒肯輸人。',64,'全唐诗/poet.song.135000.json','["搖落園林探借春，耄期詩酒肯輸人。", "狂時湖海猶嫌迮，達處羲農亦未淳。", "木葉蔽身如盛服，藜羹加糝即常珍。", "巢由尚隠唐虞代，漫道桃源是避秦。"]'),
('50443e2b-b381-494c-887e-1b1209c458aa','秋冬之交雜賦六首  其一','陸游','宋','宋诗','song-poetry','','[]','蓬戶終年閉，靈臺一事無。',48,'全唐诗/poet.song.135000.json','["蓬戶終年閉，靈臺一事無。", "貧猶能自活，衰未藉人扶。", "兒學無歆異，孫啼有啟呱。", "東鄰麴道士，折簡也能呼。"]'),
('4db9c90b-4d7d-4d8e-865b-2856ad2f815b','秋冬之交雜賦六首  其二','陸游','宋','宋诗','song-poetry','','[]','霽日收殘靄，微霜作早寒。',48,'全唐诗/poet.song.135000.json','["霽日收殘靄，微霜作早寒。", "桐凋無宿葉，水退出新灘。", "室小纔容膝，門低每觸冠。", "平生只此是，何物動憂端。"]'),
('12cf5923-fe7d-47cb-a9b8-f96273ea3784','秋冬之交雜賦六首  其三','陸游','宋','宋诗','song-poetry','','[]','避俗嫌林淺，安貧覺屋寬。',48,'全唐诗/poet.song.135000.json','["避俗嫌林淺，安貧覺屋寬。", "地爐燒葑火，土榻藉蒲團。", "稚子誇藜糝，高僧輟芋殘。", "霜寒固難出，不怕笑蹣跚。"]'),
('e8e188f3-d57e-4ae9-b702-fd48da101b2c','秋冬之交雜賦六首  其四','陸游','宋','宋诗','song-poetry','','[]','嶺下晨炊黍，津頭暮繫船。',48,'全唐诗/poet.song.135000.json','["嶺下晨炊黍，津頭暮繫船。", "寒潮吞別浦，老木慘蒼烟。", "市徙新山步，耕侵古廟壖。", "閑人不蓄幘，散髮醉江天。"]'),
('93503a97-04e8-494f-815d-046dd434a816','秋冬之交雜賦六首  其五','陸游','宋','宋诗','song-poetry','','[]','霧雨林塘晚，風霜聚落寒。',48,'全唐诗/poet.song.135000.json','["霧雨林塘晚，風霜聚落寒。", "衣冠存簡朴，農圃備艱難。", "舂簸蕎供餌，蒸炊豆作團。", "此心如古井，無地起濤瀾。"]'),
('8edee6f7-104e-4622-9b24-3c033317fedb','秋冬之交雜賦六首  其六','陸游','宋','宋诗','song-poetry','','[]','碓舍臨寒水，漁舟弄夕霏。',48,'全唐诗/poet.song.135000.json','["碓舍臨寒水，漁舟弄夕霏。", "烏將九子過，雉挾兩雌飛。", "浮世萍無蒂，流年弩發機。", "常思南鄭日，縣驛跨騾歸。"]'),
('32169832-935c-4c80-8bb7-fac79f798ddc','海山','陸游','宋','宋诗','song-poetry','','[]','補落迦山訪舊遊，庵摩勒果隘中州。',32,'全唐诗/poet.song.135000.json','["補落迦山訪舊遊，庵摩勒果隘中州。", "秋濤無際明人眼，更作津亭半日留。"]'),
('fd5a37f0-c42a-48ed-92f1-8f9f8221020b','飲村酒','陸游','宋','宋诗','song-poetry','','[]','湘浦騷人詠啜漓，黄州飲溼又增奇。',32,'全唐诗/poet.song.135000.json','["湘浦騷人詠啜漓，黄州飲溼又增奇。", "紛紛坐客評清濁，我已昏然睡不知。"]'),
('c428ef83-365f-4ade-b879-2066aec9ed76','觀諸將除書','陸游','宋','宋诗','song-poetry','','[]','百鍊剛非繞指柔，貂蟬要是出兜鍪。',32,'全唐诗/poet.song.135000.json','["百鍊剛非繞指柔，貂蟬要是出兜鍪。", "得官若使皆齊虜，對泣何疑效楚囚。"]'),
('2eb880b4-9dfd-4ea2-87dc-0016db4733fa','捫腹','陸游','宋','宋诗','song-poetry','','[]','身如椰子腹瓠壺，三畝荒園常荷鋤。',32,'全唐诗/poet.song.135000.json','["身如椰子腹瓠壺，三畝荒園常荷鋤。", "著萬卷書雖不足，容數百人還有餘。"]'),
('cf05c2ed-3815-4f8b-be75-035e8c80ac41','醉歌','陸游','宋','宋诗','song-poetry','','[]','却日莫揮戈，君當聽我歌。',48,'全唐诗/poet.song.135000.json','["却日莫揮戈，君當聽我歌。", "花殘狂有限，酒熟悶無多。", "生理憑長鑱，幽情寄短蓑。", "江湖秋萬里，未死且婆娑。"]'),
('49d3eb8c-8392-4404-a478-0f2bbbf363ca','自嘆','陸游','宋','宋诗','song-poetry','','[]','惡殺常根食，安貧但縕袍。',48,'全唐诗/poet.song.135000.json','["惡殺常根食，安貧但縕袍。", "消搖敢言達，簡默本非高。", "入剡逢飛雪，遊吳看怒濤。", "平生笑漁父，苦語勸餔糟。"]'),
('ee38a938-6557-4888-a51c-674c8421642b','村翁','陸游','宋','宋诗','song-poetry','','[]','不入城門三歲餘，亦無車馬過吾廬。',64,'全唐诗/poet.song.135000.json','["不入城門三歲餘，亦無車馬過吾廬。", "食常羹芋已忘肉，年迫蓋棺猶愛書。", "處處叩門尋醉叟，時時臨水看遊魚。", "半生名宦終何得，作箇村翁計未疏。"]'),
('03d9506f-d717-40b1-8d04-72c95cd995e2','不寐','陸游','宋','宋诗','song-poetry','','[]','一竿江渚寄沉冥，衰疾侵凌失鬢青。',32,'全唐诗/poet.song.135000.json','["一竿江渚寄沉冥，衰疾侵凌失鬢青。", "困睫日中常欲閉，夜闌枕上却惺惺。"]'),
('2412bc05-e8f6-478e-9ec2-d78793850fdb','書志','陸游','宋','宋诗','song-poetry','','[]','平生不喜作鵬摶，常伴寒螿語夜闌。',64,'全唐诗/poet.song.135000.json','["平生不喜作鵬摶，常伴寒螿語夜闌。", "一碗淖糜支日過，數椽破屋著身寬。", "衰殘雖已嘆垂白，憂患未容侵渥丹。", "後五百年吾話在，笑君虛坐幾蒲團。"]'),
('eeddef8a-b4bb-4ea3-a586-b43c4b30079c','東偏紙閣初成','陸游','宋','宋诗','song-poetry','','[]','蚍蜉占雨解移穴，蟋蟀畏寒先近床。',32,'全唐诗/poet.song.135000.json','["蚍蜉占雨解移穴，蟋蟀畏寒先近床。", "我亦聯屏爲燠室，一冬省火又宜香。"]'),
('0229eb08-a0dc-45ce-b35f-e6999617890e','小豎醉','陸游','宋','宋诗','song-poetry','','[]','漫道樽中酒不空，歌呼誰解和衰翁。',32,'全唐诗/poet.song.135000.json','["漫道樽中酒不空，歌呼誰解和衰翁。", "可憐小豎如猱玃，却有平陽吏舍風。"]'),
('e61fef67-af04-4af5-b0fd-8e5c35d4136c','雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','寸陰可惜子所知，尺宅治生今未遲。',32,'全唐诗/poet.song.135000.json','["寸陰可惜子所知，尺宅治生今未遲。", "虛費年光作閑事，人間信有白頭癡。"]'),
('f0853279-135a-44c3-84fe-e7333aadcfd5','雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','堯舜桀紂皆腐骨，王侯螻蟻同丘墟。',32,'全唐诗/poet.song.135000.json','["堯舜桀紂皆腐骨，王侯螻蟻同丘墟。", "麥苗覆塊鳩喚雨，常恨無人同荷鋤。"]'),
('5b2e6001-73e7-4f58-8f11-576b79401d0a','雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','一春妍暖無多日，八十康强有幾人。',32,'全唐诗/poet.song.135000.json','["一春妍暖無多日，八十康强有幾人。", "學不名家空自苦，路邊醉倒却關身。"]'),
('fddd0e59-ebef-45fc-a829-d56c51e080d2','雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','詩人肝肺困雕鎸，往往壽非金石堅。',32,'全唐诗/poet.song.135000.json','["詩人肝肺困雕鎸，往往壽非金石堅。", "我獨適情無傑句，化工不忌遣長年。"]'),
('67028a8f-595a-4ae7-b92f-55d890ac31ec','示兒孫輩','陸游','宋','宋诗','song-poetry','','[]','昔忝諸生後，初非一世豪。',48,'全唐诗/poet.song.135000.json','["昔忝諸生後，初非一世豪。", "但希鄉有秩，敢望郡功曹。", "斂版寧爲辱，扶犁亦足高。", "兒孫勿妄想，底處不徒勞。"]'),
('a6cda1ec-09a3-4c54-8326-6e9e3594b1f9','雜賦六首  其一','陸游','宋','宋诗','song-poetry','','[]','養疾清溪曲，風林幾著霜。',48,'全唐诗/poet.song.135000.json','["養疾清溪曲，風林幾著霜。", "細書如助懶，薄酒不成狂。", "老嘆朋儕盡，閑知歲月長。", "柴門偶一出，倚杖立斜陽。"]'),
('991746d3-584a-4856-a5e9-5b2e791b106e','雜賦六首  其二','陸游','宋','宋诗','song-poetry','','[]','孤學違流俗，危機歷畏途。',48,'全唐诗/poet.song.135000.json','["孤學違流俗，危機歷畏途。", "逢人增戃怳，看鏡失膚腴。", "閉戶書圍坐，移燈影向隅。", "空懷四方志，泯默死東吳。"]'),
('2c58d13b-8bd9-4c1c-8d71-b2bc38cf4d0e','雜賦六首  其三','陸游','宋','宋诗','song-poetry','','[]','家業貧原憲，年齡老伏生。',48,'全唐诗/poet.song.135000.json','["家業貧原憲，年齡老伏生。", "但悲鸞獨舞，那羨雁能鳴。", "釀酒秋常醉，驅牛夜亦耕。", "此身當自貴，勿用作投瓊。"]'),
('87c7420d-786c-49a8-9de0-b5ca1bec4fd7','雜賦六首  其四','陸游','宋','宋诗','song-poetry','','[]','貴固不如賤，狂應未勝癡。',48,'全唐诗/poet.song.135000.json','["貴固不如賤，狂應未勝癡。", "閉門真已矣，命駕欲何之。", "碧縷生香袖，清漪漲硯池。", "是中有佳處，不覺晝陰移。"]'),
('84569adc-737d-4a23-b32a-c2c67e7b0ee9','雜賦六首  其五','陸游','宋','宋诗','song-poetry','','[]','海上魚鹽聚，烟中鷄犬聲。',48,'全唐诗/poet.song.135000.json','["海上魚鹽聚，烟中鷄犬聲。", "耕農叱牛去，醉叟策馿行。", "斂薄民差樂，烽消盜略平。", "悠然憩松下，我亦有幽情。"]'),
('965bece6-243c-434c-8958-7f7cdbf4e40a','雜賦六首  其六','陸游','宋','宋诗','song-poetry','','[]','櫛髮晨興後，寬腰午餉餘。',48,'全唐诗/poet.song.135000.json','["櫛髮晨興後，寬腰午餉餘。", "講明窮理學，讎校養生書。", "倚杖聽啼鳥，臨池看戲魚。", "怡然又終日，底事解愁予。"]'),
('90dce673-fd92-473e-b117-a8f269c15bd8','幽居','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','人間歲月苦駸駸，白首幽居不厭深。',64,'全唐诗/poet.song.135000.json','["人間歲月苦駸駸，白首幽居不厭深。", "懶愛舉杯成美睡，靜嫌對弈動機心。", "山村野渡雙芒屩，夜雪晨霜一布衾。", "不到匡廬三十載，夢携巾鉢上東林。"]'),
('de1d0221-4b83-4197-becd-f0aac71f9eca','連日作陰頗有雨雪意','陸游','宋','宋诗','song-poetry','','[]','十分曆日過八九，徂歲迫人殊可驚。',64,'全唐诗/poet.song.135000.json','["十分曆日過八九，徂歲迫人殊可驚。", "霜木蕭蕭臨古道，雪雲慘慘冒高城。", "山頭噤雀無生意，水面饑鳶有墮聲。", "剩壓新醅供旨蓄，從今次第問春耕。"]'),
('7f13cca3-ddca-4d7a-be0d-e7a0f03b2139','山房','陸游','宋','宋诗','song-poetry','','[]','四紀移家剡曲傍，自茨生草作山房。',64,'全唐诗/poet.song.135000.json','["四紀移家剡曲傍，自茨生草作山房。", "寒侵夜艾知霜重，行遍天涯覺夢長。", "戒婢無勞事釵澤，課奴相率補陂塘。", "無衣已免豳人嘆，數箔春蠶歲有常。"]'),
('197dc87b-afaf-4de4-bbbe-779ba15a8398','梅市暮歸','陸游','宋','宋诗','song-poetry','','[]','老境惟閉門，不與事物接。',144,'全唐诗/poet.song.135000.json','["老境惟閉門，不與事物接。", "時逢佳山水，尚復快登涉。", "山程策小蹇，水泛搖短楫。", "今茲稅駕地，佳事喜稠疊。", "雲生溼行縢，風細掠醉頰。", "旅羹芼玉糝，僧飯敷白氎。", "葑火煨芋魁，瓦甑炊豆莢。", "經行出幽圃，懷抱頗自愜。", "枯籬絡丹實，深澗堆黄葉。", "白雲橫谷口，綠篠穿山脅。", "還家寧迫暮，取路羞徑捷。", "何當倚蒲龕，一坐十小劫。"]'),
('b3af386c-d3bd-48b3-8d21-bd5bf121fb13','法雲寺','陸游','宋','宋诗','song-poetry','','[]','法雲古蘭若，西走錢塘路。',120,'全唐诗/poet.song.135000.json','["法雲古蘭若，西走錢塘路。", "帆影梅市橋，人語柯山聚。", "吾家昔爲鄰，來往無晨暮。", "十世三百年，散徙非復故。", "修廊與廣殿，亦已化烟霧。", "經營久不倦，大體始略具。", "鐘魚以時鳴，軒檻有幽趣。", "中庭掃蕪穢，斷碣起顛仆。", "老我絕世緣，隨身惟兩屨。", "願言治北窗，寂寞同子住。"]'),
('8e537406-1522-4b9f-8b0f-b23ab15405de','郊居','陸游','宋','宋诗','song-poetry','','[]','郊居本宴如，觸事自多感。',72,'全唐诗/poet.song.135000.json','["郊居本宴如，觸事自多感。", "况當搖落時，雲重天慘慘。", "路窮非通途，地偏無遠覽。", "殘蕪連古道，槁葉滿幽坎。", "老來厭了了，萬事付黮闇。", "地爐熾生柴，喚客烹薺糝。"]'),
('811e2b8a-e09a-4aa9-963a-2c002a97e165','作雪不成獨詠','陸游','宋','宋诗','song-poetry','','[]','淡日朝穿霧，濃雲夜護霜。',48,'全唐诗/poet.song.135000.json','["淡日朝穿霧，濃雲夜護霜。", "風聲空浩蕩，雪意愈微茫。", "棐几閑臨帖，銅爐靜炷香。", "悠然踐殘歲，不是傲羲皇。"]'),
('9c1f7807-359d-442a-844d-361920917459','聞雁','陸游','宋','宋诗','song-poetry','','[]','蜻蜓浦中聞雁聲，寒侵短褐客愁生。',32,'全唐诗/poet.song.135000.json','["蜻蜓浦中聞雁聲，寒侵短褐客愁生。", "忽思大散關頭路，雪壓蒙氈夜下程。"]'),
('26215f87-ed30-4719-b57c-2fee41a45bd0','泛舟至蜻蜓浦小泊漁村','陸游','宋','宋诗','song-poetry','','[]','醉泛蜻蜓浦，咿啞一櫓聲。',48,'全唐诗/poet.song.135000.json','["醉泛蜻蜓浦，咿啞一櫓聲。", "陂塘秋水瘦，墟落暮烟生。", "野店曾留醉，樵翁不記名。", "相逢雖惘惘，懷抱已先傾。"]'),
('a9afd722-7c93-420e-80fa-a51fc966dff5','散策門外鄰叟怪其瘦','陸游','宋','宋诗','song-poetry','','[]','八十衰翁力既愆，强扶藤杖出門前。',32,'全唐诗/poet.song.135000.json','["八十衰翁力既愆，强扶藤杖出門前。", "朝晡恃粥何勞嘆，齒脫牙搖已數年。"]'),
('14e4b05d-5376-4a4c-995e-43afae90008a','書警二首  其一','陸游','宋','宋诗','song-poetry','','[]','束带接一客，伸紙報一書。',48,'全唐诗/poet.song.135000.json','["束带接一客，伸紙報一書。", "未爲甚疲勞，已覺不枝梧。", "惟有袖手坐，儼然如齋居。", "尚懼精神衰，藥石以自扶。"]'),
('37403f76-c330-49c1-a08d-6b4c44033e50','書警二首  其二','陸游','宋','宋诗','song-poetry','','[]','情慾雖害人，要是自惑溺。',48,'全唐诗/poet.song.135000.json','["情慾雖害人，要是自惑溺。", "吾觀日用事，飲食真勍敵。", "乃知匕箸間，其禍甚衽席。", "堂堂六尺軀，勿爲口腹役。"]'),
('8f65b0ae-94af-4e7d-ae49-b2f12a6d3cc8','園中','陸游','宋','宋诗','song-poetry','','[]','殘菊無復花，遊蜂抱枯叢。',48,'全唐诗/poet.song.135000.json','["殘菊無復花，遊蜂抱枯叢。", "我老復多疾，寄迹窮巷中。", "開門無客至，安取樽不空。", "夕陽挂高樹，此日還匆匆。"]'),
('9a60a442-9c50-407d-8883-4648790988cc','冬晴行園中二首  其一','陸游','宋','宋诗','song-poetry','','[]','冬溫光景如春妍，暮年强健勝壯年。',64,'全唐诗/poet.song.135000.json','["冬溫光景如春妍，暮年强健勝壯年。", "手推園門拂石坐，豈暇爲客思無氈。", "殘蕪未死更鬰鬰，晚菊欲槁猶鮮鮮。", "閑愁正得酒彈壓，此夕預知當熟眠。"]'),
('ba2d3090-6e4a-48dc-9945-7504fba6c3e6','冬晴行園中二首  其二','陸游','宋','宋诗','song-poetry','','[]','桔槔灌蔬固已非，竹筧澆花宜見譏。',64,'全唐诗/poet.song.135000.json','["桔槔灌蔬固已非，竹筧澆花宜見譏。", "杏繁梅瘦種性別，一氣生殺均天機。", "細推物理孰不爾，摶風未可嘲卑飛。", "君其置之且共酌，白酒方熟黄雞肥。"]'),
('781e8103-59fc-47ad-bf5f-ab127fb43ae2','懷青城舊遊','陸游','宋','宋诗','song-poetry','','[]','宦途到處不黔突，惟有劍南縻歲月。',96,'全唐诗/poet.song.135000.json','["宦途到處不黔突，惟有劍南縻歲月。", "屢遊老澤蒼玉嶂，疑是虛皇白銀闕。", "松肪擣麨具晨餐，槲葉作衣勝短褐。", "泥飲不容繁杏落，浩歌常送寒蟬沒。", "水邊洞口適有遇，握手一言換凡骨。", "少陵老子未識真，欲倚黄精除白髮。"]'),
('8ec3b7bc-de0c-4af2-a81c-e472a4ee92e5','晚立','陸游','宋','宋诗','song-poetry','','[]','倦憑小豎立柴門，殘角疏鐘欲斷魂。',64,'全唐诗/poet.song.135000.json','["倦憑小豎立柴門，殘角疏鐘欲斷魂。", "傷雁養翎依荻浦，渡牛浮鼻望烟村。", "壯心已覺隨年往，孤學何由與俗論。", "數點雨聲催返舍，小窗燈火對壺飧。"]'),
('f78096ef-2a38-4b2a-a1a8-37dc260c1634','志喜','陸游','宋','宋诗','song-poetry','','[]','雪鬢蕭蕭九十翁，短檠猶喜策新功。',64,'全唐诗/poet.song.135000.json','["雪鬢蕭蕭九十翁，短檠猶喜策新功。", "斲輪自得不傳處，治水本行無事中。", "山市兒童隨小蹇，江村烟雨宿孤篷。", "更知衰疾從今減，萬里塵清蜀藥通。"]'),
('e4353bb3-48ce-42b0-b1e0-fb45d8675279','窮居','陸游','宋','宋诗','song-poetry','','[]','仕宦初何得，窮居半士農。',48,'全唐诗/poet.song.135000.json','["仕宦初何得，窮居半士農。", "清宵叔夜鍛，平旦伯鸞舂。", "馬磨猶支日，牛衣亦過冬。", "湖中有嘯父，何計得相從。"]'),
('5f0dbe40-3f1e-4937-8765-29a9e1fe49e3','冬暖園中萱草蓊然海棠亦著花可愛作路浚井皆近事也','陸游','宋','宋诗','song-poetry','','[]','暖景變嚴冬，誰知造化功。',48,'全唐诗/poet.song.135000.json','["暖景變嚴冬，誰知造化功。", "少留萱草綠，探借海棠紅。", "築路橫塘北，疏泉小嶺東。", "欣然得佳處，忘却歲將窮。"]'),
('5ceb09a9-2721-4df0-9fc3-02e48810b20d','即事示兒輩','陸游','宋','宋诗','song-poetry','','[]','今歲霜遲殊未寒，籬東烏桕葉纔丹。',64,'全唐诗/poet.song.135000.json','["今歲霜遲殊未寒，籬東烏桕葉纔丹。", "病輕漸喜免求藥，老甚難誇能據鞍。", "鄰舍僧貧分米少，酒坊人熟督錢寬。", "晚來笑向兒孫說，且得無生一話團。"]'),
('cbb6702a-8508-4b2d-aadd-36eae8ccecef','小雨頗寒','陸游','宋','宋诗','song-poetry','','[]','冬溫初喜一寒新，紙閣磚爐養病身。',64,'全唐诗/poet.song.135000.json','["冬溫初喜一寒新，紙閣磚爐養病身。", "殘雨已收猶點滴，斷雲欲散更輪囷。", "衣裳可典寧留笥，口腹雖饞肯累人。", "一事明朝差似樂，探梅閑岸接䍦巾。"]'),
('ef45a0e0-cbf3-4e35-9dd9-939936ab2483','題舍壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','身寄瓜牛廬，手持科斗書。',48,'全唐诗/poet.song.135000.json','["身寄瓜牛廬，手持科斗書。", "尚憎駑戀棧，肯羨鶴乘車。", "富貴何加我，山林亦宴如。", "年來常去殺，不嘆食無魚。"]'),
('3324f7ca-51ef-4f84-97ef-5f08811d736c','題舍壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','草沒孔明廬，塵流倚相書。',48,'全唐诗/poet.song.135000.json','["草沒孔明廬，塵流倚相書。", "家居四立壁，出駕獨轅車。", "窮達本無擇，死生良自如。", "鏡湖三百里，處處侶禽魚。"]'),
('a511dc16-3bc1-4509-9f91-e7f996699a3e','仲冬書事','陸游','宋','宋诗','song-poetry','','[]','邊頭無警少鈴聲，病得新霜亦已平。',64,'全唐诗/poet.song.135000.json','["邊頭無警少鈴聲，病得新霜亦已平。", "赤脚聽蛩勤夜績，蒼頭租犢待冬耕。", "發奩雙兔駢頭卧，溢榼芳醪徹底清。", "里巷紛紛誇節物，春盤儺鼓漸關情。"]'),
('1715e18e-dd41-4617-bad4-0a1728381fab','醉舞','陸游','宋','宋诗','song-poetry','','[]','渭城朝雨不須歌，爛醉江頭舞短蓑。',32,'全唐诗/poet.song.135000.json','["渭城朝雨不須歌，爛醉江頭舞短蓑。", "自是先生眼根鈍，天狐伎倆本無多。"]'),
('d07339d0-ce5e-45f9-b4a1-08617442da43','思蜀二首  其一','陸游','宋','宋诗','song-poetry','','[]','白帝城邊八陣磧，青城山下丈人祠。',32,'全唐诗/poet.song.135000.json','["白帝城邊八陣磧，青城山下丈人祠。", "英雄不生僊又去，零落草間多折碑。"]'),
('66eb6741-7c81-4bf3-81b4-fdaec8d7d5fb','思蜀二首  其二','陸游','宋','宋诗','song-poetry','','[]','蜀莊鳴飛隘九區，超然豈止山澤癯。',32,'全唐诗/poet.song.135000.json','["蜀莊鳴飛隘九區，超然豈止山澤癯。", "荒臺古井無處所，行子但覓房公湖。"]'),
('c35a1e38-d68d-4817-b2c3-586af05cd620','次韵李季章參政哭其夫人七首  其一','陸游','宋','宋诗','song-poetry','','[]','飛蓋傳呼入省門，依然殘夢浣花村。',32,'全唐诗/poet.song.135000.json','["飛蓋傳呼入省門，依然殘夢浣花村。", "遥知最是傷心處，衫袂猶霑掃黛痕。"]'),
('41b11fef-222b-4a64-b402-10a777c474a6','次韵李季章參政哭其夫人七首  其二','陸游','宋','宋诗','song-poetry','','[]','焚香黄閣退朝歸，道話時時正要提。',32,'全唐诗/poet.song.135000.json','["焚香黄閣退朝歸，道話時時正要提。", "九十老翁緣底健，一生强半是單栖。"]'),
('9ba4a03a-ae73-4408-8e86-61dae6e41205','次韵李季章參政哭其夫人七首  其三','陸游','宋','宋诗','song-poetry','','[]','萬里氈車入鳳城，豈知遽已迫斜曛。',32,'全唐诗/poet.song.135000.json','["萬里氈車入鳳城，豈知遽已迫斜曛。", "似聞後院思遺愛，掩泪人人說小君。"]'),
('82cae3ac-05ec-419f-b54f-20f09773622a','次韵李季章參政哭其夫人七首  其四','陸游','宋','宋诗','song-poetry','','[]','佛供齋僧冀萬分，幽明路絕竟難論。',32,'全唐诗/poet.song.135000.json','["佛供齋僧冀萬分，幽明路絕竟難論。", "若爲可慰重泉念，觸事平心無怨恩。"]'),
('9f5fd1ec-5adc-476e-ac9d-e07aee9fcb0d','次韵李季章參政哭其夫人七首  其五','陸游','宋','宋诗','song-poetry','','[]','焄蒿一去杳難知，數紙遺書手自披。',32,'全唐诗/poet.song.135000.json','["焄蒿一去杳難知，數紙遺書手自披。", "切勿輕爲歸蜀夢，竹枝忍復聽吾伊。"]'),
('b7ce4025-d761-4544-9906-ec13d65bf7ff','次韵李季章參政哭其夫人七首  其六','陸游','宋','宋诗','song-poetry','','[]','害道無如狥愛嗔，養生尤要嗇精神。',32,'全唐诗/poet.song.135000.json','["害道無如狥愛嗔，養生尤要嗇精神。", "祝公少置空閨憶，天下安危在此身。"]'),
('fe6fc834-ac81-47cc-8616-81091268a4c5','次韵李季章參政哭其夫人七首  其七','陸游','宋','宋诗','song-poetry','','[]','富貴思歸豈坐迂，岷山種芋已成區。',32,'全唐诗/poet.song.135000.json','["富貴思歸豈坐迂，岷山種芋已成區。", "獨歸它日公無憾，天際烟帆與石俱。"]'),
('ed321359-842b-4c11-af83-e5ea11e2562b','試筆','陸游','宋','宋诗','song-poetry','','[]','人間元無第一手，萬事端如屈伸肘。',64,'全唐诗/poet.song.135000.json','["人間元無第一手，萬事端如屈伸肘。", "但能看破即超然，何代商山無四叟。", "老民自視中何有，傾身經營一杯酒。", "此外管城差可人，相從且作明窗友。"]'),
('b5c790c9-6ef4-407a-9f78-b779ee3c3ffa','屠希筆','陸游','宋','宋诗','song-poetry','','[]','屠希一筆價必千，紹興初載海內傳。',80,'全唐诗/poet.song.135000.json','["屠希一筆價必千，紹興初載海內傳。", "高皇愛賞登玉几，求書蚤暮常差肩。", "一朝希死子孫弱，歲久僅可售百錢。", "宣城晉陵競聲價，外雖甚飾中枵然。", "嗚呼世事每如此，使我太息中夕起。"]'),
('ddee841c-5df8-4906-b76d-50829deaec90','寒夜吟','陸游','宋','宋诗','song-poetry','','[]','仕宦孰不願美官，無如兩膊聳聳寒。',88,'全唐诗/poet.song.135000.json','["仕宦孰不願美官，無如兩膊聳聳寒。", "可憐誤信紙上語，至死功名心未闌。", "骯髒得倚門，矍鑠猶據鞍。", "何如百年中，盡付一漁竿。", "布襦可以度雪夕，麥飯可以支朝餐。", "但知禪龕著身穩，莫和詩人行路難。"]'),
('eb995a76-998e-4a64-b6bc-d5e071090a68','記夢','陸游','宋','宋诗','song-poetry','','[]','衣紳飄舉髮颼飀，一鶴聊爲太華遊。',32,'全唐诗/poet.song.135000.json','["衣紳飄舉髮颼飀，一鶴聊爲太華遊。", "每過名山思小憩，天風浩浩不容留。"]'),
('8e80e671-130c-4109-9b67-1eab84f1e113','霜夜二首  其一','陸游','宋','宋诗','song-poetry','','[]','月淡霜清夜漏遲，疏鐘杳杳度南陂。',64,'全唐诗/poet.song.135000.json','["月淡霜清夜漏遲，疏鐘杳杳度南陂。", "燈殘有恨欲誰語，鷄老無聲如我衰。", "使入蜀川方在道，書傳淮浦定何時。", "若爲可遣閑愁得，獨擁寒爐爇豆萁。"]'),
('eb3934e0-319f-4d63-b943-1a6a353a6b0f','霜夜二首  其二','陸游','宋','宋诗','song-poetry','','[]','土床紙帳卧幽寂，枕上細聽城上更。',64,'全唐诗/poet.song.135000.json','["土床紙帳卧幽寂，枕上細聽城上更。", "榾柮燒殘地爐冷，喔咿聲斷天窗明。", "風霜欲透草茨屋，鹽酪不下薺糝羹。", "猶恨扶犁老無力，向來枉是請躬耕。"]'),
('d9c8a5eb-0c4a-46db-89dc-0b02b5c67f4b','歲暮','陸游','宋','宋诗','song-poetry','','[]','歲暮風霜慘，村深草棘稠。',48,'全唐诗/poet.song.135000.json','["歲暮風霜慘，村深草棘稠。", "力衰行每蹇，衣薄鼻多鼽。", "久矣當長往，悠然尚小留。", "兒童報炊熟，得飽且忘憂。"]'),
('5dc2f654-fd05-4e41-b675-8ceab01c7f27','與野人散策門外','陸游','宋','宋诗','song-poetry','','[]','春意侵寒律，川雲結夕陰。',48,'全唐诗/poet.song.135000.json','["春意侵寒律，川雲結夕陰。", "閑人了無事，鄰叟偶相尋。", "廢沼萍黏塊，孤村雀滿林。", "世間真夢耳，何物可關心。"]'),
('187f2d1d-d80a-4d31-8434-c4561a80416d','十一月十一日夜聞雨聲','陸游','宋','宋诗','song-poetry','','[]','入冬殊未寒，塵土冒原野。',72,'全唐诗/poet.song.135000.json','["入冬殊未寒，塵土冒原野。", "溝溪但枯萍，不聞清湍瀉。", "今夕復何夕，急雨鳴屋瓦。", "豈惟宿麥長，分喜到菜把。", "明朝開衡門，想見泥濺踝。", "豐年儻可期，擊壤歌豳雅。"]'),
('977c14d7-563a-4482-96e6-166070c4b9cc','自述二首  其一','陸游','宋','宋诗','song-poetry','','[]','怡然氣貌漸還嬰，淡飯粗裘過此生。',32,'全唐诗/poet.song.135000.json','["怡然氣貌漸還嬰，淡飯粗裘過此生。", "儘道無方能縮地，夢中夜夜上青城。"]'),
('23925d40-edd4-4267-8b1f-4b99170872a6','自述二首  其二','陸游','宋','宋诗','song-poetry','','[]','齒卼復牢能咀嚼，足攣漸愈可跏趺。',32,'全唐诗/poet.song.135000.json','["齒卼復牢能咀嚼，足攣漸愈可跏趺。", "短檠非復衰翁事，且與兒孫共地爐。"]'),
('c7819188-a843-4682-98bc-59dfa2f1bfde','歲暮老懷','陸游','宋','宋诗','song-poetry','','[]','粥美忘流啜，燈孤伴獨吟。',48,'全唐诗/poet.song.135000.json','["粥美忘流啜，燈孤伴獨吟。", "衾寒知夜艾，身痛卜天陰。", "薪炭常憂絕，杯觴不厭深。", "故人今已矣，三嘆有遺音。"]'),
('ef48a930-98a3-44bb-bd1b-11fe76132671','書况','陸游','宋','宋诗','song-poetry','','[]','垂白渭南叟，深居湖上村。',72,'全唐诗/poet.song.135000.json','["垂白渭南叟，深居湖上村。", "貧知蔬食美，閑覺布衣尊。", "琴譜從僧借，茶經與客論。", "探梅來直步，沽酒到偏門。", "細織籠安鶴，頻求果飼猿。", "舊書編未絕，猶足教諸孫。"]'),
('b084a776-cb4d-4f30-95b3-c2bd2ef52408','書道室壁','陸游','宋','宋诗','song-poetry','','[]','餘生天地一飛蓬，學道年來似有功。',64,'全唐诗/poet.song.135000.json','["餘生天地一飛蓬，學道年來似有功。", "習氣掃除空劫外，精神澡雪隠書中。", "種瓜谿父時時見，賣藥壺公處處同。", "莫謂與人緣苦薄，相隨拍手有兒童。"]'),
('807475c7-ad10-425f-a715-5647f1127f96','書志','陸游','宋','宋诗','song-poetry','','[]','蓬矢桑弧射四方，豈知垂老卧江鄉。',64,'全唐诗/poet.song.135000.json','["蓬矢桑弧射四方，豈知垂老卧江鄉。", "讀書雖復具隻眼，貯酒其如無別腸。", "疋馬揚鞭遊鄠杜，扁舟捩柁上瀟湘。", "自悲此志俱難豁，且復狂歌破夜長。"]'),
('1e23c599-ee64-4c5a-bf09-b01ec3d25255','雪夕','陸游','宋','宋诗','song-poetry','','[]','目視𥉂𥉂左耳聾，吾衰略與昔人同。',64,'全唐诗/poet.song.135000.json','["目視𥉂𥉂左耳聾，吾衰略與昔人同。", "移燈自看竛竮影，取酒時澆礧磈胸。", "東郭稍能師順子，北山未敢笑愚公。", "空村雪虐風饕夜，袖手悠然政策功。"]'),
('c4c68d6f-56ac-4e8c-82b5-1061e16534f3','書枕屏四首  其一','陸游','宋','宋诗','song-poetry','','[]','西域兜羅被，南番篤耨香。',24,'全唐诗/poet.song.135000.json','["西域兜羅被，南番篤耨香。", "慣眠三丈日，不識五更霜。"]'),
('dd31fb47-3395-41bf-9fc3-9da7ed217b1b','書枕屏四首  其二','陸游','宋','宋诗','song-poetry','','[]','心若冰將釋，貌如兒未孩。',24,'全唐诗/poet.song.135000.json','["心若冰將釋，貌如兒未孩。", "青城上官叟，時入夢中來。"]'),
('6f2e1dd7-9539-44d4-a1bd-0f5a6d30774b','書枕屏四首  其三','陸游','宋','宋诗','song-poetry','','[]','甘菊縫爲枕，疏梅畫作屏。',24,'全唐诗/poet.song.135000.json','["甘菊縫爲枕，疏梅畫作屏。", "改詩眠未穩，聞雪醉初醒。"]'),
('60c87640-ca8a-45e0-b527-f4a1d797cba7','書枕屏四首  其四','陸游','宋','宋诗','song-poetry','','[]','星斗闌干曉，窗扉曨{日怱}明。',27,'全唐诗/poet.song.135000.json','["星斗闌干曉，窗扉曨{日怱}明。", "金門與茅店，一種是鷄聲。"]'),
('68df4f5c-3905-4458-ae0b-5d00851f8ecd','二友','陸游','宋','宋诗','song-poetry','','[]','剩儲名酒待梅開，凈掃虛窗候月來。',32,'全唐诗/poet.song.135000.json','["剩儲名酒待梅開，凈掃虛窗候月來。", "老子幽居得二友，人間萬事信悠哉。"]'),
('5ed05c06-2ec1-422b-99e8-2bc921c67aa2','寄五郎兼示十五郎','陸游','宋','宋诗','song-poetry','','[]','八十九十老可驚，白髮森然憎鏡明。',64,'全唐诗/poet.song.135000.json','["八十九十老可驚，白髮森然憎鏡明。", "身當遊岱尚少駐，書欲藏山殊未成。", "大兒爲國戍絕塞，季子伴翁親短檠。", "古人已矣不可作，夜闌撫几嘆平生。"]'),
('177c4b84-fead-4120-96f5-806e6e7919c5','鄰曲相過','陸游','宋','宋诗','song-poetry','','[]','鄰曲集山家，相看一笑譁。',48,'全唐诗/poet.song.135000.json','["鄰曲集山家，相看一笑譁。", "扶行足踸踔，半落齒槎牙。", "農圃乖生理，風霜感歲華。", "老來情話少，更盡此甌茶。"]'),
('ca8a19cd-ebad-4ade-8aba-47d8707d1a98','東窗','陸游','宋','宋诗','song-poetry','','[]','臘近寒何薄，秋衣著尚宜。',48,'全唐诗/poet.song.135000.json','["臘近寒何薄，秋衣著尚宜。", "年光祈雪見，節物賣燈知。", "川日初沉後，樓鐘欲動時。", "東窗對兒子，聊與細論詩。"]'),
('f8783033-abd7-4297-833f-2cdf34847879','曉寒','陸游','宋','宋诗','song-poetry','','[]','落月銜山口，濃霜倒菊叢。',48,'全唐诗/poet.song.135000.json','["落月銜山口，濃霜倒菊叢。", "青氈壓衾暖，軟火滿爐紅。", "起晚書虧課，愁多酒策功。", "杜陵如昔否，誰與問征鴻。"]'),
('e0c7bc4f-6961-485c-a492-cae7c66a2e3b','小雪','陸游','宋','宋诗','song-poetry','','[]','簷飛數片雪，瓶插一枝梅。',24,'全唐诗/poet.song.135000.json','["簷飛數片雪，瓶插一枝梅。", "童子敲清磬，先生入定回。"]'),
('8ff5f2ff-9c1b-40bf-96ef-238cfb05c67b','書感','陸游','宋','宋诗','song-poetry','','[]','夢裏逢無咎，天涯哭季長。',24,'全唐诗/poet.song.135000.json','["夢裏逢無咎，天涯哭季長。", "吾生亦有幾，且復釣滄浪。"]'),
('5236696e-43e2-4aed-b551-36405ac8e792','家釀頗勁戲作','陸游','宋','宋诗','song-poetry','','[]','千古英雄骨作塵，不如一醉却關身。',64,'全唐诗/poet.song.135000.json','["千古英雄骨作塵，不如一醉却關身。", "鼎來雖恨王陵戇，熟味方知孟子醇。", "試問浩歌遺世事，何如酣枕養天真。", "竹林嵇阮雖名勝，要是淵明最可人。"]'),
('3e05e6bf-281e-4bb5-b917-3169e0023007','食薺糝甚美蓋蜀人所謂東坡羹也','陸游','宋','宋诗','song-poetry','','[]','薺糝芳甘妙絕倫，啜來恍若在峨岷。',64,'全唐诗/poet.song.135000.json','["薺糝芳甘妙絕倫，啜來恍若在峨岷。", "蓴羹下豉知難敵，牛乳抨酥亦未珍。", "異味頗思修凈供，秘方常惜授厨人。", "午窗自撫膨脝腹，好住烟村莫厭貧。"]'),
('f8c1aafe-a0cc-4ac8-96fe-1633d3a925f2','雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','鋤草春愈茂，養草秋亦衰。',24,'全唐诗/poet.song.135000.json','["鋤草春愈茂，養草秋亦衰。", "不如兩置之，榮悴渠有時。"]'),
('16aa9fcb-6428-4d0a-94b8-3f32cd3d906a','雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','栖鷄未旦鳴，粒食固宜報。',24,'全唐诗/poet.song.135000.json','["栖鷄未旦鳴，粒食固宜報。", "林鳥何預人，嘵嘵欲誰告。"]'),
('db020ac6-8dcc-4afa-9c8d-4674f1f5bba7','雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','碩果墜池響，魚隊散無迹。',24,'全唐诗/poet.song.135000.json','["碩果墜池響，魚隊散無迹。", "空弦可落雁，此事蓋自昔。"]'),
('e9943cd1-719a-4510-a364-04b8b4ef8a7e','雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','滌硯欲其潔，磨鏡欲其明。',24,'全唐诗/poet.song.135000.json','["滌硯欲其潔，磨鏡欲其明。", "願君試思之，與己孰重輕。"]'),
('42544c7c-6cce-422c-a04d-f0389fe7b6cf','幽情','陸游','宋','宋诗','song-poetry','','[]','免歸又破六年閑，每寄幽情烟水間。',64,'全唐诗/poet.song.135000.json','["免歸又破六年閑，每寄幽情烟水間。", "清鏡不藏新白髮，芳樽猶惜舊朱顔。", "一編蠹簡心空在，百甕寒齏債未還。", "莫爲岷峨勞夢想，故鄉隨分有名山。"]'),
('580bbcdd-a59e-4a06-856e-9090e848da42','醉歌','陸游','宋','宋诗','song-poetry','','[]','不癡不聾不作翁，平生與世馬牛風。',146,'全唐诗/poet.song.135000.json','["不癡不聾不作翁，平生與世馬牛風。", "無材無德癡頑老，爾來對客惟稱好。", "相風使帆第一籌，隨風倒柁更何憂。", "亦不求作佛，亦不願封侯。", "亦不須脫裘去換酒，亦不須賣劍來買牛。", "甲第從渠饜粱肉，貂蟬本自出兜鍪。", "燮理陰陽豈不好，纔得閑管晴雨如鵓鳩。", "辛苦築壘拂雲祠，不如吟嘯風月登高樓。", "爾作楚舞吾齊謳，身安意適死即休。"]'),
('84152e78-59c0-4a31-a3b9-5fbdfd3e0c7b','霜冷','陸游','宋','宋诗','song-poetry','','[]','梅花消息動江邊，漸見新春換故年。',32,'全唐诗/poet.song.135000.json','["梅花消息動江邊，漸見新春換故年。", "莫道孤翁心似鐵，夜來霜冷透青氈。"]'),
('6d47c204-a061-4f9f-82e3-23c6bf5fb00e','讀書雜言','陸游','宋','宋诗','song-poetry','','[]','書亦何用於世哉，聖人之言如造化，巍巍地闢而天開。',140,'全唐诗/poet.song.135000.json','["書亦何用於世哉，聖人之言如造化，巍巍地闢而天開。", "淵源虞唐至周孔，黄河萬里崑崙來。", "天不使諸儒爲戰國血，又不使六藝爲亡秦灰。", "豁如盲瞽見皦日，快若聾聵聞春雷。", "插空泰華起突兀，垂天雲漢森昭回。", "奈何後世獨不省，顧捨夷路趨邛郲。", "不知開眼蹈覆轍，乃欲歸罪車輪摧。", "福有基，禍有胎，一朝産禍吁可哀。"]'),
('0084161d-68a9-4797-88a7-7f27f75577da','東嶺','陸游','宋','宋诗','song-poetry','','[]','雲罅漏斜日，駕言東嶺行。',48,'全唐诗/poet.song.135000.json','["雲罅漏斜日，駕言東嶺行。", "鴉翻半天黑，鷺起一川明。", "小立照溝水，欲歸聞角聲。", "君看浮世事，何處異棋枰。"]'),
('6401ac21-7eee-47e6-9901-5d216bf95b83','書戒','陸游','宋','宋诗','song-poetry','','[]','我幼事父師，熟聞忠厚言。',120,'全唐诗/poet.song.135000.json','["我幼事父師，熟聞忠厚言。", "治身接物間，要使如春溫。", "鞭朴不可弛，此語實少恩。", "但能交相愛，餘亦何足論。", "家貧頼奴婢，炊汲與譍門。", "餘力具茗藥，夕飯或至昏。", "有過尚當貰，况可使煩冤。", "出仕推此心，所樂在平反。", "寧坐軟弱廢，促駕歸丘園。", "吾老死無日，作詩遺子孫。"]'),
('1932ae3a-1f31-46b1-a5a1-e6404a7a3301','書齋壁','陸游','宋','宋诗','song-poetry','','[]','烟水雲山千萬重，散人名號繼吾宗。',64,'全唐诗/poet.song.135000.json','["烟水雲山千萬重，散人名號繼吾宗。", "買雛養就沖霄鶴，拾子栽成偃蓋松。", "父老年年同社酒，兒孫世世作春農。", "晚窗睡覺添幽事，卧聽蘭亭古寺鐘。"]'),
('78da0a27-d98a-4610-a415-ffbb05e0e391','雪意','陸游','宋','宋诗','song-poetry','','[]','風吼江郊雪意濃，雲如兩陣决雌雄。',64,'全唐诗/poet.song.135000.json','["風吼江郊雪意濃，雲如兩陣决雌雄。", "山寒酒過平時量，窗黑書虧半日功。", "閑話更端茶竈熟，清詩分韵地爐紅。", "不須遽覓華胥路，更竢天花落坐中。"]'),
('88414ac9-5722-4223-9e87-50eaa86d49a0','山房','陸游','宋','宋诗','song-poetry','','[]','何處合題詩，山房病起時。',48,'全唐诗/poet.song.135000.json','["何處合題詩，山房病起時。", "晨光鳥先覺，春信柳偏知。", "陋學勤何益，虛名悔可追。", "布衾新絮暖，惟與睡相宜。"]'),
('e68dda7f-0cfb-4157-848e-5514525c85c7','晨起','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','勛業文章謝不能，生涯分付一枝藤。',64,'全唐诗/poet.song.135000.json','["勛業文章謝不能，生涯分付一枝藤。", "身同湘浦孤舟客，心羨廬山下版僧。", "倦枕厭聞窗外雨，殘膏猶在壁間燈。", "草芝要及清晨服，深愧蠻童爲扣冰。"]'),
('cd58cc88-f52a-4da8-ba91-a56cfc060a4f','兩雁','陸游','宋','宋诗','song-poetry','','[]','兩雁東西來，合群以南翔。',72,'全唐诗/poet.song.135000.json','["兩雁東西來，合群以南翔。", "鏡湖接天台，海闊天茫茫。", "冥飛遠矰弋，長路諳冰霜。", "君看此氣象，豈復謀稻粱。", "正爾下杜陵，已復掠瀟湘。", "超遥萬里程，燕雀安能量。"]'),
('40bcad5a-8d6f-4a5c-9a6e-8dcbf332b62d','書文稿後','陸游','宋','宋诗','song-poetry','','[]','上蔡牽黄犬，丹徒作布衣。',24,'全唐诗/poet.song.135000.json','["上蔡牽黄犬，丹徒作布衣。", "苦言誰解聽，臨禍始知非。"]'),
('72f83dc9-0442-41e5-aa8b-5736b20a6ebd','題唐執中書樓','陸游','宋','宋诗','song-poetry','','[]','吾州唐子他州無，閉戶偏讀家藏書。',64,'全唐诗/poet.song.135000.json','["吾州唐子他州無，閉戶偏讀家藏書。", "志氣頗聞已山立，神仙固自多樓居。", "終日坐忘對燕几，有時出遊騎蹇馿。", "人生如此自可爾，勿羨新貴高門閭。"]'),
('d9b42864-f6e8-4893-9a0d-3be72aca5cec','歲晚六首  其一','陸游','宋','宋诗','song-poetry','','[]','雲暗郊原雪意稠，天公似欲富來麰。',32,'全唐诗/poet.song.135000.json','["雲暗郊原雪意稠，天公似欲富來麰。", "布衾歲久真如鐵，詎敢私懷一己憂。"]'),
('35c805c6-0cf0-45ab-bf36-0e97ed0901bc','歲晚六首  其二','陸游','宋','宋诗','song-poetry','','[]','不學空門不學仙，端居胸次自超然。',32,'全唐诗/poet.song.135000.json','["不學空門不學仙，端居胸次自超然。", "絳人甲子君休問，新歲吾兒本命年。"]'),
('5c9274b7-362c-4460-984a-3017b394bd3f','歲晚六首  其三','陸游','宋','宋诗','song-poetry','','[]','戒殺家庖罷饋魚，病脾亦復禁寒蔬。',32,'全唐诗/poet.song.135000.json','["戒殺家庖罷饋魚，病脾亦復禁寒蔬。", "莫慚鄰里嘲枯淡，出甑香粳玉不如。"]'),
('c472d587-70d5-4313-9060-121bba05994a','歲晚六首  其四','陸游','宋','宋诗','song-poetry','','[]','小岫嶙峋炷寶熏，卷書閑對一窗雲。',32,'全唐诗/poet.song.135000.json','["小岫嶙峋炷寶熏，卷書閑對一窗雲。", "雁聲忽向天邊過，起立中庭看斷群。"]'),
('478329de-631a-47d8-9f67-9bc8521abd04','歲晚六首  其五','陸游','宋','宋诗','song-poetry','','[]','小塢梅開十二三，曲塘冰綻水如藍。',32,'全唐诗/poet.song.135000.json','["小塢梅開十二三，曲塘冰綻水如藍。", "兒童鬭采春盤料，蓼茁芹芽欲滿籃。"]'),
('91e80cb9-8595-465a-a9ab-51f8cd33ee98','歲晚六首  其六','陸游','宋','宋诗','song-poetry','','[]','久已功名不上心，亦無心要老山林。',32,'全唐诗/poet.song.135000.json','["久已功名不上心，亦無心要老山林。", "鹿門采藥悠然去，千載龐公是賞音。"]'),
('e8dff7e0-79b2-4472-b267-c002370d92d8','雀啄粟','陸游','宋','宋诗','song-poetry','','[]','坡頭車敗雀啄粟，桑下餉來烏攫肉。',64,'全唐诗/poet.song.135000.json','["坡頭車敗雀啄粟，桑下餉來烏攫肉。", "乘時投隙自謂才，苟得未必爲汝福。", "忍饑蓬蒿固亦難，要是少遠彈射辱。", "老農輟耒爲汝悲，豈信江湖有鴻鵠。"]'),
('b4805134-503a-474a-ab6b-4e3bc064beb8','老翁','陸游','宋','宋诗','song-poetry','','[]','老翁睡少知遥夜，貧士衾單怯苦寒。',64,'全唐诗/poet.song.135000.json','["老翁睡少知遥夜，貧士衾單怯苦寒。", "悶裏不嫌村酒薄，瘦來偏覺舊衣寬。", "籬門遇健時能出，書卷乘閑亦取看。", "深愧野人憐寂莫，放鋤相喚共朝餐。"]'),
('f53d5a9d-1c4d-46bb-9929-99dec899b9b7','寄子虡','陸游','宋','宋诗','song-poetry','','[]','人生恨無年，我老已爛熟。',120,'全唐诗/poet.song.135000.json','["人生恨無年，我老已爛熟。", "退耕鏡湖上，風雨有茅屋。", "事君闕補報，得此不啻足。", "餘年尚幾何，嫋嫋風中燭。", "大兒戍塞垣，馳馬佩矢箙。", "去家千餘里，辛苦就微祿。", "書來續三紙，語悲不忍讀。", "遹弟在我傍，亦復泪溢目。", "門戶嗟日衰，持守頼家督。", "雪雲暗淮天，念汝方露宿。"]'),
('300c2047-2e04-4607-9635-106eee21d34a','雜詠四首  其一','陸游','宋','宋诗','song-poetry','','[]','少日狂疏觸怒嗔，每緣憂患喪吾真。',32,'全唐诗/poet.song.135000.json','["少日狂疏觸怒嗔，每緣憂患喪吾真。", "晚收咄咄書空手，却作騰騰任運人。"]'),
('1420bd19-f735-4e99-a5b4-0a8aa602ec31','雜詠四首  其二','陸游','宋','宋诗','song-poetry','','[]','得過一日且一日，安知今吾非故吾。',32,'全唐诗/poet.song.135000.json','["得過一日且一日，安知今吾非故吾。", "袖手明窗讀周易，不辜香飯一齋盂。"]'),
('a5f78010-d6f0-402a-8193-1a81a58f6ba5','雜詠四首  其三','陸游','宋','宋诗','song-poetry','','[]','松肪燎火滿爐紅，罌粟煎湯到手空。',32,'全唐诗/poet.song.135000.json','["松肪燎火滿爐紅，罌粟煎湯到手空。", "試問齋居守丹竈，何如醉卧聽松風。"]');
